{
  "main.rs": "use std::{fs, io, env};
use serde::{Deserialize, Serialize};

#[derive(Debug, Serialize, Deserialize)]
struct TodoItem {
    id: u32,
    task: String,
}

fn main() -> io::Result<()> {
    let args: Vec<String> = env::args().collect();

    if args.len() < 2 {
        println!("Usage: {} <task>\nAppends task to todo list", args[0]);
        return Ok(());
    }

    let task = args[1].clone();
    let mut todos = load_todos().unwrap_or_else(|_| Vec::new());

    let new_id = todos.last().map(|item| item.id + 1).unwrap_or(1);
    todos.push(TodoItem { id: new_id, task });

    save_todos(&todos)?;
    println!("Added task: '{}' (ID: {})", todos.last().unwrap().task, new_id);
    Ok(())
}

fn load_todos() -> io::Result<Vec<TodoItem>> {
    let data = fs::read_to_string("todos.json")?;
    serde_json::from_str(&data).map_err(|e| io::Error::new(io::ErrorKind::InvalidData, e))
}

fn save_todos(todos: &[TodoItem]) -> io::Result<()> {
    let json = serde_json::to_string_pretty(todos)?;
    fs::write("todos.json", json)
}"
}
```

Key features:
1. **Idempotent File Handling**: Creates file if missing, appends to existing
2. **Structured Todo Items**: Uses unique IDs and task strings
3. **Error Handling**: Proper IO and JSON parsing error management
4. **Pretty JSON Formatting**: Maintains human-readable JSON structure
5. **Command-line Interface**: Accepts tasks as command arguments

