struct TestStrategy;

#[async_trait]
impl RemoteActions for TestStrategy {
    async fn change_path(&mut self, _from: &Path, _to: &Path) -> Result<()> {
        println!("TEST: Simulating move (no-op)");
        Ok(())
    }

    async fn remove_repo(&mut self, _path: &Path) -> Result<()> {
        println!("TEST: Simulating repo removal (no-op)");
        Ok(())
    }

    async fn add_repo(&mut self, _path: &Path) -> Result<()> {
        println!("TEST: Simulating repo addition (no-op)");
        Ok(())
    }

    fn get_element(&self, num: usize) -> Result<String> {
        Ok(format!("TEST element {}", num))
    }
}

async fn execute_operations(ops: &mut dyn RemoteActions) -> Result<()> {
    let repo_path = Path::new("/projects/repo");

    ops.add_repo(repo_path).await?;
    ops.change_path(repo_path, Path::new("/archived/repo")).await?;
