use radiate::prelude::*;
use std::fmt;

// Define custom operator struct
struct SqrtPlusOne;

// Implement Operator trait for custom operator
impl Operator for SqrtPlusOne {
    // Operator takes 1 argument
    fn arity(&self) -> u32 { 1 }

    // Perform operation: sqrt(x) + 1.0
    fn operate(&self, stack: &mut Vec<f32>) {
        if let Some(x) = stack.pop() {
            let result = x.sqrt() + 1.0;
            stack.push(result);
        }
    }

    // Symbol for display purposes
    fn symbol(&self) -> String { "√+1".to_string() }
}

