use serde::Deserialize;
use serde::de::{self, Deserializer, MapAccess, Visitor};
use std::fmt;

#[derive(Debug)]
struct Character {
    name: String,
    ac: u8,
    current: u16,
    max: u16,
    temp: u16,
}

// Custom visitor to deserialize Character
impl<'de> Deserialize<'de> for Character {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        // Helper struct for deserialization
        #[derive(Deserialize)]
        struct Fields {
            name: String,
            ac: u8,
            hp: u16,
        }

        // Deserialize into helper struct
        let helper = Fields::deserialize(deserializer)?;

        // Build Character using values from helper
        Ok(Character {
            name: helper.name,
            ac: helper.ac,
            current: helper.hp,
            max: helper.hp,
            temp: 0,
        })
    }
}

fn main() {
    let json_data = r#"
        {
