use std::env;
use std::fs;
use std::path::Path;

const FILE_PATH: &str = "output.json";

fn load_todos() -> Vec<String> {
    if Path::new(FILE_PATH).exists() {
        let data = fs::read_to_string(FILE_PATH).unwrap_or_else(|_| String::from("[]"));
        serde_json::from_str(&data).unwrap_or_else(|_| Vec::new())
    } else {
        Vec::new()
    }
}

fn save_todos(todos: &[String]) {
    let json = serde_json::to_string_pretty(todos).expect("Failed to serialize todos");
    fs::write(FILE_PATH, json).expect("Failed to write file");
