**main.rs:**
```rust
use serde::de::{self, Deserialize, Deserializer, MapAccess, SeqAccess, Visitor};
use serde_derive::Deserialize;
use std::fmt;

#[derive(Debug, Deserialize, PartialEq)]
#[serde(tag = "type", content = "value")]
enum B {
    Int(i32),
    Text(String),
    Boolean(bool),
}

struct A {
    x: usize,
    b: Vec<B>,
}

impl Default for A {
    fn default() -> Self {
        A {
            x: 0,
            b: Vec::new(),
        }
    }
}

struct AVisitor;

impl<'de> Visitor<'de> for AVisitor {
    type Value = A;

    fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
        formatter.write_str("struct A with fields 'x' and 'b'")
    }

    fn visit_map<V>(self, mut map: V) -> Result<A, V::Error>
    where
        V: MapAccess<'de>,
    {
        let mut val = A::default();

        while let Some(key) = map.next_key::<&str>()? {
            match key {
                "x" => {
                    val.x = map.next_value()?;
                }
                "b" => {
                    // Deserialize Vec<B> using a custom visitor
                    val.b = map.next_value::<VecB>()?;
                }
                _ => {
                    // Handle unknown fields
                    return Err(de::Error::unknown_field(key, &["x", "b"]));
                }
            }
        }

        Ok(val)
    }
}

struct VecB;

impl<'de> Deserialize<'de> for Vec<B> {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        deserializer.deserialize_seq(VecB)
    }
}

impl<'de> Visitor<'de> for VecB {
    type Value = Vec<B>;

    fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
        formatter.write_str("a sequence of B elements")
    }

    fn visit_seq<S>(self, mut seq: S) -> Result<Self::Value, S::Error>
    where
        S: SeqAccess<'de>,
    {
        let mut vec = Vec::new();
        while let Some(elem) = seq.next_element::<B>()? {
            vec.push(elem);
        }
        Ok(vec)
    }
}

impl<'de> Deserialize<'de> for A {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        deserializer.deserialize_map(AVisitor)
    }
}

fn main() {
    let json = r#"
        {
            "x": 42,
            "b": [
                { "type": "Int", "value": 10 },
                { "type": "Text", "value": "hello" },
                { "type": "Boolean", "value": true }
            ]
        }
    "#;

    let a: A = serde_json::from_str(json).expect("Failed to deserialize");
    println!("Deserialized successfully!");
    println!("x: {}", a.x);
    println!("b: {:?}", a.b);
}
```

