async fn list_dir_recursive(tree: &Arc<smb::Tree>, path: &str) -> Result<(), Box<dyn std::error::Error>> {
    // Normalize paths to use backslashes
    let normalized_path = if path.is_empty() {
        "\\".to_string()
    } else {
        path.replace('/', "\\")
    };

