Here's a self-contained solution that demonstrates how to fetch related structs by ID using SQLx. The solution uses a JOIN query and manual `FromRow` implementation to handle nested structs:

```json
{
  "Cargo.toml": {
    "content": "[package]
name = "sqlx_structs"
version = "0.1.0"
edition = "2024"

[dependencies]
sqlx = { version = "0.8.6", features = ["runtime-tokio", "sqlite", "macros"] }
tokio = { version = "1.44.2", features = ["rt-multi-thread", "macros"] }"
  },
  "main.rs": {
    "content": "use sqlx::{FromRow, Row, sqlite::SqliteRow, SqlitePool, Error};

#[derive(Debug, PartialEq)]
pub struct Employee {
    pub id: u64,
    pub name: String,
    pub team: Team,
}

#[derive(Debug, PartialEq)]
pub struct Team {
    pub id: u64,
    pub name: String,
}

impl<'r> FromRow<'r, SqliteRow> for Employee {
    fn from_row(row: &'r SqliteRow) -> Result<Self, Error> {
        let id: u64 = row.try_get("id")?;
        let name: String = row.try_get("name")?;
        let team_id: u64 = row.try_get("team_id")?;
        let team_name: String = row.try_get("team_name")?;

        Ok(Employee {
            id,
            name,
            team: Team {
                id: team_id,
                name: team_name,
            },
        })
    }
}

#[tokio::main]
async fn main() -> Result<(), Error> {
    // Create in-memory SQLite database
    let pool = SqlitePool::connect("sqlite::memory:").await?;

    // Create tables
    sqlx::query(
        r#"
        CREATE TABLE teams (
            id INTEGER PRIMARY KEY,
            name TEXT
        );

        CREATE TABLE employees (
            id INTEGER PRIMARY KEY,
            name TEXT,
            team INTEGER,
            FOREIGN KEY (team) REFERENCES teams(id)
        );
        "#
    )
    .execute(&pool)
    .await?;

    // Insert sample data
    sqlx::query(
        r#"
        INSERT INTO teams (id, name) VALUES
            (1, 'East Coast Team'),
            (2, 'West Coast Team');

        INSERT INTO employees (id, name, team) VALUES
            (1, 'Boston Alice', 1),
            (2, 'Seattle Bob', 2);
        "#
    )
    .execute(&pool)
    .await?;

    // Fetch employee with nested team data
    let employee: Employee = sqlx::query_as(
        r#"
        SELECT 
            e.id, 
            e.name, 
            t.id AS team_id, 
            t.name AS team_name 
        FROM employees e
        JOIN teams t ON e.team = t.id
        WHERE e.id = 1
        "#
    )
    .fetch_one(&pool)
    .await?;

    // Verify results
    println!("Employee: {:?}", employee);
    println!("Team name: {}", employee.team.name);

    // Expected values
    assert_eq!(employee.id, 1);
    assert_eq!(employee.name, "Boston Alice");
    assert_eq!(employee.team.id, 1);
    assert_eq!(employee.team.name, "East Coast Team");

    Ok(())
}"
  }
}
```

