use std::borrow::Cow;
use std::marker::PhantomData;

// Define a minimal Resource trait and types for testing.
pub trait Resource {
    type DynamicType: Default + Clone;

    fn group(dyn_type: &Self::DynamicType) -> Cow<'static, str>;
    fn kind(dyn_type: &Self::DynamicType) -> Cow<'static, str>;
    fn meta(&self) -> Meta;
}

pub struct Meta {
    pub name: Option<String>,
}

