pub struct SampleDynamicType;

#[derive(Clone)]
pub struct SampleResource {
    name: String,
}

impl SampleResource {
    pub fn new(name: &str) -> Self {
        Self {
            name: name.to_string(),
        }
    }
}

impl Resource for SampleResource {
    type DynamicType = SampleDynamicType;

    fn group(_: &Self::DynamicType) -> Cow<'static, str> {
        Cow::Borrowed("test-group")
    }

    fn kind(_: &Self::DynamicType) -> Cow<'static, str> {
        Cow::Borrowed("test-kind")
    }

    fn meta(&self) -> Meta {
        Meta {
            name: Some(self.name.clone()),
        }
    }
}

#[derive(Debug, Clone)]
pub struct ResourceRef<R: Resource> {
    type_: PhantomData<R>,
    dynamic_type: R::DynamicType,
    name: String,
}

impl<R: Resource> ResourceRef<R> {
    pub fn new(resource: R) -> Self {
        let name = resource.meta().name.as_deref().expect("Resource must have a name");
        Self::new_named(name)
    }

    pub fn new_named(name: &str) -> Self {
        let dynamic_type = R::DynamicType::default();
        Self {
            type_: PhantomData,
            dynamic_type,
            name: name.to_string(),
        }
    }

    pub fn group(&self) -> Option<Cow<str>> {
        let group = R::group(&self.dynamic_type);
        if group.is_empty() {
            None
        } else {
            Some(group)
        }
    }

    pub fn kind(&self) -> Cow<str> {
        R::kind(&self.dynamic_type)
    }

    pub fn name(&self) -> &str {
        &self.name
    }
}

fn main() {
    let resource = SampleResource::new("my-resource");
    let resource_ref = ResourceRef::<SampleResource>::new(resource);

    println!("ResourceRef created successfully!");
    println!("name: {}", resource_ref.name());
    println!("kind: {}", resource_ref.kind());
    println!("group: {:?}", resource_ref.group());
}
