Here's the complete solution with the `Cargo.toml` and `main.rs` files. The solution includes a custom derive macro using a proc-macro crate and attribute parsing to convert structs into Notion API-compatible HashMaps.

### Cargo.toml
```toml
[package]
name = "notion_api_helper"
version = "0.1.0"
edition = "2021"

[lib]
name = "notion_macros"
proc-macro = true

[dependencies]
syn = { version = "2.0", features = ["full", "extra-traits"] }
quote = "1.0"
proc-macro2 = "1.0"

[dependencies.serde]
version = "1.0"
features = ["derive"]

[dependencies.serde_json]
version = "1.0"

[dependencies.hashbrown]
version = "0.14"
features = ["serde"]
```

### main.rs
```rust
use serde::{Serialize, Deserialize};
use serde_json::Value;
use hashbrown::HashMap;
use notion_macros::NotionProperties;

mod notion_macros {
    use proc_macro::TokenStream;
    use quote::quote;
    use syn::{parse_macro_input, DeriveInput, Data, Fields, Meta, NestedMeta, Lit};

    #[proc_macro_derive(NotionProperties, attributes(notion_property))]
    pub fn derive_notion_properties(input: TokenStream) -> TokenStream {
        let input = parse_macro_input!(input as DeriveInput);
        let struct_name = &input.ident;

        let fields = match &input.data {
            Data::Struct(s) => match &s.fields {
                Fields::Named(fields) => &fields.named,
                _ => panic!("Only structs with named fields are supported"),
            },
            _ => panic!("Only structs are supported"),
        };

        let mut conversion_code = Vec::new();

        for field in fields {
            let field_ident = field.ident.as_ref().unwrap();
            let field_name_str = field_ident.to_string();

            let mut property_type = None;
            let mut property_name = None;

            // Parse field attributes
            for attr in &field.attrs {
                if attr.path().is_ident("notion_property") {
                    let meta_list = attr.parse_args_with(syn::punctuated::Punctuated::<Meta, syn::Token![,]>::parse_terminated).unwrap();
                    for meta in meta_list {
                        match meta {
                            Meta::NameValue(nv) => {
                                let ident = nv.path.get_ident().unwrap().to_string();
                                match &*ident {
                                    "type" => {
                                        if let Lit::Str(s) = &nv.lit {
                                            property_type = Some(s.value());
                                        }
                                    }
                                    "name" => {
                                        if let Lit::Str(s) = &nv.lit {
                                            property_name = Some(s.value());
                                        }
                                    }
                                    _ => {}
                                }
                            },
                            _ => {}
                        }
                    }
                }
            }

            let name = property_name.unwrap_or_else(|| field_name_str.clone());
            let prop_type = property_type.expect("Missing 'type' in notion_property attribute");

            let conversion = match prop_type.as_str() {
                "title" => quote! {
                    map.insert(#name.to_string(), PropertyValue::Title(vec![
                        RichTextObject {
                            text: TextObject {
                                content: self.#field_ident.clone(),
                                link: None,
                            },
                            annotations: None,
                            data_type: Some(RichTextType::Text),
                            equation: None,
                            mention: None,
                            plain_text: None,
                            href: None,
                        }
                    ]));
                },
                "url" => quote! {
                    if let Some(ref val) = self.#field_ident {
                        map.insert(#name.to_string(), PropertyValue::Url(val.clone()));
                    }
                },
                "MultiSelect" => quote! {
                    let items: Vec<SelectObject> = self.#field_ident.as_ref().map_or_else(Vec::new, |vec| {
                        vec.iter().map(|v| SelectObject {
                            id: None,
                            color: None,
                            name: v.to_string(),
                        }).collect()
                    });
                    map.insert(#name.to_string(), PropertyValue::MultiSelect(items));
                },
                _ => panic!("Unsupported property type: {}", prop_type),
            };

            conversion_code.push(conversion);
        }

        let expanded = quote! {
            impl #struct_name {
                pub fn to_notion_properties(&self) -> HashMap<String, PropertyValue> {
                    use crate::PropertyValue::*;
                    use crate::{RichTextObject, TextObject, RichTextType, SelectObject};

                    let mut map = HashMap::new();
                    #(#conversion_code)*
                    map
                }
            }
        };

        TokenStream::from(expanded)
    }
}

#[derive(Debug, Serialize, Deserialize)]
#[serde(tag = "type", rename_all = "camelCase")]
pub enum PropertyValue {
    Title(Vec<RichTextObject>),
    Url(String),
    MultiSelect(Vec<SelectObject>),
    // Add other property types as needed
}

#[derive(Debug, Serialize, Deserialize)]
pub struct RichTextObject {
    #[serde(skip_serializing_if = "Option::is_none")]
    pub annotations: Option<serde_json::Value>,

    #[serde(rename = "type", skip_serializing_if = "Option::is_none")]
    pub data_type: Option<RichTextType>,

    #[serde(skip_serializing_if = "Option::is_none")]
    pub equation: Option<serde_json::Value>,

    #[serde(skip_serializing_if = "Option::is_none")]
    pub mention: Option<serde_json::Value>,

    #[serde(skip_serializing_if = "Option::is_none")]
    pub plain_text: Option<String>,

    #[serde(skip_serializing_if = "Option::is_none")]
    pub href: Option<String>,

    pub text: TextObject,
}

#[derive(Debug, Serialize, Deserialize)]
pub enum RichTextType {
    #[serde(rename = "text")]
    Text,
    // Add other rich text types as needed
}

#[derive(Debug, Serialize, Deserialize)]
pub struct TextObject {
    pub content: String,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub link: Option<String>,
}

#[derive(Debug, Serialize, Deserialize)]
pub struct SelectObject {
    #[serde(skip_serializing_if = "Option::is_none")]
    pub id: Option<String>,

    #[serde(skip_serializing_if = "Option::is_none")]
    pub color: Option<String>,

    pub name: String,
}

#[derive(NotionProperties, Serialize, Deserialize, Debug)]
struct MyUnit {
    #[notion_property(type = "title", name = "Name")]
    pub name: String,

    #[notion_property(type = "url", name = "Icon url")]
    pub icon_url: Option<String>,

    #[notion_property(type = "MultiSelect", name = "Roles")]
    pub categories: Option<Vec<serde_json::Value>>,
}

fn main() {
    let unit = MyUnit {
        name: "Test Unit".to_string(),
        icon_url: Some("https://example.com/icon.png".to_string()),
        categories: Some(vec![
            serde_json::json!("Developer"),
            serde_json::json!("Designer"),
        ]),
    };

    let properties = unit.to_notion_properties();
    println!("{:#?}", properties);
}
```

### How to Use:
1. Create a new Rust project: `cargo new notion_api_helper`
2. Replace `Cargo.toml` with the provided content
3. Create `src/main.rs` with the provided content
4. Run with `cargo run`

### Key Features:
1. Custom `NotionProperties` derive macro
2. Attribute parsing with `#[notion_property(type="...", name="...")]`
3. Handles:
   - `title` → RichTextObject conversion
   - `url` → Optional string handling
   - `MultiSelect` → Vector conversion
4. Serialization with Serde
5. Uses efficient `hashbrown::HashMap`

The output will show a properly formatted HashMap suitable for the Notion API. The macro automatically handles optional fields and converts values to the appropriate Notion property types based on the field attributes.

