    tracing::info!(
        "Completed! Downloaded {} trades in {:.2} seconds",
        trades.len(),
        start.elapsed().as_secs_f32()
    );
    Ok(())
}

async fn fetch_trades_from_azure() -> Result<Vec<TradeData>> {
    // Load environment variables
    let tenant_id = env::var("AZURE_TENANT_ID")?;
    let client_id = env::var("AZURE_CLIENT_ID")?;
    let client_secret = env::var("AZURE_CLIENT_SECRET")?;
    let account_name = env::var("AZURE_ACCOUNT_NAME")?;
    let container_name = env::var("AZURE_CONTAINER_NAME")?;
    let prefix_opt = env::var("AZURE_PREFIX_OPT")?;
    let prefix_fut = env::var("AZURE_PREFIX_FUT")?;

    // Get OAuth token
    let token = get_oauth_token(&tenant_id, &client_id, &client_secret)
        .await
        .context("Failed to get OAuth token")?;

    // Create Azure clients
    let credentials = StorageCredentials::bearer_token(token);
    let container_client = Arc::new(
        BlobServiceClient::new(account_name, credentials)
            .container_client(container_name)
    );

    // List all blob names first
    let list_start = Instant::now();
    let prefixes = vec![prefix_opt, prefix_fut];
    let all_blob_names = list_all_blobs(&container_client, &prefixes).await?;
    tracing::info!(
        "Listed {} blobs in {:.2} seconds",
        all_blob_names.len(),
        list_start.elapsed().as_secs_f32()
    );

    // Download and parse blobs in parallel
    let download_start = Instant::now();
    let trades = download_and_parse_blobs(&container_client, &all_blob_names)
        .await
        .context("Failed to download and parse blobs")?;

    tracing::info!(
        "Downloaded and parsed {} blobs in {:.2} seconds",
        trades.len(),
        download_start.elapsed().as_secs_f32()
    );

    Ok(trades)
}

async fn list_all_blobs(
    container_client: &Arc<ContainerClient>,
    prefixes: &[String],
) -> Result<Vec<String>> {
    let mut tasks = Vec::new();

    for prefix in prefixes {
        let client = Arc::clone(container_client);
        let prefix = prefix.clone();
        tasks.push(tokio::spawn(async move {
            let mut blob_names = Vec::new();
            let mut stream = client
                .list_blobs()
                .prefix(prefix)
                .include_metadata(false)
                .into_stream();

            while let Some(Ok(response)) = stream.next().await {
                for blob in response.blobs.blobs() {
                    if blob.name.ends_with(".json") {
                        blob_names.push(blob.name.clone());
                    }
                }
            }
            blob_names
        }));
    }

    let mut all_blob_names = Vec::new();
    for task in tasks {
        all_blob_names.extend(task.await?);
    }

    Ok(all_blob_names)
}

async fn download_and_parse_blobs(
    container_client: &Arc<ContainerClient>,
    blob_names: &[String],
) -> Result<Vec<TradeData>> {
    let semaphore = Arc::new(Semaphore::new(
        std::thread::available_parallelism()?.get() * 10,
    ));
    let mut tasks = Vec::with_capacity(blob_names.len());

    for blob_name in blob_names {
        let client = Arc::clone(container_client);
        let blob_name = blob_name.clone();
        let semaphore = Arc::clone(&semaphore);

        tasks.push(tokio::spawn(async move {
            let _permit = semaphore.acquire().await?;
            let result: Result<TradeData> = (|| async {
                let blob_client = client.blob_client(&blob_name);
                let data = blob_client
                    .get_content()
                    .await
                    .map_err(|e| anyhow!("Download failed for {}: {}", blob_name, e))?;

                serde_json::from_slice(&data)
                    .map_err(|e| anyhow!("JSON parse failed for {}: {}", blob_name, e))
            })()
            .await;

            match result {
                Ok(trade) => Ok(trade),
                Err(e) => {
                    tracing::error!("{}", e);
                    Err(e)
                }
            }
        }));
    }

    let mut trades = Vec::new();
    for task in tasks {
        match task.await? {
            Ok(trade) => trades.push(trade),
            Err(_) => continue, // Already logged
        }
    }

    Ok(trades)
}

async fn get_oauth_token(
    tenant_id: &str,
    client_id: &str,
    client_secret: &str,
) -> Result<String> {
    let token_url = format!("https://login.microsoftonline.com/{}/oauth2/v2.0/token", tenant_id);
    let params = TokenRequest {
        grant_type: "client_credentials",
        client_id,
        client_secret,
        scope: "https://storage.azure.com/.default",
    };

    let response = reqwest::Client::new()
        .post(&token_url)
        .form(&params)
        .send()
        .await
        .context("Token request failed")?;

    if !response.status().is_success() {
        let body = response.text().await.unwrap_or_default();
        return Err(anyhow!(
            "Token request failed: {} - {}",
            response.status(),
            body
        ));
    }

    let token_response: TokenResponse = response
        .json()
        .await
        .context("Failed to parse token response")?;

    Ok(token_response.access_token)
}
```

