enum ClientWrapper<'a> {
    Owned(Client),
    Borrowed(&'a Client),
}

impl Deref for ClientWrapper<'_> {
    type Target = Client;

    fn deref(&self) -> &Self::Target {
        match self {
            Self::Owned(c) => c,
            Self::Borrowed(c) => c,
        }
    }
}

impl DbContainer {
    pub fn new(db_config: DbConfig) -> Self {
        Self {
            db_config,
            default_conn: tokio::sync::OnceCell::new(),
        }
    }

    pub async fn create_database(&self, name: &str) -> Result<(), tokio_postgres::Error> {
        let client = self.connect(None).await?;
        client
            .execute(&format!("CREATE DATABASE {name}"), &[])
            .await?;
        // For real usage, you'd create a new connection and apply schema here
        Ok(())
    }

    pub async fn drop_database(&self, name: &str) -> Result<u64, tokio_postgres::Error> {
        let client = self.connect(None).await?;
        let terminate_sql = format!(
            "
            SELECT pg_terminate_backend(pid)
            FROM pg_stat_activity
            WHERE datname = '{name}' AND pid <> pg_backend_pid();
            ",
        );
        client.execute(&terminate_sql, &[]).await?;
        client.execute(&format!("DROP DATABASE {name}"), &[]).await
    }

    async fn connect(&self, db_name: Option<&str>) -> Result<ClientWrapper<'_>, tokio_postgres::Error> {
        let mut conn_str = format!(
            "host=localhost port={} user=postgres password={}",
            self.db_config.port, self.db_config.postgres_password
        );

        if let Some(dbname) = db_name {
            conn_str.push_str(&format!(" dbname={dbname}"));
            let (client, conn) = tokio_postgres::connect(&conn_str, NoTls).await?;

            tokio::spawn(async move {
                if let Err(e) = conn.await {
                    eprintln!("Connection error (specific db): {e}");
                }
            });

            Ok(ClientWrapper::Owned(client))
        } else {
            let default_conn = self.default_conn.get_or_try_init(|| async {
                let (client, conn) = tokio_postgres::connect(&conn_str, NoTls).await?;
                let handle = tokio::spawn(async move {
                    if let Err(e) = conn.await {
                        eprintln!("Connection error (default db): {e}");
                    }
                });
                Ok::<_, tokio_postgres::Error>(DefaultConnection { client, _handle: handle })
            }).await?;

            Ok(ClientWrapper::Borrowed(&default_conn.client))
        }
    }
}

#[tokio::main]
async fn main() -> anyhow::Result<()> {
    env_logger::init();

    let db_config = DbConfig {
        port: 5432,
        name: "postgres".to_string(),
        user: "postgres".to_string(),
        postgres_password: "postgres".to_string(),
        db_password: "password".to_string(),
    };

    let container = DbContainer::new(db_config);

    for i in 0..5 {
        let db_name = format!("testdb_{}", i);
        println!("Creating database {}", db_name);
        container.create_database(&db_name).await?;
        println!("Dropping database {}", db_name);
        container.drop_database(&db_name).await?;
    }

    println!("All operations completed successfully!");
    Ok(())
}
```

### Key Fixes:
1. **Persistent Connection Task**: 
   - Stored both the `Client` and its `JoinHandle` in a `DefaultConnection` struct
   - The `_handle` field keeps the connection task alive for the lifetime of the `DbContainer`

2. **Connection Management**:
   - **Default connection**: Cached using `OnceCell` with the connection task spawned during initialization
   - **Database-specific connections**: Created on-demand and managed temporarily (not cached)

3. **Lifetime Handling**:
   - `ClientWrapper` returns either an owned client (temp connections) or a reference to the cached client
   - Uses async `OnceCell::get_or_try_init` to safely initialize the connection

4. **Resource Cleanup**:
   - The connection task automatically cancels when `DbContainer` is dropped
   - PostgreSQL connections properly closed when the container goes out of scope

### Usage:
1. Create a new Rust project: `cargo new cached_tokio_postgres`
2. Replace `Cargo.toml` and `main.rs` with the provided files
3. Ensure PostgreSQL is running locally on port 5432 (default credentials: postgres/postgres)
4. Run with: `cargo run`

The example will create and drop 5 test databases, demonstrating that the default connection remains active throughout the process.

