#[derive(Deserialize, Debug)]
struct TextureMetadata {
    offset: usize,
    size: usize,
}

#[derive(Asset, TypePath, Debug)]
struct WadArchive {
    path: String,
    textures: HashMap<String, TextureMetadata>,
}

#[derive(Asset, TypePath, Debug)]
struct WadTexture {
    data: Vec<u8>,
}

struct WadArchiveLoader;
struct WadTextureLoader;

impl AssetLoader for WadArchiveLoader {
    type Asset = WadArchive;
    type Settings = ();
    type Error = anyhow::Error;

    fn load<'a>(
        &'a self,
        reader: &'a mut Reader,
        _settings: &'a Self::Settings,
        _load_context: &'a mut LoadContext,
    ) -> BoxedFuture<'a, Result<Self::Asset, Self::Error>> {
        Box::pin(async move {
            // In a real implementation, you would parse your archive format here
            // This example just reads a simple JSON index
            let mut bytes = Vec::new();
            reader.read_to_end(&mut bytes).await?;

            // Parse fake metadata (replace with actual archive format parsing)
            let textures: HashMap<String, TextureMetadata> = serde_json::from_slice(&bytes)
                .map_err(|e| anyhow!("Failed to parse index: {}", e))?;

            // Get original asset path (e.g. "textures.wad")
            let path = _load_context
                .path()
                .to_str()
                .ok_or_anyhow("Invalid asset path")?
                .to_string();

            Ok(WadArchive { path, textures })
        })
    }

    fn extensions(&self) -> &[&str] {
        &["wad"]
    }
}

impl AssetLoader for WadTextureLoader {
    type Asset = WadTexture;
    type Settings = ();
    type Error = anyhow::Error;

    fn load<'a>(
        &'a self,
        _reader: &'a mut Reader,
        _settings: &'a Self::Settings,
        load_context: &'a mut LoadContext,
    ) -> BoxedFuture<'a, Result<Self::Asset, Self::Error>> {
        Box::pin(async move {
            // Parse path in format "archive.wad#texture_name"
            let path = load_context.path().to_str().unwrap();
            let (archive_path, texture_name) = path.split_once('#')
                .ok_or_anyhow("Invalid texture path format")?;

            // Load the associated archive
            let archive = load_context.load_dependency(archive_path.parse()?);
            let archive = match archive.get::<WadArchive>().await {
                Some(archive) => archive,
                None => return Err(anyhow::anyhow!("Archive not loaded: {}", archive_path)),
            };

            // Look up texture metadata
            let metadata = archive.textures.get(texture_name)
                .ok_or_anyhow(format!("Texture '{}' not found in archive", texture_name))?;

            // Read texture data from archive
            let mut file = File::open(Path::new("assets").join(&archive.path)).await?;
            let mut buffer = vec![0u8; metadata.size];
            file.read_exact(&mut buffer).await?;

            Ok(WadTexture { data: buffer })
        })
    }

    fn extensions(&self) -> &[&str] {
        &["wadtex"]
    }
}

fn main() {
    App::new()
        .add_plugins(DefaultPlugins)
        .init_asset::<WadArchive>()
        .init_asset::<WadTexture>()
        .init_asset_loader::<WadArchiveLoader>()
        .init_asset_loader::<WadTextureLoader>()
        .add_systems(Startup, setup)
        .run();
}

fn setup(
    mut commands: Commands,
    asset_server: Res<AssetServer>,
    mut textures: ResMut<Assets<Image>>,
) {
    commands.spawn(Camera2dBundle::default());

    // Load a texture from the archive
    let texture_handle: Handle<WadTexture> = asset_server.load("textures.wad#brick");

    // Convert to Bevy Image when loaded
    commands.spawn((
        texture_handle,
        Name::new("Lazy Loaded Texture"),
    ));
}

// System to process loaded textures
fn process_textures(
    mut events: EventReader<AssetEvent<WadTexture>>,
    wad_textures: Res<Assets<WadTexture>>,
    mut images: ResMut<Assets<Image>>,
) {
    for event in events.read() {
        if let AssetEvent::LoadedWithDependencies { id } = event {
            if let Some(wad_texture) = wad_textures.get(*id) {
                // Convert to Bevy Image (replace with actual format parsing)
                let image = Image::from_bytes(
                    &wad_texture.data,
                    bevy::render::texture::ImageFormat::Png // Adjust format as needed
                ).unwrap();

                images.set_untracked(*id, image);
            }
        }
    }
}
```

### Key Features

1. **Lazy Loading**:
   - Archives are loaded first (small metadata only)
   - Individual textures are loaded on-demand
   - Uses `load_dependency` for proper dependency tracking

2. **Path Handling**:
   - Archive paths: `"textures.wad"`
   - Texture paths: `"textures.wad#brick"`
   - Bevy handles asset path resolution automatically

3. **Efficiency**:
   - Archives only load metadata (texture locations)
   - Textures load only when requested
   - Actual file I/O happens asynchronously

4. **Conversion Pipeline**:
   - Raw texture data → `WadTexture` → Bevy `Image`
   - Handles dependencies between assets

### Usage

1. Create an `assets` folder in your project root
2. Create a sample archive metadata file `assets/textures.wad`:
```json
{
    "brick": {"offset": 0, "size": 1024},
    "stone": {"offset": 1024, "size": 2048}
}
```
3. Create a sample texture file `assets/brick.png` (for testing)
4. Run with `cargo run`

### Customization Points

1. **Actual Archive Format**:
   - Implement your container format in `WadArchiveLoader`
   - Replace the JSON parsing with your format's index

2. **Texture Formats**:
   - Modify `process_textures` to handle your texture format
   - Use `ImageFormat::Dds` for GoldSrc textures

3. **Error Handling**:
   - Add proper error handling for your specific format
   - Handle partial reads and corrupt files

This solution provides a foundation for lazy loading assets from container files while integrating with Bevy's asset system for proper dependency tracking and path resolution.

