    let credentials = StorageCredentials::bearer_token(token);
    let blob_service = BlobServiceClient::new(storage_account, credentials);
    let container_client = Arc::new(blob_service.container_client(container_name));

    // List blobs concurrently
    let list_start = std::time::Instant::now();
    println!("[LOG] Listing blobs...");
    let (opt_blobs, fut_blobs) = tokio::join!(
        list_blobs(Arc::clone(&container_client), prefix_opt),
        list_blobs(Arc::clone(&container_client), prefix_fut)
    );
    let all_blobs = [opt_blobs?, fut_blobs?].concat();
    println!(
        "[LOG] Listed {} blobs in {:.2} seconds",
        all_blobs.len(),
        list_start.elapsed().as_secs_f32()
    );

    // Download and process blobs with concurrency control
