    println!(
        "[LOG] Downloaded {} blobs in {:.2} seconds",
        trades.len(),
        download_start.elapsed().as_secs_f32()
    );

    println!(
        "[LOG] Total operation time: {:.2} seconds",
        start.elapsed().as_secs_f32()
    );
    Ok(trades)
}

async fn get_oauth_token(
    tenant_id: &str,
    client_id: &str,
    client_secret: &str,
) -> Result<String, Box<dyn std::error::Error>> {
    let token_url = format!("https://login.microsoftonline.com/{}/oauth2/v2.0/token", tenant_id);
    let params = TokenRequest {
        grant_type: "client_credentials",
        client_id,
        client_secret,
        scope: "https://storage.azure.com/.default",
    };

    let client = reqwest::Client::new();
    let response = client
        .post(&token_url)
        .form(&params)
        .send()
        .await?
        .error_for_status()?;

    let token_response: TokenResponse = response.json().await?;
    Ok(token_response.access_token)
}

async fn list_blobs(
    container_client: Arc<ContainerClient>,
    prefix: String,
) -> Result<Vec<String>, Box<dyn std::error::Error>> {
    let mut stream = container_client
        .list_blobs()
        .prefix(prefix)
        .into_stream();

    let mut blob_names = Vec::new();
    while let Some(page) = stream.next().await {
        let page = page?;
        for blob in page.blobs.blobs() {
            if blob.name.ends_with(".json") {
                blob_names.push(blob.name.clone());
            }
        }
    }
    Ok(blob_names)
}

async fn download_blobs(
    container_client: Arc<ContainerClient>,
    blob_names: Vec<String>,
) -> Result<Vec<TradeData>, Box<dyn std::error::Error>> {
    let concurrency = std::thread::available_parallelism()?.get();
    let semaphore = Arc::new(Semaphore::new(concurrency));
    let mut tasks = Vec::with_capacity(blob_names.len());

    for blob_name in blob_names {
        let client = Arc::clone(&container_client);
        let permit = Arc::clone(&semaphore).acquire_owned().await?;
        tasks.push(tokio::spawn(async move {
            let result = download_and_parse(&client, &blob_name).await;
            drop(permit);
            result
        }));
    }

    let mut trades = Vec::new();
    for task in tasks {
        match task.await? {
            Ok(trade) => trades.push(trade),
            Err(e) => eprintln!("Error processing blob: {}", e),
        }
    }
    Ok(trades)
}

async fn download_and_parse(
    container_client: &ContainerClient,
    blob_name: &str,
) -> Result<TradeData, Box<dyn std::error::Error>> {
    let blob_client = container_client.blob_client(blob_name);
    let data = blob_client.get_content().await?;
    let trade: TradeData = serde_json::from_slice(&data)?;
    Ok(trade)
}
```

