mod errors;
mod models;
mod persistence;
mod pub_sub;
mod queue_handler;
mod vpn;

use crate::{api::server, app_context::AppContext, queue_handler::Handle};
use actix_web::rt;
use log::{debug, error, info};
use tokio_util::sync::CancellationToken;

#[actix_web::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    log4rs::init_file("./etc/log4rs.yaml", Default::default()).map_err(|e| {
        error!("Error initializing logger: {}", e);
        println!("Error initializing logger: {}", e);
        e
    })?;

    info!("Starting the application.");

    info!("Loading application context...");
    let _context = AppContext::instance();

    info!("Application context loaded successfully!");
    debug!("{:?}", AppContext::instance().config());

    let (actix_server, server_handle) = server::create_server()?;

    info!("Starting queue handler...");
    let queue_handle = Handle::new()?;

    // Create a cancellation token for graceful shutdown
    let cancel_token = CancellationToken::new();
    let cloned_token = cancel_token.clone();

    // Spawn the Actix server and capture its join handle
    let actix_server_handle = rt::spawn(actix_server);

    // Spawn the queue handler task with the cancellation token
    let queue_handler_handle = tokio::spawn(async move {
        // Assume queue_handle.run() is modified to accept a CancellationToken
        queue_handle.run(cloned_token).await
    });

    // Wait for Ctrl+C signal
    tokio::signal::ctrl_c().await?;
    info!("Ctrl+C received. Starting graceful shutdown...");

    // Signal the queue handler to stop
    cancel_token.cancel();
    // Stop the Actix server gracefully
    server_handle.stop(true).await;

    // Wait for the queue handler to finish
    if let Err(e) = queue_handler_handle.await {
        error!("Queue handler task failed: {:?}", e);
    }

    // Wait for the Actix server task to finish
    if let Err(e) = actix_server_handle.await {
        error!("Actix server task failed: {:?}", e);
    }

    info!("Shutdown complete.");
    Ok(())
}
```

### Explanation
1. **Cancellation Token**: The `CancellationToken` is cloned and passed to the queue handler task. When `cancel_token.cancel()` is called, it signals the queue handler to stop processing.
2. **Task Handles**: The join handles for both tasks (`actix_server_handle` and `queue_handler_handle`) are stored. This allows us to await their completion after initiating shutdown.
3. **Graceful Shutdown**:
   - **Queue Handler**: Should be modified to periodically check `token.is_cancelled()` and exit cleanly.
   - **Actix Server**: Stopped using `server_handle.stop(true).await`, which waits for pending requests to complete.
4. **Error Handling**: Errors from task completion are logged to ensure visibility during shutdown.

This approach ensures both tasks are stopped gracefully, with no background processes left running after the program exits.

