use std::{net::SocketAddr, path::PathBuf};
use hyper::{
    server::conn::http1,
    service::service_fn,
    Request, Response, StatusCode,
};
use hyper_util::rt::TokioIo;
use tokio::{fs::File, net::TcpListener};
use http_body_util::{BodyExt, Full};
use tokio_util::io::ReaderStream;
use futures::TryStreamExt;

async fn handle_request(req: Request<hyper::body::Incoming>) -> Result<Response<http_body_util::combinators::BoxBody<bytes::Bytes, std::io::Error>>, hyper::http::Error> {
    let path = PathBuf::from(".").join(
        req.uri()
            .path()
            .trim_start_matches('/')
            .trim_end_matches('/')
    );

    match File::open(&path).await {
        Ok(file) => {
            let stream = ReaderStream::new(file);
            let body = http_body_util::StreamBody::new(stream.map_err(|e| {
                std::io::Error::new(e.kind(), format!("File read error: {}", e))
            }))
            .boxed();

            Response::builder()
                .status(StatusCode::OK)
                .header("Content-Type", "application/octet-stream")
                .body(body)
        },
        Err(e) => {
            let status = if e.kind() == std::io::ErrorKind::NotFound {
                StatusCode::NOT_FOUND
            } else {
                StatusCode::INTERNAL_SERVER_ERROR
            };

            Response::builder()
                .status(status)
                .body(Full::new(e.to_string().into()).map_err(|_| unreachable!()).boxed())
        }
    }
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error + Send + Sync>> {
    let addr = SocketAddr::from(([127, 0, 0, 1], 3000));
    let listener = TcpListener::bind(addr).await?;
    println!("Serving files at http://{}/", addr);

    loop {
        let (tcp, _) = listener.accept().await?;
        let io = TokioIo::new(tcp);

