use std::iter::Iterator;

#[derive(Debug, Clone)]
pub struct Array<T> {
    store: Vec<T>,
    dims: Vec<usize>,
}

impl<T> Array<T> {
    pub fn new(store: Vec<T>, dims: Vec<usize>) -> Self {
        let total_size: usize = dims.iter().product();
        assert_eq!(store.len(), total_size, "Store length must match product of dimensions");
        Array { store, dims }
    }

    // Immutable iterator for the entire array in row-major order
    pub fn iter(&self) -> impl Iterator<Item = (Vec<usize>, &T)> {
        let dims = self.dims.clone();
        self.store.iter().enumerate().map(move |(i, value)| {
            (unflatten(i, &dims), value)
        })
    }

    // Mutable iterator for the entire array in row-major order
    pub fn iter_mut(&mut self) -> impl Iterator<Item = (Vec<usize>, &mut T)> {
        let dims = self.dims.clone();
        self.store.iter_mut().enumerate().map(move |(i, value)| {
            (unflatten(i, &dims), value)
        })
    }
}

// Helper function to convert a flat index to a multidimensional index.
fn unflatten(mut index: usize, dims: &[usize]) -> Vec<usize> {
    let mut result = Vec::with_capacity(dims.len());
    for &dim in dims.iter().rev() {
        result.push(index % dim);
        index /= dim;
    }
    result.reverse();
    result
}

fn main() {
    let mut array = Array::new(vec![1, 2, 3, 4, 5, 6], vec![2, 3]);

    println!("Immutable iteration:");
    for (index, value) in array.iter() {
        println!("Index: {:?}, Value: {}", index, value);
    }

    println!("Mutable iteration:");
    for (index, value) in array.iter_mut() {
        *value *= 10;
        println!("Index: {:?}, Value: {}", index, value);
    }

    println!("After mutation:");
    for (index, value) in array.iter() {
        println!("Index: {:>?}, Value: {}", index, value);
    }
}
```

### Explanation
1. **Array Structure**: The `Array` struct holds a `Vec<T>` for storage and a `Vec<usize>` for dimensions.
2. **Constructors**: The `new` constructor ensures the storage size matches the product of the dimensions.
3. **Iterators**:
   - **Immutable Iterator**: Uses `enumerate` to iterate over each element, converting the flat index to a multidimensional index using `unflatten`.
   - **Mutable Iterator**: Similarly, uses `enumerate` and `unflatten` but allows mutating elements via `iter_mut`.
4. **Index Calculation**: The `unflatten` function converts a flat index into a multidimensional index by processing dimensions in reverse order.
5. **Demonstration**: The `main` function shows immutable iteration, mutable iteration (modifying values), and verification of changes.

This approach safely handles mutable references by leveraging the array's contiguous storage and row-major iteration, avoiding complex lifetime issues while providing efficient access to elements.

