use std::fmt::{Debug, Display};

#[derive(Debug, thiserror::Error)]
pub enum FrameworkError {
    #[error("400: {0}")]
    Error400(Box<dyn std::error::Error>),
}

pub mod my_library {
    pub mod extensions {
        pub mod logging {
            use crate::FrameworkError;
            use log::{log, Level, Metadata, Record};

            macro_rules! warn {
                ($loc:expr, $($arg:tt)+) => {{
                    let module_path = $loc.module_path().unwrap_or("");
                    let logger = log::logger();
                    let metadata = Metadata::builder()
                        .level(Level::Warn)
                        .target(module_path)
                        .build();
                    if logger.enabled(&metadata) {
                        let record = Record::builder()
                            .metadata(metadata)
                            .args(format_args!($($arg)+))
                            .file(Some($loc.file()))
                            .line(Some($loc.line()))
                            .module_path(Some(module_path))
                            .build();
                        logger.log(&record);
                    }
                }};
            }

            macro_rules! info {
                ($loc:expr, $($arg:tt)+) => {{
                    let module_path = $loc.module_path().unwrap_or("");
                    let logger = log::logger();
                    let metadata = Metadata::builder()
