use axum::{
    extract::{self, ws::WebSocket},
    http::StatusCode,
    response::Response,
    routing::get,
    Router,
};
use axum_extra::headers;
use axum_extra::typed_header::TypedHeader;
use std::net::SocketAddr;

#[tokio::main]
async fn main() {
    let app = Router::new()
        .route("/", get(handler))
        .route("/client/:session_id", get(client_handler))
        .layer(
            tower_http::cors::CorsLayer::new()
                .allow_origin("https://www.example.com".parse::<headers::Origin>().unwrap())
                .allow_methods([axum::http::Method::GET, axum::http::Method::POST])
                .allow_headers([axum::http::header::CONTENT_TYPE]),
        );

    let addr = SocketAddr::from(([127, 0, 0, 1], 3000));
    println!("Listening on {}", addr);
    axum::Server::bind(&addr)
        .serve(app.into_make_service())
        .await
        .unwrap();
}

async fn handler() -> &'static str {
    "Regular HTTP endpoint with CORS protection"
}

async fn client_handler(
    extract::Path(session_id): extract::Path<String>,
    ws: extract::WebSocketUpgrade,
    origin: Option<TypedHeader<headers::Origin>>,
) -> Result<Response, StatusCode> {
    // Parse the allowed origin
    let allowed_origin: headers::Origin = "https://www.example.com"
        .parse()
        .expect("Valid origin format");

    // Validate the request origin
    match origin {
        Some(TypedHeader(origin)) if origin == allowed_origin => {}
        _ => return Err(StatusCode::FORBIDDEN),
    }

    // Proceed with WebSocket upgrade
    Ok(ws.on_upgrade(move |socket| handle_socket(socket, session_id)))
}

async fn handle_socket(mut socket: WebSocket, session_id: String) {
    // Simple echo implementation
    while let Some(Ok(msg)) = socket.recv().await {
        if let axum::extract::ws::Message::Text(text) = msg {
            if socket
                .send(axum::extract::ws::Message::Text(text))
                .await
                .is_err()
            {
                break;
            }
        }
    }
}
```

This solution provides:

