        let ws = client.ws("/echo").await.expect("WebSocket connection");

        // Split the WebSocket into sender and receiver
        let (mut ws_sink, mut ws_stream) = ws.split();

        // Send test message
        ws_sink
            .send(Message::Text("Hello Rocket!".into()))
            .await
            .expect("send message");

        // Receive echo response
        match ws_stream.next().await {
            Some(Ok(Message::Text(text))) => {
                assert_eq!(text, "Hello Rocket!");
            }
            Some(Ok(msg)) => panic!("Unexpected message type: {:?}", msg),
            Some(Err(e)) => panic!("WebSocket error: {:?}", e),
            None => panic!("Connection closed unexpectedly"),
