Here's a self-contained solution for implementing draggable SVG elements using custom event handling in Dioxus:

### Cargo.toml
```toml
[package]
name = "dioxus_drag_example"
version = "0.1.0"
edition = "2021"

[dependencies]
dioxus = { version = "0.7", features = ["web"] }
dioxus-web = "0.7"
log = "0.4"
```

### main.rs
```rust
use dioxus::prelude::*;
use dioxus_web::Config;

#[derive(Clone, Copy, Default, PartialEq)]
struct ElementPoint {
    x: f64,
    y: f64,
}

impl ElementPoint {
    fn new(x: f64, y: f64) -> Self {
        Self { x, y }
    }
}

#[derive(Clone, Copy)]
struct DragState {
    mouse_position: Signal<ElementPoint>,
    is_dragged: Signal<bool>,
}

impl DragState {
    fn new() -> Self {
        Self {
            mouse_position: Signal::new(ElementPoint::default()),
            is_dragged: Signal::new(false),
        }
    }
}

fn main() {
    dioxus_web::launch_cfg(App, Config::new());
}

#[component]
fn App() -> Element {
    rsx! {
        div {
            style: "text-align: center;",
            h1 { "Drag points in SVG" }
            DragProvider {
                Point { id: 0, x: 100.0, y: 100.0, r: 5.0 }
                Point { id: 1, x: 200.0, y: 200.0, r: 5.0 }
                Point { id: 2, x: 300.0, y: 300.0, r: 5.0 }
            }
        }
    }
}

#[component]
fn DragProvider(children: Element) -> Element {
    let drag_state = use_context_provider(|| DragState::new());

    rsx! {
        div {
            style: "width: 400px; height: 400px; margin: 0 auto;",
            svg {
                width: "400",
                height: "400",
                style: "border: 1px solid black; background-color: #f0f0f0;",
                onmousemove: move |e| {
                    let coords = e.element_coordinates();
                    drag_state.mouse_position.set(ElementPoint::new(coords.x, coords.y));
                },
                onmousedown: move |_| drag_state.is_dragged.set(true),
                onmouseup: move |_| drag_state.is_dragged.set(false),
                onmouseleave: move |_| drag_state.is_dragged.set(false),
                {children}
            }
        }
    }
}

#[component]
fn Point(id: usize, x: f64, y: f64, r: f64) -> Element {
    let mut coords = use_signal(|| ElementPoint::new(x, y));
    let mut is_dragged = use_signal(|| false);
    let drag_state = use_context::<DragState>();

    use_effect(move || {
        if *is_dragged.read() {
            if !*drag_state.is_dragged.read() {
                is_dragged.set(false);
            } else {
                let new_pos = *drag_state.mouse_position.read();
                if new_pos != *coords.read() {
                    coords.set(new_pos);
                }
            }
        }
    });

    rsx! {
        circle {
            class: "point",
            cx: "{coords.read().x}",
            cy: "{coords.read().y}",
            r: "{r}",
            fill: "blue",
            onmousedown: move |_| is_dragged.set(true),
        }
    }
}
```

### Key Features:

1. **Context-Based State Management**:
   - `DragState` shared via context provides mouse position and drag status
   - Eliminates the need for prop drilling

2. **Optimized Rendering**:
   - Only dragged points update their position
   - No full component tree rebuilds during dragging
   - Uses signals for efficient state updates

3. **Accurate Mouse Tracking**:
