```rust
use std::env;
use std::fs;
use std::io::{self, ErrorKind};
use std::path::Path;

const FILE_PATH: &str = "output.json";

fn load_or_create_todos() -> Vec<String> {
    if !Path::new(FILE_PATH).exists() {
        return Vec::new();
    }

    let data = match fs::read_to_string(FILE_PATH) {
        Ok(data) => data,
        Err(e) => {
            eprintln!("Error reading file: {}", e);
            Vec::new()
        }
    };

    serde_json::from_str(&data).unwrap_or_else(|e| {
        eprintln!("Error parsing JSON: {}", e);
        Vec::new()
    })
}

fn save_todos(todos: &[String]) -> io::Result<()> {
    let json = serde_json::to_string_pretty(todos)?;
    fs::write(FILE_PATH, json)
}

fn main() {
    let args: Vec<String> = env::args().skip(1).collect();

    if args.is_empty() {
        let todos = load_or_create_todos();
        println!("Current todos: {:?}", todos);
        return;
    }

    let mut todos = load_or_create_todos();
    todos.extend(args);

    match save_todos(&todos) {
        Ok(_) => println!("Successfully saved {} todos", todos.len()),
        Err(e) => eprintln!("Error saving todos: {}", e),
    }
}
```

