use dioxus::prelude::*;
use dioxus_signals::*;
use log::info;

#[derive(Clone, Copy, Debug)]
struct DragState {
    mouse_position: Signal<ElementPoint>,
    is_dragging: Signal<bool>,
}

impl DragState {
    fn new() -> Self {
        Self {
            mouse_position: Signal::new(ElementPoint::default()),
            is_dragging: Signal::new(false),
        }
    }
}

#[component]
fn DragProvider(children: Element) -> Element {
    let drag_state = use_context_provider(|| DragState::new());

    rsx! {
        div {
            id: "drag-provider",
            style: "width: 100%; height: 100%; position: fixed; top: 0; left: 0;",
            onmousemove: move |e| {
                drag_state.mouse_position.set(e.element_coordinates());
                e.stop_propagation();
            },
            onmousedown: move |_| {
                drag_state.is_dragging.set(true);
            },
            onmouseup: move |_| {
                drag_state.is_dragging.set(false);
            },
            onmouseleave: move |_| {
                drag_state.is_dragging.set(false);
            },
            {children}
        }
    }
}

#[derive(Props, PartialEq, Clone)]
struct PointProps {
    x: f64,
    y: f64,
    id: usize,
}

#[component]
fn Point(props: PointProps) -> Element {
    let PointProps { x, y, id } = props;
    let mut coords = use_signal(|| ElementPoint::new(x, y));
    let mut is_dragged = use_signal(|| false);
    let drag_state = use_context::<DragState>();

    use_effect(move || {
        info!("Point {} created at: {:?}", id, coords.read());
    });

    if *is_dragged.read() {
        if !*drag_state.is_dragging.read() {
            is_dragged.set(false);
        } else {
            let new_pos = *drag_state.mouse_position.read();
            if new_pos != *coords.read() {
                coords.set(new_pos);
                info!("Point {} moved to: {:?}", id, new_pos);
            }
        }
    }

    rsx! {
        circle {
            class: "point",
            cx: "{coords.read().x}",
            cy: "{coords.read().y}",
            r: "5",
            fill: "blue",
            onmousedown: move |_| {
                if !*is_dragged.read() {
                    is_dragged.set(true);
                    drag_state.is_dragging.set(true);
                }
            },
        }
    }
}

fn App() -> Element {
    rsx! {
        DragProvider {
            svg {
                width: "100%",
                height: "100%",
                view_box: "0 0 400 400",
                rect {
                    width: "100%",
                    height: "100%",
                    fill: "lightgray",
                },
                Point { x: 50.0, y: 50.0, id: 0 },
                Point { x: 150.0, y: 150.0, id: 1 },
            }
        }
    }
}

fn main() {
    console_log::init_with_level(log::Level::Debug).expect("Failed to initialize logger");
    dioxus_web::launch(App);
}
```

### Explanation

1. **DragProvider Component**:
   - Provides a context (`DragState`) containing the current mouse position and a flag indicating whether a drag operation is active.
   - Tracks mouse events (`mousemove`, `mousedown`, `mouseup`, `mouseleave`) across the entire viewport to update the context's signals.

2. **Point Component**:
   - Uses the shared `DragState` context to determine when to update its position.
   - Maintains its own dragged state (`is_dragged`) and coordinates (`coords`).
   - When `is_dragged` is true, it updates its position to match the global mouse position stored in the context.
   - Starts dragging on `mousedown` and stops when the global drag state ends.

3. **Efficiency**:
   - Signals ensure that only components dependent on changed state re-render.
   - Mouse events are handled at the top level, preventing excessive event listeners on individual SVG elements.

This approach allows efficient dragging of multiple SVG elements while maintaining a clean separation of concerns between the drag provider and draggable points.

