const PIXELS_PER_SIDE: usize = 8;
const PIXELS_PER_LINE: usize = PIXELS_PER_SIDE;
const BYTES_PER_PIXEL: usize = 4;

/// Flips a line of 4-byte pixels horizontally using u32 swaps and unrolled loop
fn flip_line(line_bytes: &mut [u8]) {
    debug_assert_eq!(line_bytes.len(), PIXELS_PER_LINE * BYTES_PER_PIXEL);

    // Cast byte slice to u32 slice for efficient pixel swapping
    let pixels = unsafe {
        std::slice::from_raw_parts_mut(
            line_bytes.as_mut_ptr() as *mut u32,
            PIXELS_PER_LINE
        )
    };

    // Unrolled swaps for maximum speed (fixed 8-pixel line)
    pixels.swap(0, 7);
    pixels.swap(1, 6);
    pixels.swap(2, 5);
    pixels.swap(3, 4);
}

#[cfg(test)]
