impl MdxParsingResult {
    // Single-threaded serialization
    pub fn serialize_single_threaded(&self) -> Vec<u8> {
        let mut builder = FlatBufferBuilder::new();

        let content = builder.create_string(&self.content);

        // Serialize front matter
        let ignored_parsers = self.front_matter.as_ref().map(|fm| {
            let ignored: Vec<_> = fm
                .ignored_parsers
                .iter()
                .map(|s| builder.create_string(s))
                .collect();
            builder.create_vector(&ignored)
        });

        // Serialize citations
        let citations = if self.citations.is_empty() {
            None
        } else {
            let cit: Vec<_> = self
                .citations
                .iter()
                .map(|s| builder.create_string(s))
                .collect();
            Some(builder.create_vector(&cit))
        };

        // Serialize tags
        let tags = if self.tags.is_empty() {
            None
        } else {
            let t: Vec<_> = self.tags.iter().map(|s| builder.create_string(s)).collect();
            Some(builder.create_vector(&t))
        };

        // Create the FlatBuffer
        let args = fbs::MdxParsingResultFBArgs {
            parsed_content: Some(content),
            ignored_parsers,
            citations,
            tags,
        };

        let root = fbs::MdxParsingResultFBBuilder::create(&mut builder, &args);
        builder.finish(root, None);

        builder.finished_data().to_vec()
    }

    // Multi-threaded serialization using Rayon
    pub fn serialize_multi_threaded(&self) -> Vec<u8> {
        // Pre-process expensive operations in parallel
        let front_matter_arc = Arc::new(self.front_matter.clone());

        // Process ignored_parsers in parallel
        let ignored_parsers: Option<Vec<String>> = front_matter_arc
            .as_ref()
            .map(|fm| fm.ignored_parsers.par_iter().cloned().collect());

        // Process citations in parallel
        let citations: Vec<String> = self
            .citations
            .par_iter()
            .cloned()
            .collect();

        // Process tags in parallel
        let tags: Vec<String> = self.tags.par_iter().cloned().collect();

        // Now serialize single-threaded
        let mut builder = FlatBufferBuilder::new();

        let content = builder.create_string(&self.content);

        // Create ignored_parsers vector
        let ignored_fb = ignored_parsers.as_ref().map(|ignored| {
            let ignored_offsets: Vec<_> = ignored
                .iter()
                .map(|s| builder.create_string(s))
                .collect();
            builder.create_vector(&ignored_offsets)
        });

        // Create citations vector
        let citations_fb = if citations.is_empty() {
            None
        } else {
            let cit_offsets: Vec<_> = citations
                .iter()
                .map(|s| builder.create_string(s))
                .collect();
            Some(builder.create_vector(&cit_offsets))
        };

        // Create tags vector
        let tags_fb = if tags.is_empty() {
            None
        } else {
            let tag_offsets: Vec<_> = tags.iter().map(|s| builder.create_string(s)).collect();
            Some(builder.create_vector(&tag_offsets))
        };

        // Create the FlatBuffer
        let args = fbs::MdxParsingResultFBArgs {
            parsed_content: Some(content),
            ignored_parsers: ignored_fb,
            citations: citations_fb,
            tags: tags_fb,
        };

        let root = fbs::MdxParsingResultFBBuilder::create(&mut builder, &args);
        builder.finish(root, None);

        builder.finished_data().to_vec()
    }
}

fn main() {
    // Create sample data
    let data = MdxParsingResult {
        front_matter: Some(FrontMatter {
            ignored_parsers: vec!["parser1".into(), "parser2".into()],
        }),
        content: "Hello, world!".into(),
        citations: vec!["citation1".into(), "citation2".into()],
        tags: vec!["tag1".into(), "tag2".into()],
    };

    println!("Serializing single-threaded...");
    let buffer_st = data.serialize_single_threaded();
    println!("Serialized size: {} bytes", buffer_st.len());

    println!("\nSerializing multi-threaded...");
    let buffer_mt = data.serialize_multi_threaded();
    println!("Serialized size: {} bytes", buffer_mt.len());

    println!("\nBoth methods produced buffers of same size: {}", 
        buffer_st.len() == buffer_mt.len());
}
"
  }
}
