    println!("Successfully decoded SignedData");
    println!("SignedData version: {}", signed_data.version);
    println!(
        "Digest Algorithms: {}",
        signed_data
            .digest_algorithms
            .iter()
            .map(|alg| alg.oid.to_string())
            .collect::<Vec<_>>()
            .join(", ")
    );

    // Handle encapsulated content
    let encap_content_info: &EncapsulatedContentInfo = &signed_data.encap_content_info;
    println!("eContent Type: {}", encap_content_info.econtent_type);
    if let Some(econtent) = &encap_content_info.econtent {
        write_bytes_to_file("econtent.der", econtent.as_bytes())?;
        println!("eContent written to econtent.der (length: {} bytes)", econtent.as_bytes().len());
    } else {
        println!("No eContent present");
    }

    // Process certificates
    println!("\nCertificates:");
    if let Some(certs) = &signed_data.certificates {
        for (i, cert) in certs.iter().enumerate() {
