    for (i, signer) in signed_data.signer_infos.iter().enumerate() {
        println!("SignerInfo #{}:", i + 1);
        println!("  Version: {}", signer.version);
        println!("  Issuer: {}", signer.sid.issuer);
        println!("  Serial: {}", signer.sid.serial_number);
    }

    Ok(())
}
