```rust
use rayon::prelude::*;

#[derive(Debug, Default, Clone)]
struct B {
    r: Vec<f64>,
    v: Vec<f64>,
    f: Vec<f64>,
    nb: Vec<usize>,
}

impl B {
    pub fn criterion(&self, other: &B) -> f64 {
        let dx = self.r[0] - other.r[0];
        let dy = self.r[1] - other.r[1];
        let dz = self.r[2] - other.r[2];
        dx * dx + dy * dy + dz * dz
    }
}

#[derive(Debug, Default, Clone)]
struct A {
    elems: Vec<B>,
    cutoff: f64,
}

impl A {
    pub fn get_nelems(&self) -> usize {
        self.elems.len()
    }

    pub fn build_lists(&mut self) {
        let nelems = self.get_nelems();
        let cutoff = self.cutoff;
        let elems = &self.elems; // Immutable reference for parallel access

        // Precompute neighbor lists in parallel
        let neighbors: Vec<Vec<usize>> = (0..nelems)
            .into_par_iter()
            .map(|i| {
                let mut nb = Vec::new();
                for j in 0..nelems {
                    if i == j {
                        continue;
                    }
                    if elems[i].criterion(&elems[j]) < cutoff {
                        nb.push(j);
                    }
                }
                nb
            })
            .collect();

        // Assign computed neighbor lists
        for (elem, nb_list) in self.elems.iter_mut().zip(neighbors) {
            elem.nb = nb_list;
        }
    }
}

fn main() {
    // Create test data
    let mut a = A {
        elems: vec![
            B {
                r: vec![0.0, 0.0, 0.0],
                ..Default::default()
            },
            B {
                r: vec![1.0, 0.0, 0.0],
                ..Default::default()
            },
            B {
                r: vec![0.0, 2.0, 0.0],
                ..Default::default()
            },
            B {
                r: vec![0.5, 0.0, 0.0],
                ..Default::default()
            },
        ],
        cutoff: 1.1, // Squared cutoff = 1.21
    };

    // Build neighbor lists
    a.build_lists();

    // Verify results
    for (i, elem) in a.elems.iter().enumerate() {
        println!("Element {} at {:?} has neighbors: {:?}", i, elem.r, elem.nb);
    }

    // Expected:
    // Element 0: neighbors [1, 3] (distances 1.0 and 0.5)
    // Element 1: neighbors [0, 3] (distances 1.0 and sqrt(0.5²+1²)≈1.118)
    // Element 2: no neighbors (distance > 1.1)
    // Element 3: neighbors [0, 1] (distances 0.5 and ≈1.118)
}
```

