Here's the solution:

**Cargo.toml**
```toml
[package]
name = "cow_struct_fix"
version = "0.1.0"
edition = "2021"
```

**main.rs**
```rust
use std::borrow::Cow;
use std::marker::PhantomData;

trait Resource {
    type DynamicType: Default;
    fn group(dynamic_type: &Self::DynamicType) -> Cow<'_, str>;
    fn kind(dynamic_type: &Self::DynamicType) -> Cow<'_, str>;
    fn meta(&self) -> Metadata;
}

struct Metadata {
    name: Option<String>,
}

#[derive(Default)]
struct SampleDynamicType;

struct SampleResource {
    meta: Metadata,
}

impl Resource for SampleResource {
    type DynamicType = SampleDynamicType;

    fn group(_: &Self::DynamicType) -> Cow<'_, str> {
        Cow::Borrowed("example.com")
    }

    fn kind(_: &Self::DynamicType) -> Cow<'_, str> {
        Cow::Borrowed("Pod")
    }

    fn meta(&self) -> Metadata {
        Metadata {
            name: self.meta.name.clone(),
        }
    }
}

#[derive(Debug, Clone)]
pub struct ResourceRef<R: Resource>
where
    R::DynamicType: Default,
{
    type_: PhantomData<R>,
    dynamic_type: R::DynamicType,
    group: Option<String>,
    kind: String,
    name: String,
}

impl<R: Resource> ResourceRef<R>
where
    R::DynamicType: Default,
{
    pub fn new(resource: R) -> Self {
        let name = resource
            .meta()
            .name
            .as_deref()
            .expect("Resource must have a name");
        Self::new_named(name)
    }

    pub fn new_named(name: &str) -> Self {
        let dynamic_type = R::DynamicType::default();
        let group_cow = R::group(&dynamic_type);
        let kind_cow = R::kind(&dynamic_type);

        Self {
            type_: PhantomData,
            dynamic_type,
            group: if group_cow.is_empty() {
                None
            } else {
                Some(group_cow.into_owned())
            },
            kind: kind_cow.into_owned(),
            name: name.to_string(),
        }
    }

    pub fn group(&self) -> &str {
        self.group.as_deref().unwrap_or("")
    }

    pub fn kind(&self) -> &str {
        &self.kind
    }

    pub fn name(&self) -> &str {
        &self.name
    }
}

fn main() {
    let resource = SampleResource {
        meta: Metadata {
            name: Some("my-resource".to_string()),
        },
    };

    let resource_ref = ResourceRef::<SampleResource>::new(resource);
    println!("ResourceRef created successfully!");
    println!("Group: {}", resource_ref.group());
    println!("Kind: {}", resource_ref.kind());
    println!("Name: {}", resource_ref.name());
}
```

This solution:
1. Uses owned Strings instead of Cow references
2. Removes lifetime parameters that are no longer needed
3. Converts Cow values to owned Strings during construction
