  "main.rs": {
    "content": "use std::fmt;

use chumsky::prelude::*;
use chumsky::extra;

#[derive(Debug, Clone, PartialEq)]
pub enum Token {
    Ident(String),
    Num(i64),
    Add,
    Sub,
}

impl fmt::Display for Token {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        match self {
            Token::Ident(s) => write!(f, "identifier '{}'", s),
            Token::Num(n) => write!(f, "number {}", n),
            Token::Add => write!(f, "'+'"),
            Token::Sub => write!(f, "'-'"),
        }
    }
}

pub trait BaseParser {
    type InputToken<'src>: PartialEq + fmt::Display + 'src;
    type Input<'src>: ChumskyInput<'src, Token = Self::InputToken<'src>, Span = SimpleSpan>;
    type Output;

    fn parser<'src>() -> impl ChumskyParser<
        'src,
        Self::Input<'src>,
        Self::Output,
        extra::Err<Rich<'src, Self::InputToken<'src>, SimpleSpan>>,
    >;

    fn parse_this<'src>(input: Self::Input<'src>) -> Result<Self::Output, Vec<String>> {
        Self::parser().parse(input).into_result().map_err(|errors| {
            errors
                .into_iter()
                .map(|e| e.to_string())
                .collect::<Vec<_>>()
        })
    }
}

struct IdentifierParser;

impl BaseParser for IdentifierParser {
    type InputToken<'src> = Token;
    type Input<'src> = &'src [Token];
    type Output = String;

    fn parser<'src>() -> impl ChumskyParser<'src, Self::Input<'src>, Self::Output, extra::Err<Rich<'src, Token, SimpleSpan>>> {
        filter(|tok| matches!(tok, Token::Ident(_)))
            .map(|tok| match tok {
                Token::Ident(s) => s,
                _ => unreachable!(),
            })
    }
}

struct NumberParser;

impl BaseParser for NumberParser {
    type InputToken<'src> = Token;
    type Input<'src> = &'src [Token];
    type Output = i64;

    fn parser<'src>() -> impl ChumskyParser<'src, Self::Input<'src>, Self::Output, extra::Err<Rich<'src, Token, SimpleSpan>>> {
        filter(|tok| matches!(tok, Token::Num(_)))
            .map(|tok| match tok {
                Token::Num(n) => *n,
                _ => unreachable!(),
            })
    }
}

fn main() {
    // Parse identifier
    let tokens = vec![Token::Ident("foo".to_string())];
    let result = IdentifierParser::parse_this(tokens.as_slice());
    println!("Identifier parse: {:?}", result);

