    let result = NumberParser::parse_this(tokens.as_slice());
    println!("Number parse: {:?}", result);

    // Error case
    let tokens = vec![Token::Add];
    let result = NumberParser::parse_this(tokens.as_slice());
    println!("Error case: {:?}", result);
}"
  }
}
