**main.rs**:
```rust
use std::io::ErrorKind;
use std::os::unix::net::UnixDatagram;
use std::path::Path;
use std::sync::mpsc;
use std::thread;
use std::time::{Duration, Instant};

use cadence::prelude::*;
use cadence::{BufferedUnixMetricSink, QueuingMetricSink, StatsdClient};
use tempfile::tempdir;

fn run_mock_agent(socket_path: &Path, ready_tx: mpsc::Sender<()>) -> usize {
    // Remove existing socket file
    let _ = std::fs::remove_file(socket_path);

    let socket = match UnixDatagram::bind(socket_path) {
        Ok(s) => s,
        Err(e) => panic!("failed to bind to socket {}: {}", socket_path.display(), e),
    };

    // Signal readiness
    ready_tx.send(()).expect("failed to send ready signal");

    let mut count = 0;
    let mut buf = [0; 1024];
    let mut last_received = Instant::now();
    let timeout = Duration::from_secs(2); // Increased timeout for reliability

    loop {
        let elapsed = last_received.elapsed();
        if elapsed >= timeout {
            println!("Mock agent: timeout after {:?}", elapsed);
            break;
        }

        let remaining = timeout - elapsed;
        socket
            .set_read_timeout(Some(remaining))
            .expect("set_read_timeout failed");

        match socket.recv(&mut buf) {
            Ok(n) => {
                let payload = String::from_utf8_lossy(&buf[..n]);
                // Count all metrics in payload (newline separated)
                count += payload.trim().split('\n').count();
                last_received = Instant::now();
            }
            Err(e) if e.kind() == ErrorKind::WouldBlock || e.kind() == ErrorKind::TimedOut => break,
            Err(e) => {
                eprintln!("Mock agent recv error: {:?}", e);
                break;
            }
        }
    }

    println!("Mock agent received {} metrics", count);
    count
}

fn main() {
    let tempdir = tempdir().expect("failed to create tempdir");
    let socket_path = tempdir.path().join("dsd.socket");

    // Agent readiness channel
    let (ready_tx, ready_rx) = mpsc::channel();

    println!("Starting mock agent...");
    let mock_agent_handle = thread::spawn({
        let socket_path = socket_path.clone();
        move || run_mock_agent(&socket_path, ready_tx)
    });

    // Wait for agent initialization
    ready_rx.recv().expect("failed to receive ready signal");
    println!("Mock agent ready, socket created at {:?}", socket_path);

    // Configure client with same parameters as production
    let sock = UnixDatagram::unbound().expect("unbound socket failed");
    sock.connect(&socket_path).expect("socket connect failed");
    let buffered_sink = BufferedUnixMetricSink::from(&socket_path, sock);
    let queuing_sink = QueuingMetricSink::from(buffered_sink);
    let client = StatsdClient::builder("test", queuing_sink)
        .with_error_handler(|e| eprintln!("[STATSD_ERR]: {:?}", e))
        .build();

    // High-volume test parameters
    const NUM_METRICS: usize = 100_000;
    const BATCH_SIZE: usize = 10_000;

    println!("Sending {} metrics...", NUM_METRICS);
    for i in 0..NUM_METRICS {
        client
            .count("test.operations", 1)
            .with_tag("client", "test")
            .with_tag("network", "mainnet")
            .send();

        if i > 0 && i % BATCH_SIZE == 0 {
            println!("Sent: {}", i);
        }
    }

    println!("Metrics sent, dropping client...");
    drop(client); // Force flush
    println!("Client dropped, waiting for agent...");

    let received = mock_agent_handle.join().unwrap();
    let success = received == NUM_METRICS;

    println!(
        "Test {} - Sent: {}, Received: {}",
        if success { "PASSED" } else { "FAILED" },
        NUM_METRICS,
        received
    );

    if !success {
        eprintln!(
            "ERROR: Only received {}/{} metrics ({:.2}%)",
            received,
            NUM_METRICS,
            (received as f32 / NUM_METRICS as f32) * 100.0
        );
    }
}
```

### Key Features:
1. **Realistic Simulation**:
   - Uses same `cadence` crate with queuing/buffered sinks
   - High-volume metric sending (100k metrics)
   - Tagged metrics like production code

2. **Diagnostic Tools**:
   - Mock agent that validates metric delivery
   - Detailed error reporting
   - Buffer/count management
   - Performance logging

3. **Self-contained**:
   - No external dependencies needed
   - Automatic temp directory cleanup
   - Standalone executable

### How to Use:
1. Create new project: `cargo new dogstatsd_test`
2. Replace `Cargo.toml` and `src/main.rs` with above files
3. Run: `cargo run`

### Expected Output:
```
Starting mock agent...
Mock agent ready, socket created at "..."
Sending 100000 metrics...
Sent: 10000
...
Sent: 90000
Metrics sent, dropping client...
Client dropped, waiting for agent...
Mock agent received 100000 metrics
Test PASSED - Sent: 100000, Received: 100000
```

### Interpretation:
- If test passes: Your original client code is working correctly and the issue is likely in the Datadog agent configuration or infrastructure
- If test fails: Shows client-side issues (queue handling, buffer sizes, threading)
- Check the percentage of received metrics to identify patterns

You can adjust `NUM_METRICS` and `BATCH_SIZE` to match your production throughput. The mock agent will report exactly how many metrics made it through the Unix socket pipeline.

