```rust
use std::{fs, path::Path, str::FromStr};

use sqlx::{
    query_as, Acquire, ColumnIndex, Database, Decode, FromRow, Pool, Row, Sqlite, SqlitePool, Type,
    sqlite::SqliteConnectOptions,
};
use uuid::Uuid;

#[derive(Debug, PartialEq)]
pub struct Employee {
    pub id: u64,
    pub name: String,
    pub team: Team,
}

impl<'r, R: Row> FromRow<'r, R> for Employee
where
    &'r str: ColumnIndex<R>,
    u64: Decode<'r, R::Database> + Type<R::Database>,
    String: Decode<'r, R::Database> + Type<R::Database>,
{
    fn from_row(row: &'r R) -> Result<Self, sqlx::Error> {
        let id = row.try_get("id")?;
        let name = row.try_get("name")?;
        let team_id = row.try_get("team_id")?;
        let team_name = row.try_get("team_name")?;

        Ok(Employee {
            id,
            name,
            team: Team {
                id: team_id,
                name: team_name,
            },
        })
    }
}

#[derive(Debug, FromRow, PartialEq)]
pub struct EmployeeWithTeamId {
    pub id: u64,
    pub name: String,
    pub team: TeamId,
}

pub type TeamId = u64;

#[derive(Debug, PartialEq)]
pub struct Team {
    pub id: TeamId,
    pub name: String,
}

pub async fn get_pool() -> Pool<Sqlite> {
    let path = Path::new("test_db");
    if !path.exists() {
        let _ = fs::create_dir("test_db");
    }

    let id = Uuid::new_v4();
    let file_path = format!("test_db/{}.db", id);

    let pool_opts = SqliteConnectOptions::from_str(&file_path)
        .unwrap()
        .create_if_missing(true);
    let db_pool = SqlitePool::connect_with(pool_opts).await.unwrap();

    let mut conn = db_pool.acquire().await.unwrap();
    let mut tx = conn.begin().await.unwrap();

    let schema_sql = "
        CREATE TABLE teams (
            id INTEGER PRIMARY KEY,
            name TEXT
        );

        CREATE TABLE employees (
            id INTEGER PRIMARY KEY,
            name TEXT,
            team INTEGER,
            FOREIGN KEY (team) REFERENCES teams(id)
        );";
    sqlx::query(schema_sql).execute(&mut *tx).await.unwrap();

    let dummy_data_sql = "
        INSERT INTO
            teams (id, name)
        VALUES
            (1, 'East Coast Team'),
            (2, 'West Coast Team');

        INSERT INTO
            employees (id, name, team)
        VALUES
            (1, 'Boston Alice', 1),
            (2, 'Seattle Bob', 2);
    ";
    sqlx::query(dummy_data_sql)
        .execute(&mut *tx)
        .await
        .unwrap();

    tx.commit().await.unwrap();
    conn.close().await.unwrap();

    db_pool
}

#[tokio::main]
async fn main() -> Result<(), sqlx::Error> {
    let pool = get_pool().await;
    let mut conn = pool.acquire().await?;

    let employee: Employee = query_as(
        "
        SELECT 
            e.id AS id, 
            e.name AS name, 
            t.id AS team_id, 
            t.name AS team_name 
        FROM employees e 
        INNER JOIN teams t ON e.team = t.id 
        WHERE e.id = 1
    ",
    )
    .fetch_one(&mut *conn)
    .await?;

    println!("Employee ID: {}", employee.id);
    println!("Employee Name: {}", employee.name);
    println!("Team ID: {}", employee.team.id);
    println!("Team Name: {}", employee.team.name);

    Ok(())
}

#[cfg(test)]
mod tests {
    use super::*;

    #[tokio::test]
    async fn create_db() {
        let _pool = get_pool().await;
        assert!(true);
    }

    #[tokio::test]
    async fn get_employee_with_team_id() {
        let pool: Pool<Sqlite> = get_pool().await;
        let mut conn = pool.acquire().await.unwrap();

        let employee: EmployeeWithTeamId =
            query_as("SELECT * FROM employees WHERE id = 1")
                .fetch_one(&mut *conn)
                .await
                .unwrap();

        let expected_employee = EmployeeWithTeamId {
            id: 1,
            name: String::from("Boston Alice"),
            team: 1,
        };

        assert_eq!(employee, expected_employee);
    }

    #[tokio::test]
    async fn get_employee() {
        let pool: Pool<Sqlite> = get_pool().await;
        let mut conn = pool.acquire().await.unwrap();

        let employee: Employee = query_as(
            "
            SELECT 
                e.id AS id, 
                e.name AS name, 
                t.id AS team_id, 
                t.name AS team_name 
            FROM employees e 
            INNER JOIN teams t ON e.team = t.id 
            WHERE e.id = 1
        ",
        )
        .fetch_one(&mut *conn)
        .await
        .unwrap();

        let expected_team = Team {
            id: 1,
            name: String::from("East Coast Team"),
        };
        let expected_employee = Employee {
            id: 1,
            name: String::from("Boston Alice"),
            team: expected_team,
        };

        assert_eq!(employee, expected_employee);
    }
}
```

### Explanation
1. **Manual `FromRow` Implementation**: The `Employee` struct manually implements the `FromRow` trait. This allows us to decode a row from a JOIN query into the nested `Employee` and `Team` structs by specifying how each column maps to the struct fields.
2. **JOIN Query**: The SQL query uses a JOIN to combine data from both `employees` and `teams` tables. Column aliases (`team_id` and `team_name`) ensure clear mapping to the nested `Team` struct within `Employee`.
3. **Testing**: The test cases verify both the flat `EmployeeWithTeamId` struct (which only contains the team ID) and the nested `Employee` struct (which contains the full `Team` struct). This ensures that both approaches work as expected.
4. **Main Function**: The `main` function demonstrates fetching an employee with their full team details and printing the results. This serves as a practical example of using the implemented solution.

By using this approach, you can efficiently fetch and store related structs by ID while maintaining clear and maintainable code. The manual `FromRow` implementation provides flexibility to handle complex nested structures not directly supported by SQLx's derive macros.

