use radiate::prelude::*;
use radiate::tree::prelude::*;

struct SqrtPlusOne;

impl Operator for SqrtPlusOne {
    fn run(&self, args: &[f32]) -> f32 {
        if args.is_empty() {
            return f32::NAN;
        }
        (args[0] + 1.0).sqrt()
    }

    fn arity(&self) -> usize { 1 }

    fn symbol(&self) -> String { "sqrt_plus_one".to_string() }

    fn child_symbol(&self) -> Option<String> { None }
}

fn main() {
    // Create training data: f(x) = sqrt(x + 1)
    let training_data: Vec<Vec<f32>> = (0..10)
        .map(|x| vec![x as f32, (x as f32 + 1.0).sqrt()])
        .collect();

    // Set up operator store
    let store = vec![
        (NodeType::Vertex, vec![
            Op::Custom(Box::new(SqrtPlusOne)),
            Op::add(),
            Op::sub(),
            Op::mul()
        ]),
        (NodeType::Leaf, vec![
            Op::var(0),     // Input variable x
            Op::cons(1.0)   // Constant 1.0
        ]),
    ];

    // Create environment
    let environment = TreeEnvironment::new()
        .set_builder(
            TreeBuilder::new()
                .set_max_depth(4)
                .set_store(store)
        );

    // Create problem
    let problem = Regression::new(training_data, data_split_ratio(0.9));

    // Configure evolution
    let evolution_config = EvolutionConfig::new()
        .set_max_stagnation(50)
        .set_fitness_threshold(0.01)
        .set_verbose(true);

    // Create engine
    let mut engine = Engine::new(problem, environment, evolution_config)
        .set_threads(4)
        .set_output();

    // Run evolution
    let solution = engine.evolve();

    println!("Best solution: {}", solution.get_model());
    println!("Fitness: {}", solution.get_fitness());
}
```

