```rust
use std::env;
use std::fs;
use std::io::ErrorKind;
use std::path::Path;

const FILE_PATH: &str = "output.json";

fn load_todos() -> Vec<String> {
    if !Path::new(FILE_PATH).exists() {
        return Vec::new();
    }

    let data = fs::read_to_string(FILE_PATH).expect("Failed to read file");
    if data.trim().is_empty() {
        Vec::new()
    } else {
        serde_json::from_str(&data).expect("Failed to parse JSON")
    }
}

fn save_todos(todos: &[String]) {
    let json = serde_json::to_string_pretty(todos).expect("Failed to serialize todos");
    fs::write(FILE_PATH, json).expect("Failed to write file");
}

fn main() {
    let args: Vec<String> = env::args().skip(1).collect();

    if args.is_empty() {
        eprintln!("Error: No todo items provided");
        eprintln!("Usage: cargo run -- <todo1> [todo2 ...]");
        std::process::exit(1);
    }

    let mut todos = load_todos();
    todos.extend(args);
    save_todos(&todos);

    println!("Successfully added {} todos", todos.len());
}
