#[macro_use] extern crate rocket;

use rocket::ws::{WebSocket, Channel, Message};
use rocket::futures::{SinkExt, StreamExt};

// WebSocket route that echoes received messages
#[get("/ws")]
fn websocket(ws: WebSocket) -> Channel<'_> {
    ws.channel(|mut stream| Box::pin(async move {
        while let Some(msg) = stream.next().await {
            match msg {
                Ok(msg) => {
                    if let Err(_) = stream.send(msg).await {
                        break;
                    }
                }
                Err(_) => break,
            }
        }
    }))
}

#[launch]
fn rocket() -> _ {
    rocket::build().mount("/", routes![websocket])
}

#[cfg(test)]
mod tests {
    use super::rocket;
    use rocket::local::asynchronous::Client;
    use rocket::ws::Message;
    use rocket::futures::{SinkExt, StreamExt};

    #[tokio::test]
    async fn test_websocket_echo() {
        // Set up test client
        let client = Client::tracked(rocket()).await.expect("Rocket client");
        let mut ws = client.ws("/ws").await.expect("WebSocket connection");

        // Send a message and verify echo
        ws.send(Message::Text("Hello Rocket!".into())).await.expect("Message send");
        let msg = ws.next().await.expect("Message stream").expect("Valid message");
        assert_eq!(msg, Message::Text("Hello Rocket!".into()));

        // Send another message
        ws.send(Message::Text("Close please!".into())).await.expect("Message send");
        let msg = ws.next().await.expect("Message stream").expect("Valid message");
        assert_eq!(msg, Message::Text("Close please!".into()));
    }
}
```

