Here's a self-contained Rust project demonstrating nested custom deserialization with serde:

**Cargo.toml**
```toml
[package]
name = "nested_serializers"
version = "0.1.0"
edition = "2021"

[dependencies]
serde = { version = "1.0", features = ["derive"] }
serde_json = "1.0"
```

**main.rs**
```rust
use serde::de::{Deserialize, Deserializer, MapAccess, SeqAccess, Visitor};
use serde::ser::{Serialize, SerializeStruct, Serializer};
use std::fmt;

#[derive(Debug, Default, PartialEq)]
struct A {
    x: usize,
    b: Vec<B>,
}

#[derive(Debug, PartialEq)]
enum B {
    StringData(String),
    IntData(i32),
}

// Serialization for A
impl Serialize for A {
    fn serialize<S>(&self, serializer: S) -> Result<S::Ok, S::Error>
    where
        S: Serializer,
    {
        let mut s = serializer.serialize_struct("A", 2)?;
        s.serialize_field("x", &self.x)?;
        s.serialize_field("b", &self.b)?;
        s.end()
    }
}

// Serialization for B
impl Serialize for B {
    fn serialize<S>(&self, serializer: S) -> Result<S::Ok, S::Error>
    where
        S: Serializer,
    {
        match self {
            B::StringData(s) => serializer.serialize_str(s),
            B::IntData(i) => serializer.serialize_i32(*i),
        }
    }
}

// Deserialization for A
impl<'de> Deserialize<'de> for A {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        struct AVisitor;

        impl<'de> Visitor<'de> for AVisitor {
            type Value = A;

            fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
                formatter.write_str("struct A")
            }

            fn visit_map<V>(self, mut map: V) -> Result<A, V::Error>
            where
                V: MapAccess<'de>,
            {
                let mut x = None;
                let mut b = None;

                while let Some(key) = map.next_key::<&str>()? {
                    match key {
                        "x" => {
                            if x.is_some() {
                                return Err(serde::de::Error::duplicate_field("x"));
                            }
                            x = Some(map.next_value()?);
                        }
                        "b" => {
                            if b.is_some() {
                                return Err(serde::de::Error::duplicate_field("b"));
                            }
                            b = Some(map.next_value()?);
                        }
                        _ => {
                            return Err(serde::de::Error::unknown_field(
                                key,
                                &["x", "b"],
                            ));
                        }
                    }
                }

                let x = x.ok_or_else(|| serde::de::Error::missing_field("x"))?;
                let b = b.ok_or_else(|| serde::de::Error::missing_field("b"))?;

                Ok(A { x, b })
            }
        }

        deserializer.deserialize_map(AVisitor)
    }
}

// Deserialization for B
impl<'de> Deserialize<'de> for B {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        struct BVisitor;

        impl<'de> Visitor<'de> for BVisitor {
            type Value = B;

            fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
                formatter.write_str("string or integer")
            }

            fn visit_str<E>(self, value: &str) -> Result<Self::Value, E>
            where
                E: serde::de::Error,
            {
                Ok(B::StringData(value.to_owned()))
            }

            fn visit_i32<E>(self, value: i32) -> Result<Self::Value, E>
            where
                E: serde::de::Error,
            {
                Ok(B::IntData(value))
            }

            fn visit_i64<E>(self, value: i64) -> Result<Self::Value, E>
            where
                E: serde::de::Error,
            {
                if value >= i64::from(i32::MIN) && value <= i64::from(i32::MAX) {
                    Ok(B::IntData(value as i32))
                } else {
                    Err(E::custom(format!("i32 out of range: {}", value)))
                }
            }

            fn visit_u64<E>(self, value: u64) -> Result<Self::Value, E>
            where
                E: serde::de::Error,
            {
                if value <= i32::MAX as u64 {
                    Ok(B::IntData(value as i32))
                } else {
                    Err(E::custom(format!("i32 out of range: {}", value)))
                }
            }
        }

        deserializer.deserialize_any(BVisitor)
    }
}

fn main() {
    let data = r#"
        {
            "x": 42,
            "b": ["hello", 100, "world", -200]
        }
    "#;

    let a: A = serde_json::from_str(data).expect("Failed to deserialize");
    println!("Deserialized: {:?}", a);

    // Test serialization roundtrip
    let serialized = serde_json::to_string_pretty(&a).unwrap();
    println!("Serialized:\n{}", serialized);
}
```

This implementation:

1. Defines struct `A` and enum `B` with custom serialization/deserialization
2. Handles nested deserialization through:
   - `AVisitor` for the top-level struct
   - `BVisitor` for the nested enum values
3. Supports both string and integer variants for `B`
4. Includes proper error handling for:
   - Duplicate fields
   - Missing fields
   - Unknown fields
   - Integer range checks
5. Demonstrates round-trip serialization/deserialization

