use async_trait::async_trait;
use opentelemetry::global;
use std::time::Duration;
use tokio::time::sleep;
use tracing::{info, info_span, Instrument, Span};
use tracing_subscriber::{layer::SubscriberExt, Registry};

// Context containing parent span and OpenTelemetry context
#[derive(Clone)]
struct RequestContext {
    parent_span: Span,
    otel_ctx: opentelemetry::Context,
}

// Handler trait representing different processing stages
#[async_trait]
trait StageHandler {
    async fn stage1(&self, ctx: &RequestContext);
    async fn stage2(&self, ctx: &RequestContext);
    async fn upstream(&self, ctx: &RequestContext);
}

// Implementation of handler
struct HandlerImpl;

#[async_trait]
impl StageHandler for HandlerImpl {
    async fn stage1(&self, ctx: &RequestContext) {
        // Create child span using explicit parent relationship
        let stage_span = info_span!(parent: &ctx.parent_span, "stage1");

        async {
            info!("Executing stage1");
            sleep(Duration::from_millis(10)).await;
            info!("Stage1 completed");
        }
        .instrument(stage_span)
        .await
    }

    async fn stage2(&self, ctx: &RequestContext) {
        // Alternative method: Rehydrate OpenTelemetry context
        let _guard = ctx.otel_ctx.clone().attach();
        let stage_span = info_span!("stage2");

        async {
            info!("Executing stage2");
            sleep(Duration::from_millis(15)).await;
            info!("Stage2 completed");
        }
        .instrument(stage_span)
        .await
    }

    async fn upstream(&self, ctx: &RequestContext) {
        // Combined approach for maximum reliability
        let _guard = ctx.otel_ctx.clone().attach();
        let stage_span = info_span!(parent: &ctx.parent_span, "upstream");

        async {
            info!("Contacting upstream");
            sleep(Duration::from_millis(20)).await;
            info!("Upstream response received");
        }
        .instrument(stage_span)
        .await
    }
}

#[tokio::main]
async fn main() {
