mod queue_handler {
    #[derive(Debug)]
    pub struct Handle;

    impl Handle {
        pub fn new() -> std::io::Result<Self> {
            Ok(Handle)
        }
    }
}

#[actix_web::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    println!("Starting the application.");

    let (actix_server, server_handle) = api::server::create_server()?;

    println!("Starting queue handler...");
    let queue_handle = queue_handler::Handle::new()?;

    let cancel_token = CancellationToken::new();
    let queue_cancel_token = cancel_token.clone();

    // Spawn the Actix server as a task
    let server_task = tokio::spawn(actix_server);

    // Spawn the queue handler as a task that can be cancelled
    let queue_task = tokio::spawn(async move {
        // This is a mock queue handler that runs until cancelled
        while !queue_cancel_token.is_cancelled() {
            tokio::time::sleep(tokio::time::Duration::from_secs(1)).await;
            println!("Queue handler working...");
        }
        println!("Queue handler shutting down gracefully...");
    });

    // Wait for the ctrl_c signal
    tokio::signal::ctrl_c().await?;
    println!("Ctrl+C received, shutting down");

    // Trigger shutdown: first the queue handler, then the server
    cancel_token.cancel();
    server_handle.stop(true).await;

    // Wait for the tasks to finish
    server_task.await?;
    queue_task.await?;

    println!("Shutdown complete");
    Ok(())
}
```

### Explanation:
1. **Cancellation Token**: The `CancellationToken` is used to signal the queue handler to stop gracefully.
2. **Task Spawning**: Both the server and queue handler are spawned as separate tasks, allowing them to run concurrently.
3. **Graceful Shutdown**:
   - On Ctrl+C, the cancellation token is triggered, causing the queue handler to exit its loop.
   - The Actix server is stopped gracefully with `server_handle.stop(true).await`, which waits for pending requests to complete.
4. **Task Completion**: The main function waits for both tasks to finish before exiting, ensuring no background processes remain.

This approach ensures both components shut down gracefully when Ctrl+C is pressed, with all pending work completed before the program exits.

