) -> Result<Vec<String>, Box<dyn std::error::Error>> {
    let mut blob_names = Vec::new();
    let mut stream = container_client
        .list_blobs()
        .prefix(prefix)
        .into_stream();

    while let Some(response) = stream.next().await {
        let response = response?;
        for blob in response.blobs.blobs() {
            if blob.name.ends_with(".json") {
                blob_names.push(blob.name.clone());
            }
        }
    }

    Ok(blob_names)
}

async fn download_blobs(
    container_client: &ContainerClient,
    blob_names: Vec<String>,
) -> Result<Vec<TradeData>, Box<dyn std::error::Error>> {
    let start = Instant::now();
    let concurrency = std::thread::available_parallelism()?.get() * 4;
    tracing::info!("Downloading {} blobs with concurrency: {}", blob_names.len(), concurrency);

    let tasks = futures::stream::iter(blob_names)
        .map(|blob_name| {
            let client = container_client.clone();
            async move {
                let blob_client = client.blob_client(&blob_name);
                let data = blob_client.get_content().await?;
                let trade: TradeData = serde_json::from_slice(&data)
                    .map_err(|e| format!("JSON parse error in {}: {}", blob_name, e))?;
                Ok::<_, Box<dyn std::error::Error>>(trade)
            }
        })
        .buffer_unordered(concurrency);

    let results: Vec<Result<TradeData, _>> = tasks.collect().await;

    tracing::info!(
        "Downloaded {} blobs in {:.2}s",
        results.len(),
        start.elapsed().as_secs_f32()
    );

    // Handle errors and filter out failures
    let mut trades = Vec::new();
    let mut errors = 0;

    for result in results {
        match result {
            Ok(trade) => trades.push(trade),
            Err(e) => {
                tracing::error!("{}", e);
                errors += 1;
            }
        }
    }

    if errors > 0 {
        tracing::warn!("Failed to process {} blobs", errors);
    }

    Ok(trades)
}"
}
