    Mul,
    Div,
}

#[derive(Debug)]
pub enum Expr {
    Int(i32),
    Binary {
        left: Box<Expr>,
        op: BinOp,
        right: Box<Expr>,
    },
}

fn parse_mul_op<'a>() -> impl Parser<'a, &'a str, BinOp> {
    just('*')
        .to(BinOp::Mul)
        .or(just('/').to(BinOp::Div))
}

fn parse_primary<'a>() -> impl Parser<'a, &'a str, Expr> {
    text::int(10).map(|s: &str| Expr::Int(s.parse().unwrap()))
}

fn parse_mul_div<'a>() -> impl Parser<'a, &'a str, Expr> {
    parse_primary().foldl(
        parse_mul_op()
            .then(parse_primary())
            .repeated(),
        |lhs, (op, rhs)| Expr::Binary {
            left: Box::new(lhs),
            op,
            right: Box::new(rhs),
        },
    )
}

fn main() {
    let parser = parse_mul_div();
    let result = parser.parse("1*2*3");
    println!("{:?}", result);
}
```

**Explanation:**
- The `foldl` method handles left-associative parsing automatically
- It processes the initial expression followed by repeated (operator, expression) pairs
- For each pair, it builds a binary expression using the operator
- The closure provides clear type context to the compiler
- This approach is more efficient and idiomatic for Chumsky parsers

