### main.rs
```rust
use futures::StreamExt;
use tokio::{
    signal,
    sync::broadcast::{channel, error::RecvError, Sender},
};
use tokio_stream::wrappers::BroadcastStream;

// Event type for demonstration
#[derive(Debug, Clone)]
pub struct Event(String);

// Channel abstractions
pub fn events_channel() -> (EventSender, EventStreamFactory) {
    let (tx, _) = channel(20);
    (EventSender { tx: tx.clone() }, EventStreamFactory { tx })
}

#[derive(Debug, Clone)]
pub struct EventSender {
    tx: Sender<Event>,
}

impl EventSender {
    pub fn send(&self, event: Event) {
        let _ = self.tx.send(event);
    }
}

#[derive(Debug, Clone)]
pub struct EventStreamFactory {
    tx: Sender<Event>,
}

impl EventStreamFactory {
    pub fn all_events(&self) -> impl futures::Stream<Item = Result<Event, RecvError>> + Send {
        BroadcastStream::new(self.tx.subscribe()).filter_map(|event| match event {
            Ok(event) => Some(Ok(event)),
            Err(_) => Some(Err(RecvError)),
        })
    }
}

#[tokio::main]
async fn main() -> anyhow::Result<()> {
    // Create shutdown channel
    let (shutdown_tx, _) = channel(1);
    // Create event channel
    let (event_sender, event_factory) = events_channel();

    // Spawn event listeners
    let mut join_set = tokio::task::JoinSet::new();
    for i in 0..3 {
        let mut shutdown_rx = shutdown_tx.subscribe();
        let event_stream = event_factory.all_events();

        join_set.spawn(async move {
            let mut event_stream = Box::pin(event_stream);
            println!("Listener {} started", i);

            loop {
                tokio::select! {
                    // Listen for shutdown signal
                    _ = shutdown_rx.recv() => {
                        println!("Listener {} received shutdown", i);
                        break;
                    }
                    // Process events
                    event = event_stream.next() => {
                        match event {
                            Some(Ok(e)) => println!("Listener {} received: {:?}", i, e),
                            Some(Err(_)) => eprintln!("Listener {}: channel closed", i),
                            None => break,
                        }
                    }
                }
            }
            println!("Listener {} exiting", i);
        });
    }

    // Spawn event producer
    let producer_shutdown = shutdown_tx.subscribe();
    let event_sender_clone = event_sender.clone();
    join_set.spawn(async move {
        let mut interval = tokio::time::interval(std::time::Duration::from_secs(1));
        let mut count = 0;

        loop {
            tokio::select! {
                _ = interval.tick() => {
                    event_sender_clone.send(Event(format!("Event {}", count)));
                    count += 1;
                }
                _ = producer_shutdown.recv() => {
                    println!("Producer received shutdown");
                    break;
                }
            }
        }
        println!("Producer exiting");
    });

    // Wait for Ctrl-C
    signal::ctrl_c().await?;
    println!("\nCtrl-C received. Shutting down...");

    // Send shutdown signal to all tasks
    let _ = shutdown_tx.send(());

    // Drop main sender to prevent new events
    drop(event_sender);
    drop(event_factory);

    // Wait for all tasks to complete
    while let Some(res) = join_set.join_next().await {
        res?;
    }

    println!("All tasks exited cleanly");
    Ok(())
}
```

### Key Features:

1. **Shutdown Mechanism**:
   - Uses a broadcast channel to notify all tasks of shutdown
   - `tokio::select!` in tasks handles both events and shutdown signals

2. **Graceful Exit**:
   - Tasks break out of loops when shutdown signal is received
   - Explicit `drop()` of main event sender to prevent new events
   - `JoinSet` waits for all tasks to complete before exit

3. **Resource Cleanup**:
   - All broadcast receivers are closed when tasks exit
   - Event producer stops generating new events on shutdown

4. **Output**:
   - Shows listener/producer startup
   - Prints received events
   - Shows clean exit sequence when Ctrl-C pressed

To test:
1. Create new Rust project: `cargo new broadcast_example`
2. Replace `Cargo.toml` and `src/main.rs` with above contents
3. Run: `cargo run`
4. Press Ctrl-C to trigger shutdown

You'll see:
- Events being generated every second
- Listeners processing events
- Clean shutdown sequence when Ctrl-C pressed
- All tasks exiting gracefully before program termination

