async fn get_oauth_token(
    tenant_id: &str,
    client_id: &str,
    client_secret: &str,
) -> Result<String, Box<dyn std::error::Error>> {
    let token_url = format!("https://login.microsoftonline.com/{}/oauth2/v2.0/token", tenant_id);
    let client = reqwest::Client::new();
    let params = TokenRequest {
        grant_type: "client_credentials",
        client_id,
        client_secret,
        scope: "https://storage.azure.com/.default",
    };

    let response = client
        .post(&token_url)
        .form(&params)
        .send()
        .await?
        .error_for_status()?;

    let token_res = response.json::<TokenResponse>().await?;
    Ok(token_res.access_token)
}

async fn list_blob_names(
    container_client: &ContainerClient,
    prefixes: &[String],
) -> Result<Vec<String>, Box<dyn std::error::Error>> {
    let mut tasks = vec![];

    for prefix in prefixes {
        let mut stream = container_client
            .list_blobs()
            .prefix(prefix)
            .include_metadata(false)
            .into_stream();

        while let Some(page) = stream.next().await {
            let page = page?;
            tasks.extend(
                page.blobs
                    .blobs()
                    .filter(|b| b.name.ends_with(".json"))
                    .map(|b| b.name.clone()),
            );
        }
    }

    Ok(tasks)
}

async fn download_and_parse_blobs(
    container_client: &ContainerClient,
    blob_names: Vec<String>,
) -> Result<Vec<TradeData>, Box<dyn std::error::Error>> {
    let client = Arc::new(container_client.clone());
    let num_cpus = num_cpus::get();
    let semaphore = Arc::new(Semaphore::new(num_cpus * 2));
    let mut tasks = Vec::with_capacity(blob_names.len());

    for blob_name in blob_names {
        let client = Arc::clone(&client);
        let permit = Arc::clone(&semaphore).acquire_owned().await?;

        tasks.push(tokio::spawn(async move {
            let _permit = permit; // Held for duration of task
            match download_and_parse_blob(&client, &blob_name).await {
                Ok(trade) => Some(trade),
                Err(e) => {
                    eprintln!("Error processing {}: {}", blob_name, e);
                    None
                }
            }
        }));
    }

    let mut trades = Vec::new();
    for task in tasks {
        if let Some(trade) = task.await? {
            trades.push(trade);
        }
    }

    Ok(trades)
}

async fn download_and_parse_blob(
    container_client: &ContainerClient,
    blob_name: &str,
) -> Result<TradeData, Box<dyn std::error::Error>> {
    let blob_client = container_client.blob_client(blob_name);
    let data = blob_client.get_content().await?;
    let trade = serde_json::from_slice(&data)?;
    Ok(trade)
}
```

