use std::collections::HashMap;
use std::error::Error;

use zbus::Connection;
use zvariant::to_value;

const NETCONFIG_SERVICE: &str = "com.example.NetConfig";
const NETCONFIG_PATH: &str = "/com/example/NetConfig";
const NETCONFIG_OBJECT: &str = "com.example.Netconfig";
const NETCONFIG_METHOD: &str = "SetInterfaceIP";

const NOTIFICATIONS_SERVICE: &str = "org.freedesktop.Notifications";
const NOTIFICATIONS_PATH: &str = "/org/freedesktop/Notifications";
const NOTIFICATIONS_OBJECT: &str = "org.freedesktop.Notifications";
const NOTIFICATIONS_METHOD: &str = "Notify";

#[tokio::main]
async fn main() -> Result<(), Box<dyn Error>> {
    let connection = Connection::session().await?;

    // Set condition to choose between method calls
    let condition = true;

    let (service, path, object, method, args_value) = if condition {
        // Build arguments for Notifications.Notify
        let args_tuple = (
            "my-app".to_string(),     // app_name
            0u32,                     // replaces_id
            "dialog-information".to_string(), // app_icon
            "A summary".to_string(),  // summary
            "Some body".to_string(),  // body
            vec!["".to_string(); 0],  // actions
            HashMap::<String, zvariant::Value>::new(), // hints
            5000,                     // timeout
        );
        let args_value = to_value(&args_tuple)?;
        (
            NOTIFICATIONS_SERVICE,
            NOTIFICATIONS_PATH,
            NOTIFICATIONS_OBJECT,
            NOTIFICATIONS_METHOD,
            args_value,
        )
    } else {
        // Build arguments for NetConfig.SetInterfaceIP
        let args_tuple = (
            "enxc0470e9a117".to_string(),  // interface
            "192.168.1.141".to_string(),   // ip
        );
        let args_value = to_value(&args_tuple)?;
        (
            NETCONFIG_SERVICE,
            NETCONFIG_PATH,
            NETCONFIG_OBJECT,
            NETCONFIG_METHOD,
            args_value,
        )
    };

    // Make D-Bus method call
    let m = connection
        .call_method(Some(service), path, Some(object), method, &args_value)
        .await?;

    // Deserialize and process reply
    let reply: u32 = m.body().deserialize()?;
    dbg!(reply);

    Ok(())
}
```

### Key Changes:
1. **Tuple-based Arguments:** Uses tuples directly instead of structs to represent method parameters
2. **Value Conversion:** Converts tuples to `zvariant::Value` using `to_value()` for serialization
3. **Owned Data:** Uses `String` and `HashMap<String, Value>` instead of references for lifetime safety
4. **Condition Handling:** Branches logic based on runtime condition to choose between:
   - Notification service call (when `condition = true`)
   - NetConfig service call (when `condition = false`)
5. **Error Handling:** Propagates errors using `?` operator

This approach handles both the complex `HashMap` with `Value` elements and the dynamic method selection while maintaining compatibility with zbus's type requirements.

