pub static ZOBRIST_SEEDS: [u64; 781] = generate_zobrist_seeds();

const SEED: u64 = 4174800045971885562;

const fn generate_zobrist_seeds() -> [u64; 781] {
    let mut result = [0; 781];
    let mut state = SEED;
    let mut i = 0;

    while i < 781 {
        let (new_state, rand_val) = next_splitmix64(state);
        result[i] = rand_val;
        state = new_state;
        i += 1;
    }

    result
}

const fn next_splitmix64(state: u64) -> (u64, u64) {
    let new_state = state.wrapping_add(0x9E3779B97F4A7C15);
    let mut z = new_state;
    z = (z ^ (z >> 30)).wrapping_mul(0xBF58476D1CE4E5B9);
    z = (z ^ (z >> 27)).wrapping_mul(0x94D049BB133111EB);
    (new_state, z ^ (z >> 31))
}

