use num_traits::Float;
use std::ops::Add;

pub trait Processor {
    type Input: Copy;
    type Output;

    fn prepare(&mut self, rate: f64);
    fn process(&mut self, input: Self::Input) -> Self::Output;
}

pub trait Sample: Copy + Clone + Add<Self, Output = Self> {
    type Float: Float;

    const CHANNELS: usize;

    fn mono(&self) -> Self::Float;
    fn gain(&self, db: Self::Float) -> Self;
}

#[derive(Copy, Clone)]
pub struct Node<P>(pub P);

impl<In: Copy, Out, P> Processor for Node<P>
where
    P: Processor<Input = In, Output = Out>,
{
    type Input = In;
    type Output = Out;

    fn prepare(&mut self, _rate: f64) {}
    fn process(&mut self, input: Self::Input) -> Self::Output {
        self.0.process(input)
    }
}

pub struct Gain<F: Float>(pub F);

impl<F: Float> Processor for Gain<F> {
    type Input = F;
    type Output = F;

    fn prepare(&mut self, _rate: f64) {}
    fn process(&mut self, input: Self::Input) -> Self::Output {
        self.0 * input
    }
}

pub fn gain_node<F: Float>(db: F) -> Node<Gain<F>> {
    Node(Gain(db))
}

impl Sample for f32 {
    type Float = Self;
    const CHANNELS: usize = 1;

    fn mono(&self) -> Self::Float {
        *self
    }

    fn gain(&self, db: Self::Float) -> Self {
        *self * db.exp2()
    }
}

impl Sample for f64 {
    type Float = Self;
    const CHANNELS: usize = 1;

    fn mono(&self) -> Self::Float {
        *self
    }

    fn gain(&self, db: Self::Float) -> Self {
        *self * db.exp2()
    }
}

fn main() {
    println!("Run `cargo test` to execute the tests");
}

#[cfg(test)]
