use smb::{Directory, FileAccessMask};
use std::sync::Arc;
use futures::stream::StreamExt;

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    let args: Vec<String> = std::env::args().collect();
    if args.len() != 4 {
        eprintln!("Usage: {} <url> <username> <password>", args[0]);
        std::process::exit(1);
    }
    let url = &args[1];
    let username = &args[2];
    let password = &args[3];

    let options = smb::SmbOptions::default()
        .url(url)?
        .username(username)?
        .password(password)?
        .connect()
        .await?;

    let tree = Arc::new(options.into_tree().await?);
    list_dir_recursive(&tree, "").await?;

    Ok(())
}

async fn list_dir_recursive(
    tree: &Arc<smb::Tree>,
    path: &str,
) -> Result<(), Box<dyn std::error::Error>> {
    let resource = tree
        .open_existing(path, FileAccessMask::FILE_LIST_DIRECTORY)
        .await?;
    let dir: Directory = resource.try_into()?;

    let mut stream = dir.query("*").await?;
    while let Some(entry) = stream.next().await {
        let entry = entry?;
        let name = entry.file_name();
        let full_path = if path.is_empty() {
            name.to_string()
        } else {
            format!("{}\\{}", path, name)
        };

        println!("{}", full_path);

        if entry.is_directory() && name != "." && name != ".." {
            list_dir_recursive(tree, &full_path).await?;
        }
    }
    Ok(())
}
```

