use std::io::{BufRead, BufReader, Write};
use std::process::{Command, Stdio};
use std::sync::mpsc::{self, Receiver, Sender, TryRecvError};
use std::thread;

use rustyline::error::ReadlineError;
use rustyline::AsyncEvent;
use rustyline::async::{AsyncReader, AsyncReaderResult};
use rustyline::Editor;

struct EventAsyncReader(Receiver<()>);

impl AsyncReader for EventAsyncReader {
    fn next_event(&mut self) -> AsyncReaderResult {
        match self.0.try_recv() {
            Ok(()) => Ok(AsyncEvent::Interrupt),
            Err(TryRecvError::Empty) => Ok(AsyncEvent::Readline),
            Err(TryRecvError::Disconnected) => Ok(AsyncEvent::Eof),
        }
    }
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let mut child = Command::new("bash")
        .arg("-i")
        .stdin(Stdio::piped())
        .stdout(Stdio::piped())
        .stderr(Stdio::piped())
        .spawn()?;

    let (line_tx, line_rx) = mpsc::channel::<String>();
    let (event_tx, event_rx) = mpsc::channel::<()>();

    let stdout = child.stdout.take().unwrap();
    let stderr = child.stderr.take().unwrap();

    // Spawn threads to read stdout and stderr
    let tx_out = line_tx.clone();
    let tx_ev_out = event_tx.clone();
    thread::spawn(move || {
        let reader = BufReader::new(stdout);
        for line in reader.lines() {
            let line = line.unwrap();
            if tx_out.send(line.clone()).is_err() || tx_ev_out.send(()).is_err() {
                break;
            }
        }
    });

    let tx_err = line_tx.clone();
    let tx_ev_err = event_tx.clone();
    thread::spawn(move || {
        let reader = BufReader::new(stderr);
        for line in reader.lines() {
            let line = line.unwrap();
            if tx_err.send(line.clone()).is_err() || tx_ev_err.send(()).is_err() {
                break;
            }
        }
    });

    let mut rl = Editor::<()>::new()?;
    let mut async_reader = EventAsyncReader(event_rx);

    loop {
        // Print all pending output first
        while let Ok(line) = line_rx.try_recv() {
            println!("{}", line);
        }

        // Read user input with async support
        let readline = rl.readline_with("> ", &mut async_reader);
        match readline {
            Ok(line) => {
                if let Some(stdin) = child.stdin.as_mut() {
                    writeln!(stdin, "{}", line)?;
                }
            }
            Err(ReadlineError::Interrupted) => {
                continue; // Re-prompt on interrupt
            }
            Err(ReadlineError::Eof) => break, // Exit on Ctrl-D
            Err(err) => {
                eprintln!("Error: {:?}", err);
                break;
            }
        }
    }

    // Cleanup: Wait for child to exit
    if let Ok(Some(status)) = child.try_wait() {
        println!("Child exited with: {}", status);
    } else {
        let _ = child.kill();
        child.wait()?;
    }

    Ok(())
}
```

### Explanation
1. **Child Process Setup**: The child process (e.g., `bash -i`) is spawned with piped standard streams to capture input and output.
2. **Output Threads**: Separate threads read the child's stdout and stderr. Each line of output is sent to a channel (`line_tx`) and triggers an event (`event_tx`) to notify the main thread.
3. **Async Reader**: The custom `EventAsyncReader` checks for output events. If output is available, it interrupts the `readline` call, allowing the main thread to process pending output.
4. **Main Loop**:
   - **Output Handling**: Before each `readline` call, any pending output from the child is printed.
   - **User Input**: The `readline_with` function integrates the async reader, enabling prompt refreshes on output.
   - **Input Handling**: User input is sent to the child's stdin. If the child exits, the loop terminates gracefully.

This solution ensures the child's output is displayed immediately, providing a seamless user experience while maintaining interactive input capabilities.

