use std::io;
use std::sync::mpsc::{self, Sender};
use std::sync::{Arc, atomic::{AtomicBool, Ordering}};
use std::thread;
use std::time::Duration;

use signal_hook::consts::signal::*;
use signal_hook::iterator::Signals;
use termion::event::{Event, Key};
use termion::input::{TermRead, AsyncReader};
use termion::raw::IntoRawMode;

enum Message {
    Key(char),
    Signal(i32),
}

fn yield_signals(sender: Sender<Message>, stop_flag: Arc<AtomicBool>) {
    let mut signals = Signals::new(&[SIGINT, SIGTERM]).unwrap();
    loop {
        for signal in signals.pending() {
            if sender.send(Message::Signal(signal)).is_err() {
                return;
            }
        }
        if stop_flag.load(Ordering::Relaxed) {
            break;
        }
        thread::sleep(Duration::from_millis(100));
    }
}

fn yield_keys(sender: Sender<Message>, stop_flag: Arc<AtomicBool>) {
    let _stdout = io::stdout().into_raw_mode().unwrap();
    let stdin: AsyncReader = termion::async_stdin();
    let mut events = stdin.events();

    loop {
        if let Some(event) = events.next() {
            match event {
                Ok(Event::Key(Key::Char(key))) => {
                    if sender.send(Message::Key(key)).is_err() {
                        return;
                    }
                }
                _ => {}
            }
        }
        if stop_flag.load(Ordering::Relaxed) {
            break;
        }
        thread::sleep(Duration::from_millis(100));
    }
}

fn main() {
    let stop_flag = Arc::new(AtomicBool::new(false));
    let (sender, receiver) = mpsc::channel();

    let stop_flag1 = stop_flag.clone();
    let sender1 = sender.clone();
    let signal_handle = thread::spawn(move || {
        yield_signals(sender1, stop_flag1);
    });

    let stop_flag2 = stop_flag.clone();
    let sender2 = sender.clone();
    let key_handle = thread::spawn(move || {
        yield_keys(sender2, stop_flag2);
    });

    for msg in receiver {
        match msg {
            Message::Key('q') => {
                println!("Quitting due to 'q' press");
                break;
            }
            Message::Signal(sig) => {
                println!("Received signal: {}", sig);
                if sig == SIGINT || sig == SIGTERM {
                    println!("Quitting due to signal");
                    break;
                }
            }
            Message::Key(c) => {
                println!("Key pressed: {}", c);
            }
        }
    }

    stop_flag.store(true, Ordering::Relaxed);
    signal_handle.join().unwrap();
    key_handle.join().unwrap();
}
```

### Explanation

1. **Atomic Stop Flag**: An `Arc<AtomicBool>` is used to signal threads to stop. This flag is shared across all threads.
2. **Non-blocking I/O**: 
   - **Signal Thread**: Uses `Signals::pending()` to check for signals without blocking, then sleeps briefly to avoid high CPU usage.
   - **Key Thread**: Uses `termion::async_stdin()` for non-blocking input, checking for key events without blocking.
3. **Periodic Checking**: Each thread checks the stop flag every 100ms. If set, the thread breaks its loop and terminates.
4. **Main Loop**: The main thread processes messages. On receiving 'q' or a termination signal (SIGINT/SIGTERM), it sets the stop flag and waits for all threads to join.
5. **Clean Termination**: Threads restore terminal settings when exiting (via `RawTerminal` drop), ensuring no resource leaks.

This approach ensures threads terminate promptly when requested, without being blocked indefinitely on I/O operations.

