use rxrust::prelude::*;
use std::convert::Infallible;

type Type = LocalBoxedObservableClone<'static, bool, Infallible>;

fn flipflop(s: Type, r: Type) -> (Type, Type) {
    let initial_state = (true, false); // Initial stable state (set)

    let state = s
        .combine_latest(r)
        .scan(initial_state, |state, (s_val, r_val)| {
            let (q1_prev, q2_prev) = *state;

            // Compute next state based on state table
            let (q1_next, q2_next) = match (s_val, r_val) {
                (false, false) => (true, true), // Invalid state
                (false, true) => (true, false), // Set state
                (true, false) => (false, true), // Reset state
                (true, true) => (q1_prev, q2_prev), // Hold state
            };

            // Log NAND gate operations (using previous state values)
            println!(
                "nand s ({}, {}) = {}",
                s_val,
                q2_prev,
                if s_val { !q2_prev } else { true }
            );
            println!(
                "nand r ({}, {}) = {}",
                r_val,
                q1_prev,
                if r_val { !q1_prev } else { true }
            );

            (q1_next, q2_next)
        })
        .box_it_clone();

    // Split state into individual outputs
    let q1 = state.clone().map(|(q1, _)| q1).box_it_clone();
    let q2 = state.map(|(_, q2)| q2).box_it_clone();

    (q1, q2)
}

fn main() {
    let mut s = Local::behavior_subject::<bool, Infallible>(true);
    let mut r = Local::behavior_subject::<bool, Infallible>(true);

    let (q1, q2) = flipflop(s.clone().box_it_clone(), r.clone().box_it_clone());

    // Subscribe to output changes
    q1.clone()
        .combine_latest(q2.clone(), |q1_val, q2_val| (q1_val, q2_val))
        .subscribe(|(q1, q2)| println!("Output: ({}, {})", q1, q2));

    println!("Initial state (true, true) -> hold");
    println!("Setting s to false (set operation)");
    s.next(false);

    println!("Setting s to true (hold)");
    s.next(true);

    println!("Setting r to false (reset operation)");
    r.next(false);

    println!("Setting r to true (hold)");
    r.next(true);
}
```

**Explanation:**
1. **State Management:** Uses `scan` to maintain flip-flop state as a tuple `(q1, q2)`.
