Here's a self-contained solution using a custom derive macro. The implementation handles the Notion API property conversion with attributes:

Cargo.toml:
```toml
[package]
name = "notion_api_converter"
version = "0.1.0"
edition = "2021"

[dependencies]
serde = { version = "1.0", features = ["derive"] }
serde_json = "1.0"
syn = { version = "2.0", features = ["full", "extra-traits"] }
quote = "1.0"
proc-macro2 = "1.0"
```

main.rs:
```rust
use std::collections::HashMap;
use serde::{Serialize, Deserialize};

#[derive(Serialize, Deserialize, Debug)]
#[serde(tag = "type", rename_all = "snake_case")]
pub enum PropertyValue {
    Title { title: Vec<RichTextObject> },
    Url { url: Option<String> },
    MultiSelect { multi_select: Vec<SelectObject> },
}

#[derive(Serialize, Deserialize, Debug)]
pub struct RichTextObject {
    #[serde(skip_serializing_if = "Option::is_none")]
    pub annotations: Option<()>,
    #[serde(rename = "type")]
    pub data_type: String,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub equation: Option<()>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub mention: Option<()>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub plain_text: Option<()>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub href: Option<()>,
    pub text: TextObject,
}

#[derive(Serialize, Deserialize, Debug)]
pub struct TextObject {
    pub content: String,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub link: Option<()>,
}

#[derive(Serialize, Deserialize, Debug)]
pub struct SelectObject {
    #[serde(skip_serializing_if = "Option::is_none")]
    pub id: Option<()>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub color: Option<()>,
    pub name: String,
}

pub trait ToNotionProperties {
    fn to_notion_properties(&self) -> HashMap<String, PropertyValue>;
}

use proc_macro::TokenStream;
use quote::quote;
use syn::{parse_macro_input, DeriveInput, Data, Fields, Meta, NestedMeta};

#[proc_macro_derive(ToNotionProperties, attributes(notion_property))]
pub fn derive_to_notion_properties(input: TokenStream) -> TokenStream {
    let input = parse_macro_input!(input as DeriveInput);
    let name = input.ident;

    let fields = if let Data::Struct(data_struct) = input.data {
        if let Fields::Named(fields_named) = data_struct.fields {
            fields_named.named
        } else {
            panic!("Only structs with named fields are supported");
        }
    } else {
        panic!("Only structs are supported");
    };

    let conversions = fields.iter().map(|field| {
        let field_name = field.ident.as_ref().expect("Field should have identifier");
        let field_name_str = field_name.to_string();

        // Extract attributes
        let mut property_type = None;
        let mut notion_name = None;
        let mut has_custom_map = false;

        for attr in &field.attrs {
            if attr.path.is_ident("notion_property") {
                let meta = attr.parse_meta().expect("Failed to parse attribute");
                if let Meta::List(list) = meta {
                    for nested in list.nested {
                        if let NestedMeta::Meta(meta) = nested {
                            match meta {
                                Meta::NameValue(name_value) => {
                                    let ident = name_value.path.get_ident().expect("Expected identifier");
                                    if ident == "type" {
                                        if let syn::Lit::Str(lit_str) = name_value.lit {
                                            property_type = Some(lit_str.value());
                                        }
                                    } else if ident == "name" {
                                        if let syn::Lit::Str(lit_str) = name_value.lit {
                                            notion_name = Some(lit_str.value());
                                        }
                                    }
                                },
                                Meta::Path(path) => {
                                    if path.get_ident().map(|i| i == "custom_map").unwrap_or(false) {
                                        has_custom_map = true;
                                    }
                                },
                                _ => (),
                            }
                        }
                    }
                }
            }
        }

        let prop_type = property_type.expect("Missing 'type' in notion_property attribute");
        let prop_name = notion_name.expect("Missing 'name' in notion_property attribute");

        let field_type = &field.ty;

        if has_custom_map {
            quote! {
                if let Some(value) = self.#field_name.as_ref() {
                    map.insert(#prop_name.to_string(), value.clone());
                }
            }
        } else {
            match prop_type.as_str() {
                "title" => quote! {
                    map.insert(
                        #prop_name.to_string(),
                        PropertyValue::Title {
                            title: vec![
                                RichTextObject {
                                    annotations: None,
                                    data_type: "text".to_string(),
                                    equation: None,
                                    mention: None,
                                    plain_text: None,
                                    href: None,
                                    text: TextObject {
                                        content: self.#field_name.clone(),
                                        link: None,
                                    }
                                }
                            ]
                        }
                    );
                },
                "url" => quote! {
                    if let Some(url_val) = &self.#field_name {
                        map.insert(
                            #prop_name.to_string(),
                            PropertyValue::Url {
                                url: Some(url_val.clone())
                            }
                        );
                    }
                },
                "MultiSelect" => quote! {
                    if let Some(categories) = &self.#field_name {
                        map.insert(
                            #prop_name.to_string(),
                            PropertyValue::MultiSelect {
                                multi_select: categories.iter()
                                    .filter_map(|v| v.as_str().map(|s| s.to_string()))
                                    .map(|name| SelectObject {
                                        id: None,
                                        color: None,
                                        name
                                    })
                                    .collect()
                            }
                        );
                    }
                },
                _ => panic!("Unsupported property type: {}", prop_type),
            }
        }
    });

    let expanded = quote! {
        impl ToNotionProperties for #name {
            fn to_notion_properties(&self) -> HashMap<String, PropertyValue> {
                use PropertyValue::*;
                let mut map = HashMap::new();
                #(#conversions)*
                map
            }
        }
    };

    TokenStream::from(expanded)
}

#[derive(Serialize, Deserialize, ToNotionProperties)]
struct MyUnit {
    #[notion_property(type = "title", name = "Name")]
    pub name: String,

    #[notion_property(type = "url", name = "Icon url")]
    pub icon_url: Option<String>,

    #[notion_property(type = "MultiSelect", name = "Roles")]
    pub categories: Option<Vec<serde_json::Value>>,
}

fn main() {
    let unit = MyUnit {
        name: "Test Unit".to_string(),
        icon_url: Some("https://example.com/icon.png".to_string()),
        categories: Some(vec![
            serde_json::json!("Role1"),
            serde_json::json!("Role2")
        ]),
    };

    let props = unit.to_notion_properties();
    println!("{:#?}", props);
}
```

This solution includes:

1. **Cargo.toml**: Specifies required dependencies including `serde` for serialization and procedural macro crates (`syn`, `quote`, `proc-macro2`) for the custom derive.

2. **main.rs**:
   - Defines Notion API property structures (PropertyValue, RichTextObject, etc.)
   - Implements a `ToNotionProperties` trait
   - Provides a procedural macro `#[derive(ToNotionProperties)]`
