main.rs:
```rust
use rayon::prelude::*;

#[derive(Debug, Default, Clone)]
struct B {
    r: Vec<f64>,
    v: Vec<f64>,
    f: Vec<f64>,
    nb: Vec<usize>,
}

impl B {
    pub fn criterion(&self, other: &B) -> f64 {
        let dx = self.r[0] - other.r[0];
        let dy = self.r[1] - other.r[1];
        let dz = self.r[2] - other.r[2];
        dx * dx + dy * dy + dz * dz
    }
}

#[derive(Debug, Default, Clone)]
struct A {
    elems: Vec<B>,
    cutoff: f64,
}

impl A {
    pub fn get_nelems(&self) -> usize {
        self.elems.len()
    }

    pub fn build_lists(&mut self) {
        let nelems = self.get_nelems();
        if nelems == 0 {
            return;
        }
        let cutoff = self.cutoff;
        let elems = &self.elems;

        // Compute pairs in parallel (only i < j)
        let pairs: Vec<(usize, usize)> = (0..nelems)
            .into_par_iter()
            .flat_map(|i| {
                (i + 1..nelems)
                    .filter(move |&j| elems[i].criterion(&elems[j]) < cutoff)
                    .map(move |j| (i, j))
                    .collect::<Vec<_>>()
            })
            .collect();

        // Count neighbors for each node
        let mut deg = vec![0; nelems];
        for &(i, j) in &pairs {
            deg[i] += 1;
            deg[j] += 1;
        }

        // Preallocate neighbor lists
        let mut neighbors: Vec<Vec<usize>> = (0..nelems)
            .map(|_| Vec::with_capacity(deg[0]))
            .collect();

        // Populate neighbor lists symmetrically
        for (i, j) in pairs {
            neighbors[i].push(j);
            neighbors[j].push(i);
        }

        // Assign neighbor lists to elements
        for (i, elem) in self.elems.iter_mut().enumerate() {
            elem.nb = std::mem::take(&mut neighbors[i]);
        }
    }
}

fn main() {
    // Test case with 3 points forming a triangle
    let mut a = A {
        elems: vec![
            B {
                r: vec![0.0, 0.0, 0.0],
                ..Default::default()
            },
            B {
                r: vec![1.0, 0.0, 0.0],
                ..Default::default()
            },
            B {
                r: vec![0.0, 1.0, 0.0],
                ..Default::default()
            },
        ],
        cutoff: 1.1, // Should connect points 0-1 and 0-2 but not 1-2
    };

    a.build_lists();

    // Verify neighbor lists
    for (i, elem) in a.elems.iter().enumerate() {
        println!("Element {} neighbors: {:?}", i, elem.nb);
    }

    // Expected:
    // Element 0: [1, 2]
    // Element 1: [0]
    // Element 2: [0]
}
```

