    pub stress: Option<Stress>,
    pub gender: Option<Gender>,
}

pub trait MatchesCondition {
    fn matches_condition(&self, condition: &Self) -> bool;
}

// Implement MatchesCondition for simple types (using PartialEq)
impl<T: PartialEq> MatchesCondition for T {
    default fn matches_condition(&self, condition: &Self) -> bool {
        self == condition
    }
}

// Implement for Option<T> where T: MatchesCondition
impl<T: MatchesCondition> MatchesCondition for Option<T> {
    fn matches_condition(&self, condition: &Self) -> bool {
        match condition {
            Some(cond_val) => {
                if let Some(val) = self {
                    val.matches_condition(cond_val)
                } else {
                    false
                }
            }
            None => true,
        }
    }
}

// Implement for non-option struct fields that have defaults or are non-optional
impl MatchesCondition for DialectFlags {
    fn matches_condition(&self, condition: &Self) -> bool {
        *self == *condition || condition.is_empty()
    }
}

impl MatchesCondition for OrthFlags {
    fn matches_condition(&self, condition: &Self) -> bool {
        *self == *condition || condition.is_empty()
    }
}

impl MatchesCondition for bool {
    fn matches_condition(&self, condition: &Self) -> bool {
        *self == *condition
    }
}

impl MatchesCondition for DictWordMetadata {
    fn matches_condition(&self, condition: &Self) -> bool {
        // Check optional fields
        self.noun.matches_condition(&condition.noun) &&
        self.pronoun.matches_condition(&condition.pronoun) &&
        self.verb.matches_condition(&condition.verb) &&
        self.adjective.matches_condition(&condition.adjective) &&
        self.adverb.matches_condition(&condition.adverb) &&
        self.conjunction.matches_condition(&condition.conjunction) &&
        self.swear.matches_condition(&condition.swear) &&
        self.determiner.matches_condition(&condition.determiner) &&
        self.np_member.matches_condition(&condition.np_member) &&
        self.pos_tag.matches_condition(&condition.pos_tag) &&
        self.stress.matches_condition(&condition.stress) &&
        self.gender.matches_condition(&condition.gender) &&

        // Check non-optional fields with defaults
        self.dialects.matches_condition(&condition.dialects) &&
        self.orth_info.matches_condition(&condition.orth_info) &&
        self.preposition.matches_condition(&condition.preposition) &&
        self.common.matches_condition(&condition.common) &&

        // Check fields with special handling
        self.derived_from.matches_condition(&condition.derived_from)
    }
