use chrono::{DateTime, NaiveDate, NaiveTime, Utc};

fn create_datetime(
    year: i32,
    month: u32,
    day: u32,
    hour: u32,
    min: u32,
    sec: u32,
    milli: u32,
) -> DateTime<Utc> {
    let date = NaiveDate::from_ymd_opt(year, month, day)
        .expect("Invalid date");
    let time = NaiveTime::from_hms_milli_opt(hour, min, sec, milli)
        .expect("Invalid time");
    DateTime::from_utc(date.and_time(time), Utc)
}

