enum State {
    Outside,
    InsideTokenUnquoted(String),
    InsideTokenQuoted(String),
}

fn tokenize(input: &str) -> Vec<String> {
    use State::*;

    let mut tokens = Vec::new();
    let mut state = Outside;

    for c in input.chars() {
        state = match state {
            Outside => match c {
                '\'' => InsideTokenQuoted(String::new()),
                c if c.is_whitespace() => Outside,
                c => {
                    let mut s = String::new();
                    s.push(c);
                    InsideTokenUnquoted(s)
                }
            },
            InsideTokenUnquoted(mut token) => match c {
                '\'' => InsideTokenQuoted(token),
                c if c.is_whitespace() => {
                    tokens.push(token);
                    Outside
                }
                c => {
                    token.push(c);
                    InsideTokenUnquoted(token)
                }
            },
            InsideTokenQuoted(mut token) => match c {
                '\'' => InsideTokenUnquoted(token),
                c => {
                    token.push(c);
                    InsideTokenQuoted(token)
                }
            },
        };
    }

    match state {
        Outside => (),
        InsideTokenUnquoted(token) | InsideTokenQuoted(token) => tokens.push(token),
    }

    tokens
}

fn main() {
    let input = " one  ' two  'three    four";
    let tokens = tokenize(input);

    println!("{} tokens:", tokens.len());
    for token in tokens {
        println!("<{}>", token);
    }
}
```

This solution uses a state machine to properly handle:
1. Quoted sections (with single quotes)
2. Unquoted sections
3. Proper token separation by whitespace
4. Empty tokens from empty quotes
5. Adjacent quoted and unquoted text

