**main.rs**:
```rust
use std::{
    io,
    path::{Path, PathBuf},
    sync::Arc,
};
use hyper::{
    body::Body,
    server::conn::http1,
    service::service_fn,
    Request, Response, StatusCode,
    header::{CONTENT_LENGTH, CONTENT_TYPE},
};
use tokio::{
    fs::File,
    net::TcpListener,
};
use tokio_util::io::ReaderStream;
use mime_guess::from_path;

async fn handle_request(
    req: Request<Body>,
    base_dir: Arc<PathBuf>
) -> Result<Response<Body>, io::Error> {
    // Get request path and resolve to absolute path
    let request_path = req.uri().path();
    let mut path = base_dir.join(request_path.trim_start_matches('/'));

    // Handle directory requests (serve index.html)
    if path.is_dir() {
        path.push("index.html");
    }

    // Security check to prevent directory traversal
    if !path.starts_with(&*base_dir) {
        return Ok(not_found());
    }

    // Attempt to open file
    match File::open(&path).await {
        Ok(file) => {
            let metadata = match file.metadata().await {
                Ok(meta) => meta,
                Err(_) => return Ok(internal_server_error()),
            };

            // Handle directories (after potential index.html check)
            if metadata.is_dir() {
                return Ok(not_found());
            }

            // Get content type from file extension
            let content_type = from_path(&path)
                .first_or_octet_stream()
                .to_string();

            // Create streaming body
            let stream = ReaderStream::new(file);
            let body = Body::from_stream(stream);

            // Build successful response
            Ok(Response::builder()
                .header(CONTENT_LENGTH, metadata.len())
                .header(CONTENT_TYPE, content_type)
                .body(body)
                .unwrap())
        }
        Err(_) => Ok(not_found()),
    }
}

fn not_found() -> Response<Body> {
    Response::builder()
        .status(StatusCode::NOT_FOUND)
        .body(Body::from("404 Not Found"))
        .unwrap()
}

fn internal_server_error() -> Response<Body> {
    Response::builder()
        .status(StatusCode::INTERNAL_SERVER_ERROR)
        .body(Body::from("500 Internal Server Error"))
        .unwrap()
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error + Send + Sync>> {
    let base_dir = std::env::current_dir()?;
    let base_dir = Arc::new(base_dir);
    let addr = "127.0.0.1:8080".parse()?;
    let listener = TcpListener::bind(addr).await?;

    println!("Serving files from {:?}", base_dir);
    println!("Listening on http://{}", addr);

    loop {
        let (stream, _) = listener.accept().await?;
        let base_dir = base_dir.clone();

        tokio::spawn(async move {
            let service = service_fn(move |req| handle_request(req, base_dir.clone()));

            if let Err(err) = http1::Builder::new()
                .serve_connection(stream, service)
                .await
            {
                eprintln!("Connection error: {err}");
            }
        });
    }
}
```

Key features of this implementation:
1. **Streaming File Handling**: Uses `ReaderStream` to convert Tokio's `File` into a stream of bytes
2. **Efficient Memory Usage**: Only buffers small chunks at a time (64KB default)
3. **Security Measures**:
   - Prevents directory traversal attacks
   - Handles path normalization
   - Content type detection
4. **Directory Handling**:
   - Automatically serves index.html for directories
   - Returns 404 for directories without index.html
5. **Proper HTTP Headers**:
   - Sets Content-Length from file metadata
   - Detects MIME types using file extensions
   - Returns appropriate status codes

