    role: String,
}

impl AccessClaims {
    fn validate_role_admin(&self) -> Result<(), APIError> {
        if self.role == "admin" {
            Ok(())
        } else {
            Err(APIError::new(
                StatusCode::FORBIDDEN,
                "Only admin can perform this action",
            ))
        }
