// Define the API error
#[derive(Debug)]
struct APIError {
    status: StatusCode,
    message: String,
}

impl APIError {
    fn new(status: StatusCode, message: &str) -> Self {
        APIError {
            status,
            message: message.to_string(),
        }
    }

    fn invalid_input(message: &str) -> Self {
        Self::new(StatusCode::BAD_REQUEST, message)
    }
}

impl IntoResponse for APIError {
    fn into_response(self) -> Response {
        (self.status, self.message).into_response()
    }
}

// Define the validated JSON extractor
#[derive(Debug)]
pub struct ValidatedJson<T>(pub T);

#[async_trait]
impl<S, T, B> FromRequest<S, B> for ValidatedJson<T>
where
    B: Send + 'static,
    T: DeserializeOwned + Validate,
    S: Send + Sync,
    Json<T>: FromRequest<S, B>,
{
    type Rejection = APIError;

    async fn from_request(req: Request<B>, state: &S) -> Result<Self, Self::Rejection> {
        let Json(payload) = Json::<T>::from_request(req, state)
            .await
            .map_err(|err| APIError::invalid_input(&err.to_string()))?;
        payload
            .validate()
            .map_err(|e| APIError::invalid_input(&e.to_string()))?;
