pub struct ApiVersionHeader(pub APIVersion);

#[async_trait]
impl<S> FromRequestParts<S> for ApiVersionHeader
where
    S: Send + Sync,
{
    type Rejection = APIError;

    async fn from_request_parts(parts: &mut Parts, _state: &S) -> Result<Self, Self::Rejection> {
        use axum::http::header::HeaderName;

        let name = HeaderName::from_static("x-api-version");
        let value = parts.headers.get(&name).ok_or_else(|| {
            APIError::new(
                StatusCode::BAD_REQUEST,
                "missing X-Api-Version header",
