        })?;

        let s = value.to_str().map_err(|_| {
            APIError::new(
                StatusCode::BAD_REQUEST,
                "invalid X-Api-Version header",
            )
        })?;

        let version = s.parse().map_err(|err: String| {
            APIError::new(StatusCode::BAD_REQUEST, &err)
        })?;

        Ok(ApiVersionHeader(version))
    }
}

// Implement FromRequestParts for AccessClaims
