use serde::Deserialize;
use serde::de::Deserializer;

#[derive(Debug)]
struct Character {
    name: String,
    ac: u8,
    current: u16,
    max: u16,
    temp: u16,
}

impl<'de> Deserialize<'de> for Character {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        // Define helper struct matching JSON fields
        #[derive(Deserialize)]
        struct Helper {
            name: String,
            ac: u8,
            hp: u16,
        }

        // Deserialize into helper struct
        let helper = Helper::deserialize(deserializer)?;

        // Map helper to main struct
        Ok(Character {
            name: helper.name,
            ac: helper.ac,
            current: helper.hp,
            max: helper.hp,
            temp: 0, // Initialize temp to 0
        })
    }
}

fn main() {
    // Valid JSON input (fixed missing comma)
    let json = r#"
        {
            "name": "Henry",
            "ac": 16,
            "hp": 54
        }
    "#;

    // Deserialize JSON into Character struct
    let character: Character = serde_json::from_str(json).unwrap();

    // Verify field values
    println!("Name: {}", character.name);
    println!("AC: {}", character.ac);
    println!("Current HP: {}", character.current);
    println!("Max HP: {}", character.max);
    println!("Temp HP: {}", character.temp);

    // Assert expected values
    assert_eq!(character.name, "Henry");
    assert_eq!(character.ac, 16);
    assert_eq!(character.current, 54);
    assert_eq!(character.max, 54);
    assert_eq!(character.temp, 0);
    println!("All assertions passed!");
}
```

This solution:
