```rust
use cadence::prelude::*;
use cadence::{
    BufferedUnixMetricSink, QueuingMetricSink, StatsdClient, NopMetricSink, UnixMetricSinkBuilder,
};
use nix::sys::socket;
use std::os::unix::net::UnixDatagram;
use std::path::Path;
use std::process;
use std::sync::Arc;
use std::time::{Duration, Instant};
use std::env;

const SOCKET_PATH: &str = "/var/run/datadog/dsd.socket";
const METRIC_PREFIX: &str = "test_app";
const MAX_RETRIES: usize = 10;
const METRICS_PER_BATCH: usize = 10_000;

fn create_statsd_client() -> Arc<StatsdClient> {
    let mut retries = 0;
    let unix_sink = loop {
        let sock = match UnixDatagram::unbound() {
            Ok(s) => s,
            Err(e) => {
                log::error!("Failed to create unix datagram: {}", e);
                process::exit(1);
            }
        };

        match sock.connect(SOCKET_PATH) {
            Ok(_) => {
                log::info!("Connected to Datadog socket at {}", SOCKET_PATH);
                break BufferedUnixMetricSink::from(SOCKET_PATH, sock);
            }
            Err(e) => {
                log::warn!("Socket not ready ({}), retrying...", e);
                std::thread::sleep(Duration::from_secs(2));
                retries += 1;
            }
        }

        if retries >= MAX_RETRIES {
            log::error!("Failed to connect to DogStatsD socket after {} retries", MAX_RETRIES);
            process::exit(1);
        }
    };

    let queuing_sink = QueuingMetricSink::from(unix_sink);
    Arc::new(
        StatsdClient::builder(METRIC_PREFIX, queuing_sink)
            .with_error_handler(|e| log::error!("StatsD error: {}", e))
            .build(),
    )
}

fn main() -> anyhow::Result<()> {
    env_logger::Builder::from_env(env_logger::Env::default().default_filter_or("info")).init();

    // Check if socket exists
    if !Path::new(SOCKET_PATH).exists() {
        log::error!("Socket not found at {}", SOCKET_PATH);
        log::warn!("Ensure agent container is running and socket is mounted");
        process::exit(1);
    }

    let statsd = create_statsd_client();
    log::info!("Starting metric emission...");

    let mut count = 0;
    let start_time = Instant::now();

    loop {
        for _ in 0..METRICS_PER_BATCH {
            let res = statsd
                .incr_with_tags("operations.count")
                .with_tag("client_name", "test_client")
                .with_tag("client_version", "1.0")
                .with_tag("network", "mainnet")
                .with_tag("query", "get_data")
                .with_tag("runtime", "rust")
                .try_send();

            if let Err(e) = res {
                log::error!("Failed to send metric: {}", e);
            }

            count += 1;
        }

        let elapsed = start_time.elapsed().as_secs_f64();
        let rate = count as f64 / elapsed;
        log::info!(
            "Sent {} metrics | {:.2} metrics/sec",
            count,
            rate
        );

        // Brief pause to prevent 100% CPU usage
        std::thread::sleep(Duration::from_millis(10));
    }
}
```

**Key features of this test application**:
1. Validates socket existence before attempting connection
2. Implements exponential backoff for connection retries
3. Uses buffered+queued sinks identical to your production setup
4. Emits metrics at high throughput (configurable via `METRICS_PER_BATCH`)
5. Provides real-time send statistics and error logging
6. Includes all original tags for realistic testing

**To use**:
1. Create new Rust project: `cargo new dogstatsd_test`
2. Replace `Cargo.toml` and `src/main.rs` with above files
3. Build with `cargo build --release`
4. Run in your ECS environment alongside the Datadog agent container
5. Monitor agent logs and dashboard metrics

**Expected troubleshooting steps**:
1. Verify agent container mounts the socket volume correctly
2. Check agent's `dogstatsd_stats` metric for packet loss
3. Monitor agent's resource utilization (CPU/memory)
4. Test with reduced throughput by decreasing `METRICS_PER_BATCH`
5. Check for socket permission issues (`ls -la /var/run/datadog`)

This test application will help identify whether the issue is with the Rust application, the agent configuration, or the infrastructure setup by providing detailed logging and throughput statistics.

