use serde::Deserialize;

#[derive(Debug, Deserialize)]
struct ServerData {
    name: String,
}

fn deserialize_server_string<'de, D>(deserializer: D) -> Result<String, D::Error>
where
    D: serde::Deserializer<'de>,
{
    let server_data = ServerData::deserialize(deserializer)?;
    Ok(server_data.name)
}

#[derive(Debug, Deserialize)]
struct Character {
    name: String,
    #[serde(deserialize_with = "deserialize_server_string")]
    server: String,
}

fn main() {
    let json_data = r#"
        {
            "name": "Name",
            "server": {
                "name": "Server"
            }
        }
    "#;

    match serde_json::from_str::<Character>(json_data) {
