use std::{fs, path::Path, str::FromStr};

use sqlx::{
    query, query_as, Acquire, Pool, Row, Sqlite, SqlitePool,
    sqlite::{SqliteConnectOptions, SqliteRow},
};
use uuid::Uuid;

// The struct we want to use with nested Team
#[derive(Debug, PartialEq)]
pub struct Employee {
    pub id: u64,
    pub name: String,
    pub team: Team,
}

// The struct that's easy to implement, but will require more work to use
#[derive(Debug, sqlx::FromRow, PartialEq)]
pub struct EmployeeWithTeamId {
    pub id: u64,
    pub name: String,
    pub team: TeamId,
}

pub type TeamId = u64;

#[derive(Debug, PartialEq)]
pub struct Team {
    pub id: TeamId,
    pub name: String,
}

// Implement FromRow for Employee for SqliteRow
impl<'r> sqlx::FromRow<'r, SqliteRow> for Employee {
    fn from_row(row: &'r SqliteRow) -> Result<Self, sqlx::Error> {
        let employee_id: u64 = row.try_get("employee_id")?;
        let employee_name: String = row.try_get("employee_name")?;
        let team_id: u64 = row.try_get("team_id")?;
        let team_name: String = row.try_get("team_name")?;

        Ok(Employee {
            id: employee_id,
            name: employee_name,
            team: Team {
                id: team_id,
                name: team_name,
            },
        })
    }
}

/// Creates a test sqlite3 db located at `test_db/{random_uuid}.db` populated with dummy data
pub async fn get_pool() -> Pool<Sqlite> {
    // Create db folder if needed
    let path = Path::new("test_db");
    if !path.exists() {
