    let id = Uuid::new_v4();
    let file_path = format!("test_db/{}.db", id);

    // Create db pool
    let pool_opts = SqliteConnectOptions::from_str(&file_path)
        .unwrap()
        .create_if_missing(true);
    let db_pool = SqlitePool::connect_with(pool_opts).await.unwrap();

    // Connect and begin transaction
    let mut conn = db_pool.acquire().await.unwrap();
    let mut tx = conn.begin().await.unwrap();

    // Run schema query
    let schema_sql = "
        CREATE TABLE teams (
            id INTEGER PRIMARY KEY,
            name TEXT
        );

        CREATE TABLE employees (
            id INTEGER PRIMARY KEY,
            name TEXT,
            team INTEGER,
            FOREIGN KEY (team) REFERENCES teams(id)
        );";
    query(schema_sql).execute(&mut *tx).await.unwrap();

    // Run dummy data query
    let dummy_data_sql = "
        INSERT INTO
            teams (id, name)
        VALUES
            (1, 'East Coast Team'),
            (2, 'West Coast Team');

        INSERT INTO
            employees (id, name, team)
        VALUES
            (1, 'Boston Alice', 1),
            (2, 'Seattle Bob', 2);
    ";
    query(dummy_data_sql).execute(&mut *tx).await.unwrap();

    // Commit and close
    tx.commit().await.unwrap();
    conn.close().await.unwrap();

    // Return
    db_pool
}

#[tokio::main]
async fn main() {
    // Create DB and connect
    let pool: Pool<Sqlite> = get_pool().await;
    let mut conn = pool.acquire().await.unwrap();

    // Test 1: get_employee_with_team_id (the old way) still works
    let employee_with_team_id: EmployeeWithTeamId = query_as("SELECT * FROM employees WHERE id = 1")
        .fetch_one(&mut *conn)
        .await
        .unwrap();
    println!("EmployeeWithTeamId: {:?}", employee_with_team_id);

    // Test 2: get_employee (the new way with JOIN and manual FromRow)
    let employee: Employee = query_as(
        "SELECT 
            e.id AS employee_id, 
            e.name AS employee_name, 
            t.id AS team_id, 
            t.name AS team_name 
         FROM employees e 
         JOIN teams t ON e.team = t.id 
         WHERE e.id = 1",
    )
    .fetch_one(&mut *conn)
    .await
    .unwrap();
    println!("Employee: {:?}", employee);
    println!("Team name: {}", employee.team.name);
}
