```

**main.rs**:
```rust
use std::sync::Arc;
use tokio::sync::Mutex;
use tracing::{debug_span, info, info_span, Instrument, Span};
use tracing_opentelemetry::OpenTelemetrySpanExt;
use tracing_subscriber::{layer::SubscriberExt, util::SubscriberInitExt, EnvFilter};

// Context passed between stages
struct RequestContext {
    parent_span: Span,
    // Other request data would go here...
}

// Async stage handler
#[derive(Clone)]
struct StageHandler;

impl StageHandler {
    async fn process_stage(&self, ctx: Arc<Mutex<RequestContext>>, name: &'static str) {
        // Extract parent span from context
        let parent_span = {
            let ctx = ctx.lock().await;
            ctx.parent_span.clone()
        };

        // Rehydrate the OpenTelemetry context
        let otel_ctx = parent_span.context();

        // Create child span explicitly linked to parent
        let stage_span = debug_span!(name).set_parent(otel_ctx);

        // Instrumented async block
        async move {
            info!("Executing stage {}", name);
            tokio::time::sleep(std::time::Duration::from_millis(100)).await;
            info!("Completed stage {}", name);
        }
        // Attach the span to the future
        .instrument(stage_span)
        .await;
    }
}

#[tokio::main]
async fn main() {
    // Initialize tracing with OpenTelemetry
    let tracer = opentelemetry::sdk::export::trace::stdout::new_pipeline()
        .install_simple();
    let opentelemetry = tracing_opentelemetry::layer().with_tracer(tracer);

    tracing_subscriber::registry()
        .with(EnvFilter::from_default_env())
        .with(tracing_subscriber::fmt::layer())
        .with(opentelemetry)
        .init();

    // Create parent span for the request
    let root_span = info_span!("request", request_id = 123);

    // Create context with parent span
    let ctx = Arc::new(Mutex::new(RequestContext {
        parent_span: root_span.clone(),
    }));

    let handler = StageHandler;

    // Use the parent span context for the initial scope
    root_span.in_scope(|| {
        info!("Starting request processing");
    });

    // Simulate stages running on different threads
    let mut handles = Vec::new();
    for (i, stage) in ["stage1", "stage2", "stage3", "upstream"].iter().enumerate() {
        let ctx_clone = ctx.clone();
        let handler_clone = handler.clone();
        let stage_name = *stage;

        handles.push(tokio::spawn(async move {
            // Simulate delayed execution
            tokio::time::sleep(std::time::Duration::from_millis(i as u64 * 50)).await;
            handler_clone.process_stage(ctx_clone, stage_name).await;
        }));
    }

    // Wait for all stages to complete
    for handle in handles {
        handle.await.expect("Task failed");
    }

    // Explicitly end root span
    root_span.in_scope(|| {
        info!("Request completed");
    });

    // Shut down OpenTelemetry
    opentelemetry::global::shutdown_tracer_provider();
}
```

Key features demonstrated:

1. **Context Propagation**:
   - Stores parent span in shared `RequestContext`
   - Uses `Arc<Mutex<...>>` for thread-safe context sharing
   - Explicitly sets parent using `set_parent()`

2. **Rehydration**:
   - Retrieves OpenTelemetry context via `parent_span.context()`
   - Applies context to new spans using `set_parent()`
   - Uses `instrument()` to attach spans to futures

3. **Distributed Tracing**:
   - Uses OpenTelemetry with stdout exporter
   - Shows hierarchical span relationships
   - Demonstrates context propagation across threads

4. **Execution Pattern**:
   - Simulates stages executing at different times
   - Shows concurrent execution on different threads
   - Demonstrates proper shutdown procedures

