        self.elems.len()
    }

    pub fn build_lists(&mut self) {
        let nelems = self.get_nelems();
        let cutoff = self.cutoff;

        // Precompute all qualifying pairs in parallel
        let pairs: Vec<_> = (0..nelems)
            .into_par_iter()
            .flat_map(|i| {
                let elems = &self.elems;
