To resolve the issue with validating incoming requests in Axum, the key problem was that the `ValidatedJson` extractor was missing the `FromRequest` implementation. This caused the handler to fail when multiple extractors were used. Below is a self-contained solution with the necessary implementations:

### Cargo.toml
```toml
[package]
name = "axum_validation_example"
version = "0.1.0"
edition = "2021"

[dependencies]
axum = "0.8"
serde = { version = "1.0", features = ["derive"] }
validator = { version = "0.18", features = ["derive"] }
tokio = { version = "1.0", features = ["full"] }
http = "1.0"
async-trait = "0.1"
serde_json = "1.0"
tracing = "0.1"
tracing-subscriber = "0.3"
```

### main.rs
```rust
use async_trait::async_trait;
use axum::{
    extract::{FromRef, FromRequest, FromRequestParts, Request, State},
    http::{request::Parts, StatusCode, HeaderMap},
    middleware,
    response::{IntoResponse, Response},
    routing::post,
    Json, RequestExt, Router,
};
use serde::{Deserialize, Serialize};
use serde_json::json;
use std::{net::SocketAddr, sync::Arc};
use validator::Validate;

#[derive(Debug, Clone)]
struct SharedState {
    // Simulated shared state
}

#[derive(Debug, Serialize, Deserialize, Validate)]
pub struct RevokeUser {
    #[validate(length(min = 6, message = "username id must be at least 6 characters"))]
    pub user_id: String,
}

#[derive(Debug)]
pub struct AccessClaims {
    pub sub: String,
    pub role: String,
}

impl AccessClaims {
    pub fn validate_role_admin(&self) -> Result<(), APIError> {
        if self.role != "admin" {
            return Err(APIError::new(StatusCode::FORBIDDEN, "Forbidden"));
        }
        Ok(())
    }
}

#[derive(Debug)]
pub struct ApiVersionHeader(pub String);

#[derive(Debug)]
pub struct ValidatedJson<T>(pub T);

#[async_trait]
impl<S, T> FromRequest<S> for ValidatedJson<T>
where
    T: DeserializeOwned + Validate,
    S: Send + Sync,
{
    type Rejection = APIError;

    async fn from_request(req: Request, state: &S) -> Result<Self, Self::Rejection> {
        let Json(payload) = Json::<T>::from_request(req, state)
            .await
            .map_err(|e| APIError::new(StatusCode::BAD_REQUEST, &e.to_string()))?;
        payload
            .validate()
            .map_err(|e| APIError::new(StatusCode::BAD_REQUEST, &e.to_string()))?;
        Ok(ValidatedJson(payload))
    }
}

#[async_trait]
impl<S> FromRequestParts<S> for AccessClaims
where
    S: Send + Sync,
{
    type Rejection = APIError;

    async fn from_request_parts(parts: &mut Parts, _state: &S) -> Result<Self, Self::Rejection> {
        // Simulated token decoding
        Ok(AccessClaims {
            sub: "user123".to_string(),
            role: "user".to_string(),
        })
    }
}

#[async_trait]
impl<S> FromRequestParts<S> for ApiVersionHeader
where
    S: Send + Sync,
{
    type Rejection = APIError;

    async fn from_request_parts(parts: &mut Parts, _state: &S) -> Result<Self, Self::Rejection> {
        let version = parts
            .headers
            .get("x-api-version")
            .ok_or_else(|| APIError::new(StatusCode::BAD_REQUEST, "Missing X-Api-Version header"))?
            .to_str()
            .map_err(|_| APIError::new(StatusCode::BAD_REQUEST, "Invalid header value"))?
            .to_string();

        Ok(ApiVersionHeader(version))
    }
}

#[derive(Debug)]
struct APIError {
    status: StatusCode,
    message: String,
}

impl APIError {
    fn new(status: StatusCode, message: &str) -> Self {
        APIError {
            status,
            message: message.to_string(),
        }
    }
}

impl IntoResponse for APIError {
    fn into_response(self) -> Response {
        let body = json!({ "error": self.message });
        (self.status, Json(body)).into_response()
    }
}

pub async fn revoke_user_handler(
    ApiVersionHeader(api_version): ApiVersionHeader,
    State(_state): State<Arc<SharedState>>,
    access_claims: AccessClaims,
    ValidatedJson(revoke_user): ValidatedJson<RevokeUser>,
) -> Result<impl IntoResponse, APIError> {
    tracing::debug!("api version: {}", api_version);
    if access_claims.sub != revoke_user.user_id {
        access_claims.validate_role_admin()?;
    }
    tracing::debug!("revoke_user: {:?}", revoke_user);
    Ok(StatusCode::OK)
}

#[tokio::main]
async fn main() {
    tracing_subscriber::fmt::init();

    let state = Arc::new(SharedState {});

    let app = Router::new()
        .route("/revoke-user", post(revoke_user_handler))
        .with_state(state);

    let addr = SocketAddr::from(([127, 0, 0, 1], 3000));
    tracing::debug!("listening on {}", addr);
    axum::Server::bind(&addr)
        .serve(app.into_make_service())
        .await
        .unwrap();
}
```

### Key Fixes:
1. **Implemented `FromRequest` for `ValidatedJson`**: This allows Axum to properly extract and validate the JSON payload.
2. **Simplified Error Handling**: Created a unified `APIError` type that implements `IntoResponse`.
3. **Simulated Dependencies**: Provided mock implementations for `AccessClaims` and `SharedState` to make the example runnable.
4. **Testing Setup**: Added tracing for easier debugging and a working main function.

To test:
