use std::path::PathBuf;
use std::net::SocketAddr;
use hyper::body::Bytes;
use hyper::server::conn::http1;
use hyper::service::service_fn;
use hyper::{Request, Response, StatusCode};
use hyper_util::rt::TokioIo;
use tokio::net::TcpListener;
use tokio_util::io::ReaderStream;

async fn handle_request(req: Request<hyper::body::Incoming>) -> Result<Response<hyper::body::Body>, hyper::http::Error> {
    // Extract path from request URI (replace with your routing logic)
    let path = PathBuf::from("./bigfile.bin"); // Serve a fixed file for demonstration

    // Attempt to open the file
    match tokio::fs::File::open(&path).await {
        Ok(file) => {
            // Convert file into a stream of Bytes
            let stream = ReaderStream::new(file);
            let body = hyper::body::Body::wrap_stream(stream);

            // Build response with body
            Response::builder()
                .header("Content-Type", "application/octet-stream")
                .body(body)
        }
        Err(_) => {
            // Return 404 if file not found
            Response::builder()
                .status(StatusCode::NOT_FOUND)
                .body("File not found".into())
