// Resource to track loaded textures
#[derive(Resource, Default)]
struct TextureCache {
    handles: HashMap<String, Handle<Image>>,
    archive_data: HashMap<String, Arc<[u8]>>,
}

fn main() {
    App::new()
        .add_plugins(DefaultPlugins)
        .add_asset::<WadArchive>()
        .init_asset_loader::<WadLoader>()
        .init_resource::<TextureCache>()
        .add_systems(Startup, setup)
        .add_systems(Update, (load_texture_on_demand, spawn_loaded))
        .run();
}

fn setup(
    mut commands: Commands,
    asset_server: Res<AssetServer>,
    mut texture_cache: ResMut<TextureCache>,
) {
    // Load archive (only metadata/index)
    let archive_handle: Handle<WadArchive> = asset_server.load("archive.wad");

