// Component to request texture loading
#[derive(Component)]
struct LoadTexture(pub String);

fn load_texture_on_demand(
    mut commands: Commands,
    mut texture_cache: ResMut<TextureCache>,
    archives: Res<Assets<WadArchive>>,
    archive_handle: Res<Handle<WadArchive>>,
    archive_data: Res<TextureCache>,
    mut images: ResMut<Assets<Image>>,
    query: Query<(Entity, &LoadTexture)>,
) {
    for (entity, request) in query.iter() {
        let texture_name = request.0.clone();

        // Skip if already loaded
        if texture_cache.handles.contains_key(&texture_name) {
            commands.entity(entity).remove::<LoadTexture>();
            continue;
        }

        if let Some(archive) = archives.get(&archive_handle.id()) {
            if let Some(data) = archive_data.archive_data.get("archive.wad") {
                if let Some(bytes) = archive.extract(data, &texture_name) {
