[dev-dependencies]
```

main.rs:
```rust
// Define symbol interner and state
#[derive(Debug)]
struct SymbolInterner(String);

impl SymbolInterner {
    fn new() -> Self {
        SymbolInterner("test".to_string())
    }
    fn get(&self) -> &str {
        &self.0
    }
}

struct State<'e> {
    symbol_interner: &'e SymbolInterner,
}

// Define locating slice and stream types
struct LocatingSlice<'i> {
    input: &'i str,
}

impl<'i> LocatingSlice<'i> {
    fn new(input: &'i str) -> Self {
        LocatingSlice { input }
    }
}

struct Stateful<I, S> {
    input: I,
    state: S,
}

type SStream<'i, 'e> = Stateful<LocatingSlice<'i>, State<'e>>;
type ModalResult<T> = Result<T, String>;

// Define parser trait
trait ModalParser<I, O, E> {
    fn parse(&mut self, input: I) -> ModalResult<O>;
}

impl<I, O, E, F> ModalParser<I, O, E> for F
where
    F: FnMut(I) -> ModalResult<O>,
{
    fn parse(&mut self, input: I) -> ModalResult<O> {
        self(input)
    }
}

// Define Cons type
#[derive(Debug, PartialEq)]
struct Cons<'e> {
    value: &'e str,
}

// Example parser function
fn parse_cons<'i, 'e>(input: &mut SStream<'i, 'e>) -> ModalResult<Cons<'e>> {
    Ok(Cons {
        value: input.state.symbol_interner.get(),
    })
}

// Test helper macro
macro_rules! test_input_output {
    ($input:expr, $expected_output:expr, $parser:expr) => {{
        let symbol_interner = SymbolInterner::new();
        let mut stateful = SStream {
            input: LocatingSlice::new($input),
            state: State {
                symbol_interner: &symbol_interner,
            },
        };
        let parsed = $parser(&mut stateful).unwrap_or_else(|e| {
            panic!(
                "Failed on:\n\tinput: {:?}\n\texpected output: {:?}\n\n{}",
                $input, $expected_output, e
            )
        });
        assert_eq!(&parsed, $expected_output);
    }};
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_cons() {
        let expected_output = Cons { value: "test" };
        test_input_output!("(1 . 2)", &expected_output, parse_cons);
    }
}

fn main() {
    println!("Run tests with `cargo test`");
}
