}

pub fn bool_property(ui: &mut egui::Ui, title: &str, value: &mut bool, _interactable: bool) {
    ui.label(title);
    ui.checkbox(value, "");
}

pub fn namedvalue_property(ui: &mut egui::Ui, title: &str, _value: &mut NamedTypeValue, _interactable: bool) {
    ui.label(title);
    ui.label("NamedTypeValue");
}

pub fn argnamedvalue_property(ui: &mut egui::Ui, title: &str, _value: &mut ArgumentNamedValue, _interactable: bool) {
    ui.label(title);
    ui.label("ArgumentNamedValue");
}

pub fn downcast_all_enum_properties(
    _value: &mut dyn Any,
    _ui: &mut egui::Ui,
