}

pub fn downcast_property(ui: &mut egui::Ui, title: &str, value_mut: &mut dyn Any, interactable: bool) {
    if let Some(string_v) = value_mut.downcast_mut::<String>() {
        string_property(ui, title, string_v, interactable);
    } else if let Some(int_v) = value_mut.downcast_mut::<i32>() {
        i_property(ui, title, int_v, interactable);
    } else if let Some(float_v) = value_mut.downcast_mut::<f32>() {
        f_property(ui, title, float_v, interactable);
    } else if let Some(usize_v) = value_mut.downcast_mut::<usize>() {
        i_property(ui, title, usize_v, interactable);
    } else if let Some(bool_v) = value_mut.downcast_mut::<bool>() {
        bool_property(ui, title, bool_v, interactable);
    } else if downcast_all_enum_properties(value_mut, ui, title, interactable, true) {
        // Handled by enum downcaster
    } else if let Some(named_type_value) = value_mut.downcast_mut::<NamedTypeValue>() {
        namedvalue_property(ui, title, named_type_value, interactable);
    } else if let Some(argument_named_value) = value_mut.downcast_mut::<ArgumentNamedValue>() {
        argnamedvalue_property(ui, title, argument_named_value, interactable);
    } else if let Some(list) = (value_mut as &mut dyn Any).as_any_list_mut() {
        any_list_property(ui, title, list, interactable);
    } else if let Some(opt) = (value_mut as &mut dyn Any).as_any_option_mut() {
        any_option_property(ui, title, opt, interactable);
    } else {
        ui.label(egui::RichText::new(format!("Field {}: unknown type", title)).color(egui::Color32::LIGHT_RED));
    }
}

pub fn any_list_property(ui: &mut egui::Ui, title: &str, list: &mut dyn AnyList, interactable: bool) {
    egui::CollapsingHeader::new(title)
        .default_open(true)
        .enabled(interactable)
        .show(ui, |ui| {
            ui.horizontal_top(|ui| {
                if ui.button("➕ Add").clicked() {
                    list.push_default();
                }
            });

            let mut i = 0;
            while i < list.len() {
                ui.horizontal(|ui| {
                    downcast_property(ui, "", list.element_mut(i), interactable);
                    if ui.button("❌").on_hover_text("Remove").clicked() {
                        list.remove(i);
                    } else {
                        i += 1;
                    }
                });
            }
        });
}

pub fn any_option_property(ui: &mut egui::Ui, title: &str, option: &mut dyn AnyOption, interactable: bool) {
    let mut is_none = option.is_none();
    ui.horizontal(|ui| {
        ui.label(title);
        bool_property(ui, "None", &mut is_none, interactable);
        if is_none {
            option.set_none();
        } else {
            if let Some(inner) = option.as_any_mut() {
                downcast_property(ui, "", inner, interactable);
            } else {
                option.set_some_default();
            }
        }
    });
}

