### main.rs
```rust
use std::collections::HashMap;
use std::error::Error;
use zbus::Connection;
use zvariant::Value;

const NETCONFIG_SERVICE: &str = "com.example.NetConfig";
const NETCONFIG_PATH: &str = "/com/example/NetConfig";
const NETCONFIG_OBJECT: &str = "com.example.Netconfig";
const NETCONFIG_METHOD: &str = "SetInterfaceIP";

const NOTIFICATIONS_SERVICE: &str = "org.freedesktop.Notifications";
const NOTIFICATIONS_PATH: &str = "/org/freedesktop/Notifications";
const NOTIFICATIONS_OBJECT: &str = "org.freedesktop.Notifications";
const NOTIFICATIONS_METHOD: &str = "Notify";

#[tokio::main]
async fn main() -> Result<(), Box<dyn Error>> {
    let connection = Connection::session().await?;

    // Toggle between services using this boolean
    let use_notifications = true;

    if use_notifications {
        // Build empty hints map (using references for zero-copy)
        let hints = HashMap::<&str, &Value>::new();

        // Create arguments as a tuple
        let args = (
            "my-app",                   // app_name
            0u32,                       // replaces_id
            "dialog-information",       // app_icon
            "A summary",                // summary
            "Some body",                // body
            Vec::<&str>::new(),         // actions (empty)
            hints,                      // hints
            5000,                       // timeout
        );

        // Call D-Bus method
        let m = connection
            .call_method(
                Some(NOTIFICATIONS_SERVICE),
                NOTIFICATIONS_PATH,
                Some(NOTIFICATIONS_OBJECT),
                NOTIFICATIONS_METHOD,
                &args,
            )
            .await?;

        // Deserialize reply
        let reply: u32 = m.body_deserialized()?;
        dbg!(reply);
    } else {
        // Create arguments as a tuple
        let args = (
            "enxc0470e9a117",          // interface
            "192.168.1.141",           // IP address
        );

        // Call D-Bus method
        let m = connection
            .call_method(
                Some(NETCONFIG_SERVICE),
                NETCONFIG_PATH,
                Some(NETCONFIG_OBJECT),
                NETCONFIG_METHOD,
                &args,
            )
            .await?;

        // Deserialize reply
        let reply: u32 = m.body_deserialized()?;
        dbg!(reply);
    }

    Ok(())
}
```

### Key Improvements:
1. **Tuple Arguments**: Uses tuples for method arguments instead of structs, matching D-Bus's expectation of multiple parameters
2. **Lifetime Handling**: Uses `HashMap<&str, &Value>` with references to avoid ownership issues
3. **Zero-Copy**: Uses string literals (`&str`) and references to minimize allocations
4. **Conditional Calls**: Cleanly separates the two service calls using a boolean toggle
5. **Proper Deserialization**: Uses `body_deserialized()` for type-safe response handling

To test:
1. Save both files in a new Rust project
2. Run `cargo run` (ensure D-Bus services are available)
3. Toggle `use_notifications` boolean to switch services

