use futures::stream::StreamExt;
use std::time::Duration;
use tokio::sync::broadcast;

mod event {
    use axum::response::sse::Event;
    use futures::stream::Stream;
    use tokio::sync::broadcast::{channel, error::RecvError, Sender};

    pub fn events_channel() -> (EventSender, EventStreamFactory) {
        let (tx, _) = channel(20);
        (
            EventSender { tx: tx.clone() },
            EventStreamFactory { tx },
        )
    }

    #[derive(Debug, Clone)]
    pub struct EventSender {
        pub tx: Sender<Event>,
    }

    impl EventSender {
        pub fn send(&self, event: Event) {
            let _ = self.tx.send(event);
        }
    }

    #[derive(Clone)]
    pub struct EventStreamFactory {
        tx: Sender<Event>,
    }

    impl EventStreamFactory {
        pub fn all_events(&self) -> impl Stream<Item = Result<Event, RecvError>> + Send + 'static {
            broadcast::Receiver::into_stream(self.tx.subscribe())
        }
    }
}

#[tokio::main]
async fn main() {
    let (event_sender, event_stream_factory) = event::events_channel();

    // Clone the sender for the background task
    let sender_clone = event_sender.clone();
    let send_task = tokio::spawn(async move {
        let mut interval = tokio::time::interval(Duration::from_secs(1));
        loop {
            interval.tick().await;
            let event = SseEvent::default().data(format!("Event at {:?}", interval.period()));
            if sender_clone.send(event).is_err() {
                break; // Exit if channel is closed
            }
        }
    });

    // Setup axum application with the stream factory
    let app = Router::new().route(
        "/events",
        get(|event_factory: axum::extract::State<event::EventStreamFactory>| async move {
            let stream = event_factory
                .all_events()
                .map(|res| res.map_err(|e| axum::Error::new(e)));
            Sse::new(stream).keep_alive(
                axum::response::sse::KeepAlive::new()
                    .interval(Duration::from_secs(1))
                    .text("keep-alive-text"),
            )
        }),
    )
    .with_state(event_stream_factory);

    // Start server with graceful shutdown
    let server = axum::Server::bind(&"0.0.0.0:3000".parse().unwrap())
        .serve(app.into_make_service())
        .with_graceful_shutdown(async {
            tokio::signal::ctrl_c().await.expect("Failed to listen to ctrl_c");
        });

    if let Err(e) = server.await {
        eprintln!("Server error: {}", e);
    }

    // Explicitly drop the original sender and abort the send task
    drop(event_sender);
    send_task.abort();

    println!("Server shutdown complete");
}
"
}
