use polars::prelude::*;

fn main() -> PolarsResult<()> {
    // Create a sample DataFrame with one column "col1"
    let df = df! [
        "col1" => ["a", "b", "c"]
    ]?;

    // Apply transformation to create a new column "struct_list"
    let out = df
        .lazy()
        .with_column(
            col("col1")
                .map(
                    move |s: Series| {
                        let ca = s.str()?;
                        // Process each row: convert string to list of structs
                        let vec: Vec<Option<Series>> = ca
                            .iter()
                            .map(|opt_s| {
                                opt_s.map(|s| {
                                    // Create two structs per row
                                    let c1_values = vec![format!("{}1", s), format!("{}2", s)];
                                    let c2_values = vec![format!("{}_a", s), format!("{}_b", s)];

                                    // Build series for struct fields
                                    let s1 = Series::new("c1", c1_values);
                                    let s2 = Series::new("c2", c2_values);

                                    // Create struct series
                                    StructChunked::new("", &[s1, s2])
                                        .map(|sc| sc.into_series())
                                })
                                .transpose()
                            })
                            .collect::<PolarsResult<_>>()?;
                        // Convert to ListChunked and then to Series
                        let list_chunked = ListChunked::new("struct_list", &vec);
                        Ok(list_chunked.into_series())
                    },
                    GetOutput::map_type(|_| {
                        DataType::List(Box::new(DataType::Struct(vec![
                            Field::new("c1", DataType::String),
                            Field::new("c2", DataType::String),
                        ]))
                    }),
                )
                .alias("struct_list"),
        )
        .collect()?;

    println!("{:?}", out);
    Ok(())
}
```

### Explanation
1. **Cargo.toml**: Specifies the dependencies for the project, including Polars with features required for lazy evaluation, string operations, list handling, and struct data types.
2. **main.rs**:
   - **DataFrame Creation**: A sample DataFrame is created with a column "col1" containing strings "a", "b", and "c".
   - **Transformation**:
     - The `map` function processes each string in "col1".
     - For each string, two structs are created. Each struct has fields "c1" and "c2" with values derived from the original string.
     - The structs are combined into a struct series using `StructChunked::new`.
     - The struct series for each row is collected into a `ListChunked` series, forming the new column "struct_list".
   - **Output Specification**: The `GetOutput::map_type` function defines the output data type as a list of structs with string fields.
   - **Execution**: The transformation is applied in a lazy context, and the result is collected and printed.

This approach efficiently transforms each string into a list of structs, leveraging Polars' capabilities for handling complex data transformations.

