use headers::{HeaderMap, Origin};
use tower_http::cors::CorsLayer;

#[tokio::main]
async fn main() {
    let app = Router::new()
        .route("/", get(hello_world))
        .route(
            "/ws/:session_id",
            get(websocket_handler).layer(middleware::from_fn(websocket_origin_check)),
        )
        .layer(
            CorsLayer::new()
                .allow_origin("https://www.example.com".parse::<HeaderValue>().unwrap())
                .allow_methods([axum::http::Method::GET, axum::http::Method::POST])
                .allow_headers([axum::http::header::CONTENT_TYPE]),
        );

    let listener = tokio::net::TcpListener::bind("127.0.0.1:3000")
        .await
        .unwrap();
    println!("Listening on http://{}", listener.local_addr().unwrap());
    axum::serve(listener, app).await.unwrap();
}

async fn hello_world() -> Html<&'static str> {
    Html("<h1>Hello, World!</h1>")
}

async fn websocket_origin_check<B>(
    req: Request<B>,
    next: Next<B>,
) -> Result<Response, StatusCode> {
    // Check if this is a WebSocket upgrade request
    if is_websocket_upgrade(&req) {
        // Extract Origin header
        let origin = req
            .headers()
            .get("origin")
            .and_then(|value| value.to_str().ok())
            .unwrap_or("");

        // Validate origin
        if origin != "https://www.example.com" {
            return Err(StatusCode::FORBIDDEN);
        }
    }

    Ok(next.run(req).await)
}

fn is_websocket_upgrade<B>(req: &Request<B>) -> bool {
    req.headers()
        .get("upgrade")
        .map(|value| value.as_bytes())
        .filter(|value| value.eq_ignore_ascii_case(b"websocket"))
        .is_some()
}

async fn websocket_handler(
    ws: WebSocketUpgrade,
    _session_id: axum::extract::Path<String>,
) -> impl IntoResponse {
    ws.on_upgrade(|socket| handle_socket(socket))
}

async fn handle_socket(mut socket: WebSocket) {
    while let Some(Ok(msg)) = socket.recv().await {
        if let axum::extract::ws::Message::Text(text) = msg {
            if socket
                .send(axum::extract::ws::Message::Text(format!("Echo: {}", text)))
                .await
                .is_err()
            {
                break;
            }
        }
    }
}"
}
```

This solution includes:

1. **CORS Configuration**:
   - Regular HTTP routes use `tower-http`'s CORS layer
   - WebSocket routes bypass CORS and require custom origin checking

2. **WebSocket Origin Middleware**:
   - `websocket_origin_check` middleware intercepts WebSocket upgrade requests
   - Checks for `Upgrade: websocket` header
   - Validates Origin header against allowed origin ("https://www.example.com")
   - Returns 403 Forbidden for invalid origins

3. **WebSocket Handler**:
   - Simple echo WebSocket handler that demonstrates origin protection
   - Only allows connections from "https://www.example.com"

4. **Regular HTTP Route**:
   - Simple "Hello World" route protected by standard CORS

