```rust
use axum::{
    body::Body,
    extract::{FromRequest, FromRequestParts, Json, Request, State},
    http::{request::Parts, StatusCode, HeaderMap, header::HeaderName},
    response::{IntoResponse, Response},
    routing::post,
    Router,
};
use serde::{Deserialize, Serialize};
use validator::Validate;
use std::sync::Arc;

#[derive(Debug, Serialize, Deserialize, Validate, Clone)]
pub struct RevokeUser {
    #[validate(length(min = 6, message = "username id must be at least 6 characters"))]
    pub user_id: String,
}

#[derive(Debug, Clone)]
pub struct SharedState {
    // Simplified shared state
}

#[derive(Debug, Clone)]
pub struct AccessClaims {
    pub sub: String,
    pub role: String,
}

impl AccessClaims {
    pub fn validate_role_admin(&self) -> Result<(), AppError> {
        if self.role != "admin" {
            Err(AppError::AuthError("Permission denied".to_string()))
        } else {
            Ok(())
        }
    }
}

#[derive(Debug)]
pub enum AppError {
    ValidationError(String),
    AuthError(String),
    JsonExtractorError(String),
}

impl IntoResponse for AppError {
    fn into_response(self) -> Response {
        let (status, message) = match self {
            AppError::ValidationError(msg) => (StatusCode::BAD_REQUEST, msg),
            AppError::AuthError(msg) => (StatusCode::UNAUTHORIZED, msg),
            AppError::JsonExtractorError(msg) => (StatusCode::BAD_REQUEST, msg),
        };
        (status, message).into_response()
    }
}

#[derive(Debug, Clone, PartialEq)]
pub enum APIVersion {
    V1,
    V2,
}

impl std::str::FromStr for APIVersion {
    type Err = String;

    fn from_str(s: &str) -> Result<Self, Self::Err> {
        match s {
            "v1" => Ok(APIVersion::V1),
            "v2" => Ok(APIVersion::V2),
            _ => Err(format!("Unknown API version: {}", s)),
        }
    }
}

pub struct ApiVersionHeader(pub APIVersion);

#[axum::async_trait]
impl<S> FromRequestParts<S> for ApiVersionHeader
where
    S: Send + Sync,
{
    type Rejection = AppError;

    async fn from_request_parts(parts: &mut Parts, _state: &S) -> Result<Self, Self::Rejection> {
        let name = HeaderName::from_static("x-api-version");
        let value = parts
            .headers
            .get(&name)
            .ok_or_else(|| AppError::ValidationError("Missing X-Api-Version header".to_string()))?;

        let s = value
            .to_str()
            .map_err(|_| AppError::ValidationError("Invalid X-Api-Version header".to_string()))?;

        let version: APIVersion = s
            .parse()
            .map_err(|err: String| AppError::ValidationError(err))?;

        Ok(ApiVersionHeader(version))
    }
}

#[axum::async_trait]
impl<S> FromRequestParts<S> for AccessClaims
where
    S: Send + Sync,
{
    type Rejection = AppError;

    async fn from_request_parts(parts: &mut Parts, _state: &S) -> Result<Self, Self::Rejection> {
        // Simplified: Normally you would decode a token here
        Ok(AccessClaims {
            sub: "test_user".to_string(),
            role: "admin".to_string(),
        })
    }
}

pub struct ValidatedJson<T>(pub T);

#[axum::async_trait]
impl<S, T> FromRequest<S> for ValidatedJson<T>
where
    T: DeserializeOwned + Validate,
    S: Send + Sync,
{
    type Rejection = AppError;

    async fn from_request(req: Request<Body>, state: &S) -> Result<Self, Self::Rejection> {
        let Json(payload) = Json::<T>::from_request(req, state)
            .await
            .map_err(|e| AppError::JsonExtractorError(e.to_string()))?;
        payload
            .validate()
            .map_err(|e| AppError::ValidationError(e.to_string()))?;
        Ok(ValidatedJson(payload))
    }
}

pub async fn revoke_user_handler(
    ApiVersionHeader(api_version): ApiVersionHeader,
    State(_state): State<Arc<SharedState>>,
    access_claims: AccessClaims,
    ValidatedJson(revoke_user): ValidatedJson<RevokeUser>,
) -> Result<impl IntoResponse, AppError> {
    tracing::trace!("api version: {:?}", api_version);

    if access_claims.sub != revoke_user.user_id {
        access_claims.validate_role_admin()?;
    }

    tracing::trace!("revoke_user: {:?}", revoke_user);
