**main.rs:**
```rust
use std::sync::Arc;
use tokio::sync::Mutex;
use tokio_postgres::{Client, NoTls};

pub struct DbContainer {
    container_name: String,
    args: Vec<String>,
    db_config: DbConfig,
    client: Arc<Mutex<Option<Client>>>,
}

#[derive(Debug, Clone)]
pub struct DbConfig {
    pub port: u16,
    pub name: String,
    pub user: String,
    pub postgres_password: String,
    pub db_password: String,
}

impl DbContainer {
    pub fn new<N>(container_name: N, db_config: DbConfig) -> Self
    where
        N: Into<String>,
    {
        Self {
            container_name: container_name.into(),
            args: vec![
                "--env".to_string(),
                format!("POSTGRES_PASSWORD={}", &db_config.postgres_password),
                "--publish".to_string(),
                format!("{}:5432", db_config.port),
            ],
            db_config,
            client: Arc::new(Mutex::new(None)),
        }
    }

    pub async fn create_database(&self, name: &str) -> Result<(), tokio_postgres::Error> {
        let client = self.connect(None).await?;
        client
            .execute(&format!("CREATE DATABASE {name}"), &[])
            .await?;
        let client = self.connect(Some(name)).await?;
        client.batch_execute(load_schema()).await
    }

    pub async fn drop_database(&self, name: &str) -> Result<u64, tokio_postgres::Error> {
        let client = self.connect(None).await?;
        let terminate_sql = format!(
            "
            SELECT pg_terminate_backend(pid)
            FROM pg_stat_activity
            WHERE datname = '{name}' AND pid <> pg_backend_pid();
            ",
        );
        client.execute(&terminate_sql, &[]).await?;
        client.execute(&format!("DROP DATABASE {name}"), &[]).await
    }

    async fn connect(&self, db_name: Option<&str>) -> Result<Client, tokio_postgres::Error> {
        let conn_str = if let Some(dbname) = db_name {
            format!(
                "host=localhost port={} user=postgres password={} dbname={dbname}",
                self.db_config.port, self.db_config.postgres_password
            )
        } else {
            format!(
                "host=localhost port={} user=postgres password={}",
                self.db_config.port, self.db_config.postgres_password
            )
        };

        if db_name.is_some() {
            let (client, conn) = tokio_postgres::connect(&conn_str, NoTls).await?;
            tokio::spawn(async move {
                if let Err(e) = conn.await {
                    eprintln!("Connection error: {e}");
                }
            });
            Ok(client)
        } else {
            let mut client_guard = self.client.lock().await;
            if client_guard.is_none() || client_guard.as_ref().unwrap().is_closed() {
                let (client, conn) = tokio_postgres::connect(&conn_str, NoTls).await?;
                tokio::spawn(async move {
                    if let Err(e) = conn.await {
                        eprintln!("Connection error: {e}");
                    }
                });
                *client_guard = Some(client);
            }
            Ok(client_guard.as_ref().unwrap().clone())
        }
    }
}

fn load_schema() -> &'static str {
    "CREATE TABLE IF NOT EXISTS users (id SERIAL PRIMARY KEY, name TEXT NOT NULL);"
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    env_logger::init();

    let config = DbConfig {
        port: 5432,
        name: "postgres".to_string(),
        user: "postgres".to_string(),
        postgres_password: "password".to_string(),
        db_password: "password".to_string(),
    };

    let container = DbContainer::new("test-container", config);

    for i in 0..10 {
        let db_name = format!("test_db_{}", uuid::Uuid::new_v4());

        println!("Creating database: {}", db_name);
        if let Err(e) = container.create_database(&db_name).await {
            eprintln!("Failed to create database {}: {}", db_name, e);
            continue;
        }

        println!("Dropping database: {}", db_name);
        match container.drop_database(&db_name).await {
            Ok(_) => println!("Successfully dropped database {}", db_name),
            Err(e) => eprintln!("Failed to drop database {}: {}", db_name, e),
        }

        println!("Completed iteration {}", i);
    }

    Ok(())
}
```

This implementation:

1. Uses a thread-safe `Arc<Mutex<Option<Client>>>` for caching
2. Checks `client.is_closed()` before returning cached connections
3. Automatically reconnects when the connection is closed
4. Returns cloned `Client` instances that share the same connection
5. Includes a complete runnable example with UUID-based database names
6. Uses env_logger for better error visibility

The solution handles connection failures gracefully and prevents the "Closed connection" errors by:
- Monitoring connection status
- Implementing automatic reconnection
- Maintaining a single persistent connection
- Properly cloning the client for shared access

To test:
1. Create a PostgreSQL instance at localhost:5432 with user=postgres, password=password
2. Run with `cargo run`
3. Observe 10 successful create/drop cycles without connection errors

