use std::collections::HashMap;
use std::fs;
use std::path::PathBuf;

use serde::Deserialize;
use serde_json;

#[derive(Deserialize, Debug)]
struct A {
    #[serde(deserialize_with = "deserialize_path_list")]
    path_list: Vec<PathBuf>,
}

fn deserialize_path_list<'de, D>(deserializer: D) -> Result<Vec<PathBuf>, D::Error>
where
    D: serde::Deserializer<'de>,
{
    // Helper struct to capture the $ref field and ignore others
    #[derive(Deserialize)]
    struct RefContainer {
        #[serde(rename = "$ref")]
        ref_path: String,
        #[serde(flatten)]
        _ignore: HashMap<String, serde_json::Value>,
    }

    // Enum to handle both direct and referenced data
    #[derive(Deserialize)]
    #[serde(untagged)]
    enum Aux {
        Direct(Vec<PathBuf>),
        Ref(RefContainer),
    }

    match Aux::deserialize(deserializer)? {
        Aux::Direct(vec) => Ok(vec),
        Aux::Ref(container) => {
            let ref_str = container.ref_path;
            let parts: Vec<&str> = ref_str.splitn(2, '#').collect();
            let file_path = parts[0];
            let pointer = if parts.len() > 1 { parts[1] } else { "" };

            // Read and parse referenced JSON file
            let content = fs::read_to_string(file_path)
                .map_err(|e| serde::de::Error::custom(format!("Error reading {}: {}", file_path, e)))?;
            let value: serde_json::Value = serde_json::from_str(&content)
                .map_err(|e| serde::de::Error::custom(format!("Error parsing JSON in {}: {}", file_path, e)))?;

            // Resolve JSON pointer if specified
            let target_value = if pointer.is_empty() {
                value
            } else {
                value.pointer(pointer)
                    .ok_or_else(|| serde::de::Error::custom(format!("Pointer '{}' not found in {}", pointer, file_path)))?
                    .clone()
            };

            // Deserialize into Vec<PathBuf>
            serde_json::from_value(target_value)
                .map_err(|e| serde::de::Error::custom(format!("Error deserializing referenced value: {}", e)))
        }
    }
}

fn main() {
    let json_data = fs::read_to_string("b.json").expect("failed to read from b.json");
    let a_obj: A = serde_json::from_str(&json_data).expect("deserialization failed");

    for p in &a_obj.path_list {
        println!("{}", p.display())
    }
}
```

