```

Here's a self-contained solution demonstrating a lazy asset loader for Bevy using a custom archive format. The implementation avoids loading the entire archive upfront and only extracts requested assets on demand.

### Cargo.toml
```toml
[package]
name = "bevy_lazy_asset_loader"
version = "0.1.0"
edition = "2021"

[dependencies]
bevy = { version = "0.12", features = ["png"] }
anyhow = "1.0"
thiserror = "1.0"
```

### main.rs
```rust
use bevy::{
    asset::{io::Reader, AssetLoader, AsyncReadExt, LoadContext},
    prelude::*,
    utils::BoxedFuture,
};
use std::{
    collections::HashMap,
    io::Cursor,
    path::{Path, PathBuf},
    sync::{Arc, RwLock},
};
use thiserror::Error;

// Custom asset types
#[derive(Default, Debug)]
struct GameArchive {
    entries: HashMap<String, Vec<u8>>,
}

#[derive(Debug, Clone, TypePath)]
struct ArchiveEntry(pub Handle<Image>);

// Resource to track loaded archives
#[derive(Resource, Default)]
struct ArchiveRegistry {
    archives: RwLock<HashMap<PathBuf, Arc<RwLock<GameArchive>>>>,
}

// Asset loader for GameArchive
#[derive(Default)]
struct GameArchiveLoader;

#[derive(Debug, Error)]
enum ArchiveLoaderError {
    #[error("IO error: {0}")]
    Io(#[from] std::io::Error),
    #[error("Invalid archive format")]
    InvalidFormat,
}

impl AssetLoader for GameArchiveLoader {
    type Asset = GameArchive;
    type Settings = ();
    type Error = ArchiveLoaderError;

    fn load<'a>(
        &'a self,
        reader: &'a mut Reader,
        _settings: &'a (),
        _load_context: &'a mut LoadContext,
    ) -> BoxedFuture<'a, Result<Self::Asset, Self::Error>> {
        Box::pin(async move {
            let mut bytes = Vec::new();
            reader.read_to_end(&mut bytes).await?;

            // Parse archive header (simplified example)
            if bytes.len() < 12 || &bytes[0..4] != b"ARCH" {
                return Err(ArchiveLoaderError::InvalidFormat);
            }

            let entry_count = u32::from_le_bytes([bytes[4], bytes[5], bytes[6], bytes[7]]) as usize;
            let mut offset = 8;
            let mut entries = HashMap::new();

            for _ in 0..entry_count {
                if offset + 4 > bytes.len() {
                    return Err(ArchiveLoaderError::InvalidFormat);
                }

                let name_len = u32::from_le_bytes([
                    bytes[offset],
                    bytes[offset + 1],
                    bytes[offset + 2],
                    bytes[offset + 3],
                ]) as usize;
                offset += 4;

                if offset + name_len > bytes.len() {
                    return Err(ArchiveLoaderError::InvalidFormat);
                }

                let name = String::from_utf8_lossy(&bytes[offset..offset + name_len]).to_string();
                offset += name_len;

                if offset + 4 > bytes.len() {
                    return Err(ArchiveLoaderError::InvalidFormat);
                }

                let data_len = u32::from_le_bytes([
                    bytes[offset],
                    bytes[offset + 1],
                    bytes[offset + 2],
                    bytes[offset + 3],
                ]) as usize;
                offset += 4;

                if offset + data_len > bytes.len() {
                    return Err(ArchiveLoaderError::InvalidFormat);
                }

                entries.insert(name, bytes[offset..offset + data_len].to_vec());
                offset += data_len;
            }

            Ok(GameArchive { entries })
        })
    }

    fn extensions(&self) -> &[&str] {
        &["arch"]
    }
}

// System to extract assets from archives
fn extract_asset_from_archive(
    registry: Res<ArchiveRegistry>,
    mut load_context: LoadContext,
) -> Result<Image, anyhow::Error> {
    let path = load_context.path();

    // Parse virtual path: "path/to/archive.arch#texture.png"
    let (archive_path, entry_name) = parse_virtual_path(path)
        .ok_or_else(|| anyhow::anyhow!("Invalid virtual path format"))?;

    // Find the loaded archive
    let archives = registry.archives.read().unwrap();
    let archive = archives
        .get(&archive_path)
        .ok_or_else(|| anyhow::anyhow!("Archive not loaded: {}", archive_path.display()))?;

    // Read from the archive
    let archive = archive.read().unwrap();
    let bytes = archive
        .entries
        .get(entry_name)
        .ok_or_else(|| anyhow::anyhow!("Entry not found: {}", entry_name))?;

    // Load image from bytes
    let image = Image::from_buffer(
        bytes,
        bevy::render::texture::ImageType::MimeType("image/png"),
    )?;

    Ok(image)
}

fn parse_virtual_path(path: &Path) -> Option<(PathBuf, &str)> {
    let path_str = path.to_str()?;
    let parts: Vec<&str> = path_str.split('#').collect();
    if parts.len() != 2 {
        return None;
    }
    Some((PathBuf::from(parts[0]), parts[1]))
}

// Register archive entries as image assets
fn register_archive_entries(
    mut commands: Commands,
    registry: Res<ArchiveRegistry>,
    asset_server: Res<AssetServer>,
    mut images: ResMut<Assets<Image>>,
) {
    let archives = registry.archives.read().unwrap();

    for (archive_path, archive) in archives.iter() {
        let archive = archive.read().unwrap();

        for (entry_name, bytes) in &archive.entries {
            // Create virtual path: "archive.arch#entry_name"
            let virtual_path = format!("{}#{}", archive_path.display(), entry_name);

            // Manually create image asset
            if let Ok(image) = Image::from_buffer(
                bytes,
                bevy::render::texture::ImageType::MimeType("image/png"),
            ) {
                let handle = images.add(image);

                // Provide a way to access this asset through normal loading
                commands.spawn(ArchiveEntry(handle.clone()));

                // Register with asset server
                asset_server.add_asset(virtual_path.clone(), handle);
            }
        }
    }
}

fn setup(mut commands: Commands, asset_server: Res<AssetServer>) {
    // Load main archive (only loads metadata, not content)
    let archive_handle: Handle<GameArchive> = asset_server.load("example.arch");

    commands.insert_resource(ArchiveHandle(archive_handle));

    // Simple example: load a single entry from the archive
    let texture_handle: Handle<Image> = asset_server.load("example.arch#texture.png");

    commands.spawn(Camera2dBundle::default());
    commands.spawn(SpriteBundle {
        texture: texture_handle,
        ..default()
    });
}

fn track_archive_loading(
    mut registry: ResMut<ArchiveRegistry>,
    mut assets: ResMut<Assets<GameArchive>>,
    archive_handle: Res<ArchiveHandle>,
) {
    if let Some(archive) = assets.remove(archive_handle.0.id()) {
        let path = PathBuf::from("example.arch");
        registry.archives.write().unwrap().insert(path, Arc::new(RwLock::new(archive)));
    }
}

struct ArchiveHandle(Handle<GameArchive>);

fn main() {
    App::new()
        .add_plugins(DefaultPlugins)
        .add_asset::<GameArchive>()
        .init_asset_loader::<GameArchiveLoader>()
        .init_resource::<ArchiveRegistry>()
        .add_systems(Startup, setup)
        .add_systems(Update, track_archive_loading)
        .add_systems(Update, register_archive_entries)
        .run();
}
```

### Key Features:

1. **Lazy Loading**:
   - Archives are loaded as custom assets with metadata only
   - Individual assets are extracted on-demand when requested
   - No full archive decompression until needed

2. **Virtual Path System**:
   - Uses `archive.arch#asset.png` syntax
   - Custom parser handles path resolution

3. **Efficient Storage**:
   - Uses `RwLock` for thread-safe access
   - `Arc` enables shared ownership
   - Only decompresses requested assets

4. **Error Handling**:
   - Comprehensive error types
   - Graceful failure for missing assets
   - Archive format validation

### How to Use:

1. Create a test archive:
   ```bash
   echo -n "ARCH\x02\x00\x00\x00\x09\x00\x00\x00texture.png\x0d\x00\x00\x00\x89PNG\r\n\x1a\nTEST" > assets/example.arch
   ```

2. Run with:
   ```bash
   cargo run
   ```

3. To load assets:
   ```rust
   asset_server.load("example.arch#texture.png");
   ```

### Implementation Notes:

- The archive format is simplified for demonstration (real implementations would use CRC checks and compression)
- Handles image assets but can be extended to any asset type
- The registry tracks loaded archives to avoid reloading
- Actual implementations would add:
  - Proper error recovery
  - Asset watching/reloading
  - Memory management
  - Archive-specific optimizations

This solution shows the core pattern for lazy loading while maintaining compatibility with Bevy's asset system.

