use std::fmt;

use chumsky::prelude::{Input as ChumskyInput, Parser as ChumskyParser, *};
use chumsky::extra;

pub trait BaseParser {
    type InputToken<'src>: PartialEq + fmt::Display + 'src;
    type Input<'src>: ChumskyInput<'src, Token = Self::InputToken<'src>, Span = SimpleSpan>;
    type Output;

    fn parser<'src>() -> impl ChumskyParser<
        'src,
        Self::Input<'src>,
        Self::Output,
        extra::Err<Rich<'src, Self::InputToken<'src>, SimpleSpan>>,
    >;

    /// Perform the parsing within this layer
    fn parse_this<'src>(input: Self::Input<'src>) -> Result<Self::Output, Vec<String>> {
        Self::parser().parse(input).into_result().map_err(|errors| {
            errors
                .into_iter()
                .map(|e| e.to_string())
                .collect::<Vec<_>>()
        })
    }
}

pub trait BaseSliceParser: BaseParser {
    fn parse_this_owned<'src>(input: Vec<Self::InputToken<'src>>) -> Result<Self::Output, Vec<String>>
    where
        Self: BaseParser<Input<'src> = &'src [Self::InputToken<'src>]>,
    {
        Self::parse_this(input.as_slice())
    }
}

// Define a token type for our example
#[derive(Clone, Debug, PartialEq, Eq)]
pub enum Token {
    Char(char),
}

impl fmt::Display for Token {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        match self {
            Token::Char(c) => write!(f, "{}", c),
        }
    }
}

// A parser that parses a single 'a' token
struct MyParser;

impl BaseParser for MyParser {
    type InputToken<'src> = Token;
    type Input<'src> = &'src [Token];
    type Output = Token;

    fn parser<'src>() -> impl ChumskyParser<'src, Self::Input<'src>, Self::Output, extra::Err<Rich<'src, Token, SimpleSpan>>> {
        just(Token::Char('a')).map(|t| t.clone())
    }
}

// Implement BaseSliceParser for MyParser
impl BaseSliceParser for MyParser {}

fn main() {
    let tokens = vec![Token::Char('a')];
    let result = MyParser::parse_this_owned(tokens);
    println!("{:?}", result); // Outputs: Ok(Char('a'))
}
```

