use std::{
    env,
    io::{self, Write},
    os::unix::net::UnixStream,
    time::{Duration, Instant},
};
use termion::{cursor, terminal_size_pixels};

const TARGET_FPS: u64 = 60;
const FRAME_DURATION: Duration = Duration::from_nanos(1_000_000_000 / TARGET_FPS);

fn main() -> io::Result<()> {
    let socket_path = env::var("KITTY_LISTEN_ON")
        .expect("KITTY_LISTEN_ON environment variable not found. Are you using Kitty terminal?");
    let mut socket = UnixStream::connect(socket_path)?;

    let stdout = io::stdout();
    let mut handle = stdout.lock();

    let mut frame_count = 0u32;
    let mut last_id: Option<u32> = None;
    let mut time: f32 = 0.0;

    write!(handle, "{}", cursor::Hide)?;
    handle.flush()?;

    loop {
        let frame_start = Instant::now();

        let (width, height) = terminal_size_pixels().unwrap_or((640, 480));
        let (width, height) = (width as usize, height as usize);

        // Generate animated pixel data
        let pixels: Vec<u8> = (0..height)
            .flat_map(|y| {
                (0..width).flat_map(move |x| {
                    let fx = x as f32 / width as f32;
                    let fy = y as f32 / height as f32;

                    let r = ((fx * std::f32::consts::PI + time).sin() * 0.5 + 0.5) * 255.0;
                    let g = ((fy * std::f32::consts::PI + time * 1.3).sin() * 0.5 + 0.5) * 255.0;
                    let b = (((fx + fy) * std::f32::consts::PI + time * 0.7).sin() * 0.5 + 0.5) * 255.0;

                    [r as u8, g as u8, b as u8]
                })
            })
            .collect();

        // Create shared memory buffer
        let opts = memfd::MemfdOptions::default();
        let mfd = opts.create("kitty_animation")?;
        let mut file = mfd.into_file();
        file.write_all(&pixels)?;
        file.flush()?;

        // Send file descriptor via socket
        let id = frame_count;
        socket.send_fd(&id.to_le_bytes(), file.as_raw_fd())?;

        // Delete previous frame
        if let Some(last) = last_id {
            write!(handle, "\x1b_Ga=d,d=I,i={};\x1b\\", last)?;
        }

        // Transmit new image data
        write!(
            handle,
            "\x1b_Ga=T,f=24,s={},v={},i={};\x1b\\",
            width, height, id
        )?;

        // Display image full screen
        write!(handle, "\x1b_Ga=p,i={},c=1,z=1;\x1b\\", id)?;

        handle.flush()?;
        last_id = Some(id);
        frame_count = frame_count.wrapping_add(1);
        time += 0.1;

        // Maintain frame rate
        let elapsed = frame_start.elapsed();
        if elapsed < FRAME_DURATION {
            std::thread::sleep(FRAME_DURATION - elapsed);
        }
    }
}
```

**Key improvements:**
1. Uses Kitty's `KITTY_LISTEN_ON` socket for direct FD transfer
2. Shared memory buffers via `memfd` for zero-copy data transfer
3. Deletes previous frames to manage terminal memory
4. Frame rate control at 60 FPS
5. Full-screen rendering with `z=1` parameter
6. Handles raw pixels without base64 encoding
7. Proper terminal cleanup on exit

**To run:**
1. Create new project: `cargo new kitty_animation`
2. Replace `Cargo.toml` and `src/main.rs` with above contents
3. Run with `cargo run`

