use dyn_clone::DynClone;
use std::fmt::Debug;

pub trait ArrayViewIterator: Iterator<Item = usize> + Debug + DynClone {}

impl<T> ArrayViewIterator for T where T: Iterator<Item = usize> + Debug + Clone + 'static {}

dyn_clone::clone_trait_object!(ArrayViewIterator);

#[derive(Debug, Clone)]
pub struct Array<T> {
    store: Vec<T>,
    dims: Vec<usize>,
}

impl<T> Array<T> {
    pub fn new(store: Vec<T>, dims: Vec<usize>) -> Self {
        assert_eq!(store.len(), dims.iter().product::<usize>());
        Array { store, dims }
    }

    pub fn linear_index(&self, indices: &[usize]) -> usize {
        compute_linear_index(&self.dims, indices)
    }
}

fn compute_linear_index(dims: &[usize], indices: &[usize]) -> usize {
    let mut linear_index = 0;
    let mut stride = 1;
    for i in (0..dims.len()).rev() {
        linear_index += indices[i] * stride;
        stride *= dims[i];
    }
    linear_index
}

#[derive(Debug)]
pub struct ArrayIteratorFromDynMut<'a, T> {
    data: *mut T,
    dims: &'a [usize],
    selection_iterators: Vec<Box<dyn ArrayViewIterator>>,
    current_iterators: Vec<Box<dyn ArrayViewIterator>>,
    current_index_option: Vec<Option<usize>>,
}

impl<'a, T> ArrayIteratorFromDynMut<'a, T> {
    pub fn new(array: &'a mut Array<T>, selection_iterators: Vec<Box<dyn ArrayViewIterator>>) -> Self {
        let data = array.store.as_mut_ptr();
        let dims = &array.dims;
        let current_iterators = selection_iterators.iter().map(|iter| dyn_clone::clone_box(&**iter)).collect();
        let current_index_option = vec![None; selection_iterators.len()];

        Self {
            data,
            dims,
            selection_iterators,
            current_iterators,
            current_index_option,
        }
    }
}

impl<'a, T> Iterator for ArrayIteratorFromDynMut<'a, T> {
    type Item = (Vec<usize>, &'a mut T);

    fn next(&mut self) -> Option<Self::Item> {
        self.current_index_option[0] = self.current_iterators[0].next();
        for i in 0..self.selection_iterators.len() {
            if self.current_index_option[i].is_none() {
                if i == self.selection_iterators.len() - 1 {
                    return None;
                }
                self.current_iterators[i] = dyn_clone::clone_box(&*self.selection_iterators[i]);
                self.current_index_option[i] = self.current_iterators[i].next();
                if i < self.selection_iterators.len() - 1 {
                    self.current_index_option[i + 1] = self.current_iterators[i + 1].next();
                }
            } else {
