async fn main() {
    // Setup tracing with OpenTelemetry and stdout
    let tracer = global::tracer("request-tracer");
    let telemetry_layer = tracing_opentelemetry::layer().with_tracer(tracer);

    tracing_subscriber::registry()
        .with(tracing_subscriber::fmt::layer())
        .with(telemetry_layer)
        .init();

    // Parent span representing the whole request
    let request_span = info_span!("request", request_id = "req-123");
    request_span.in_scope(|| info!("Starting request"));

    // Context carrying the parent span
    let ctx = RequestContext {
        parent_span: request_span.clone(),
    };

    // Simulate async callbacks (could be called at any time/thread)
    let stage1 = execute_stage(&ctx, "stage1", 50);
    let stage2 = execute_stage(&ctx, "stage2", 30);
    let upstream = call_upstream(&ctx, "backend-service");

    // Run stages concurrently to demonstrate span continuity
    tokio::join!(stage1, stage2, upstream);

    // Ensure all spans are exported
    opentelemetry::global::shutdown_tracer_provider();
}

#[derive(Clone)]
struct RequestContext {
    parent_span: tracing::Span,  // Carries the parent span
}

async fn execute_stage(ctx: &RequestContext, name: &'static str, duration: u64) {
    // Rehydrate by creating child span from stored parent
    let stage_span = info_span!(parent: &ctx.parent_span, "stage", stage_name = name);

    let future = async move {
        info!("Executing stage");
        tokio::time::sleep(tokio::time::Duration::from_millis(duration)).await;
        info!("Stage complete");
    };

    // Correctly associates span with this execution context
    future
        .instrument(stage_span)
        .await
}

async fn call_upstream(ctx: &RequestContext, service: &'static str) {
    let upstream_span = info_span!(parent: &ctx.parent_span, "upstream", service);

    async move {
        info!("Calling upstream service");
        tokio::time::sleep(tokio::time::Duration::from_millis(70)).await;
        info!("Upstream response received");
    }
    .instrument(upstream_span)
    .await
}"
}
```

### Key Components:

1. **Context Management**:
   - `RequestContext` stores the parent span
   - Passed to all async callbacks

2. **Span Rehydration**:
   ```rust
   let stage_span = info_span!(parent: &ctx.parent_span, ...);
   ```
   Creates child spans using the stored parent

3. **Instrumentation**:
   ```rust
   future.instrument(span).await
   ```
   Associates async code with the correct span context

4. **Concurrency Handling**:
   - Uses `tokio::join!` to run stages concurrently
   - Demonstrates span continuity across threads

### How It Works:

1. A parent "request" span is created
2. The parent span is stored in `RequestContext`
3. Async callbacks use the context to:
   - Create child spans linked to the parent
   - Instrument futures with the correct span
4. OpenTelemetry integration ensures proper span propagation

