To solve the problem of downcasting any `List` or `Option` in Rust without duplicating code for each inner type, we can use a macro-based approach. This approach allows us to handle multiple types for `Vec<T>` and `Option<T>` efficiently by generating the necessary downcasting code for a predefined set of types.

### Solution
1. **Macro for Downcasting**: Define macros (`try_downcast_vec!` and `try_downcast_option!`) that generate downcasting code for `Vec<T>` and `Option<T>` for a list of types.
2. **Property Editor Functions**: Implement `list_property` and `option_property` functions to handle the UI rendering for `Vec<T>` and `Option<T>`.
3. **Basic Type Handling**: Implement property editor functions for basic types (e.g., `String`, `i32`, `bool`).
4. **Main Application**: Create a simple egui application to demonstrate the property editor.

### Implementation
Here's the complete solution:

#### Cargo.toml
```toml
[package]
name = "property_editor_example"
version = "0.1.0"
edition = "2021"

[dependencies]
egui = "0.24.0"
eframe = "0.24.0"
```

#### main.rs
```rust
use eframe::egui;
use egui::*;

struct App {
    optional_string: Option<String>,
    vec_of_i32: Vec<i32>,
    vec_of_string: Vec<String>,
    optional_i32: Option<i32>,
    optional_bool: Option<bool>,
    vec_of_bool: Vec<bool>,
}

impl Default for App {
    fn default() -> Self {
        Self {
            optional_string: Some("Hello".to_string()),
            vec_of_i32: vec![1, 2, 3],
            vec_of_string: vec!["A".to_string(), "B".to_string()],
            optional_i32: Some(42),
            optional_bool: Some(true),
            vec_of_bool: vec![true, false],
        }
    }
}

impl eframe::App for App {
    fn update(&mut self, ctx: &egui::Context, _frame: &mut eframe::Frame) {
        CentralPanel::default().show(ctx, |ui| {
            downcast_property(ui, "Optional String", &mut self.optional_string, true);
            downcast_property(ui, "Vec of i32", &mut self.vec_of_i32, true);
            downcast_property(ui, "Vec of String", &mut self.vec_of_string, true);
            downcast_property(ui, "Optional i32", &mut self.optional_i32, true);
            downcast_property(ui, "Optional bool", &mut self.optional_bool, true);
            downcast_property(ui, "Vec of bool", &mut self.vec_of_bool, true);
        });
    }
}

fn main() {
    let options = eframe::NativeOptions::default();
    eframe::run_native(
        "Property Editor Example",
        options,
        Box::new(|_cc| Box::<App>::default()),
    );
}

const PROPERTY_LABEL_PADDING: f32 = 100.0;

pub fn downcast_property(ui: &mut Ui, title: &str, value_mut: &mut dyn std::any::Any, interactable: bool) {
    if let Some(string_v) = value_mut.downcast_mut::<String>() {
        string_property(ui, title, string_v, interactable);
    } else if let Some(int_v) = value_mut.downcast_mut::<i32>() {
        i_property(ui, title, int_v, interactable);
    } else if let Some(float_v) = value_mut.downcast_mut::<f32>() {
        f_property(ui, title, float_v, interactable);
    } else if let Some(usize_v) = value_mut.downcast_mut::<usize>() {
        i_property(ui, title, usize_v, interactable);
    } else if let Some(bool_v) = value_mut.downcast_mut::<bool>() {
        bool_property(ui, title, bool_v, interactable);
    } else {
        // Macros to handle Vec<T> and Option<T> for multiple types
        macro_rules! try_downcast_vec {
            ($value_mut:expr, $ui:expr, $title:expr, $interactable:expr, $($ty:ty),*) => {
                $(
                    if let Some(v) = $value_mut.downcast_mut::<Vec<$ty>>() {
                        list_property($ui, $title, v, $interactable);
                        return;
                    }
                )*
            };
        }

        macro_rules! try_downcast_option {
            ($value_mut:expr, $ui:expr, $title:expr, $interactable:expr, $($ty:ty),*) => {
                $(
                    if let Some(v) = $value_mut.downcast_mut::<Option<$ty>>() {
                        option_property($ui, $title, v, $interactable);
                        return;
                    }
                )*
            };
        }

        try_downcast_vec!(
            value_mut, ui, title, interactable,
            String, i32, f32, usize, bool
        );

        try_downcast_option!(
            value_mut, ui, title, interactable,
            String, i32, f32, usize, bool
        );

        ui.label(RichText::new(format!("Field {}: unknown type", title)).color(Color32::LIGHT_RED));
    }
}

pub fn list_property<T>(ui: &mut Ui, title: &str, value_mut: &mut Vec<T>, interactable: bool)
where
    T: Default + 'static + std::fmt::Debug,
{
    CollapsingHeader::new(title)
        .default_open(true)
        .enabled(interactable)
        .show(ui, |ui| {
            ui.horizontal_top(|ui| {
                if ui.button("➕ Add").clicked() {
                    value_mut.push(T::default());
                }
            });

            let mut i = 0;
            while i < value_mut.len() {
                ui.horizontal(|ui| {
                    downcast_property(ui, "", &mut value_mut[i], interactable);
                    if ui.button("❌").on_hover_text("Remove").clicked() {
                        value_mut.remove(i);
                    } else {
                        i += 1;
                    }
                });
            }
        });
}

pub fn option_property<T>(ui: &mut Ui, title: &str, value_mut: &mut Option<T>, interactable: bool)
where
    T: Default + 'static,
{
    let mut is_option_none = value_mut.is_none();

    ui.horizontal(|ui| {
        ui.label(title);
        ui.add_space(PROPERTY_LABEL_PADDING);
        bool_property(ui, "None", &mut is_option_none, interactable);
        ui.add_space(2.0);
        if is_option_none {
            *value_mut = None;
        } else if let Some(inner) = value_mut.as_mut() {
            downcast_property(ui, "", inner, interactable);
        } else {
            *value_mut = Some(T::default());
        }
    });
}

// Basic property editor functions
pub fn string_property(ui: &mut Ui, title: &str, value: &mut String, interactable: bool) {
    ui.horizontal(|ui| {
        ui.label(title);
        ui.add_space(PROPERTY_LABEL_PADDING);
        if interactable {
            ui.text_edit_singleline(value);
        } else {
            ui.label(value);
        }
    });
}

pub fn i_property<T: egui::emath::Numeric>(ui: &mut Ui, title: &str, value: &mut T, interactable: bool) {
    ui.horizontal(|ui| {
        ui.label(title);
        ui.add_space(PROPERTY_LABEL_PADDING);
        if interactable {
            ui.add(DragValue::new(value));
        } else {
            ui.label(format!("{}", value));
        }
    });
}

pub fn f_property(ui: &mut Ui, title: &str, value: &mut f32, interactable: bool) {
    ui.horizontal(|ui| {
        ui.label(title);
        ui.add_space(PROPERTY_LABEL_PADDING);
