{
  "Cargo.toml": {
    "content": "[package]
name = "sql_editor"
version = "0.1.0"
edition = "2021"

[dependencies]
rustyline = "12.0.0""
  },
  "main.rs": {
    "content": "use rustyline::{
    Cmd,
    CompletionType,
    Config,
    Context,
    Editor,
    Event,
    EventContext,
    EventHandler,
    KeyEvent,
    Modifiers,
    Movement,
    RepeatCount,
    Result,
    conditional_handler::ConditionalEventHandler,
};

struct MyEventHandler {
    insert_char: char,
}

impl MyEventHandler {
    fn new(insert_char: char) -> MyEventHandler {
        MyEventHandler { insert_char }
    }
}

impl ConditionalEventHandler for MyEventHandler {
    fn handle(
        &self,
        _event: &Event,
        _count: RepeatCount,
        _positive: bool,
        context: &EventContext,
    ) -> Option<Cmd> {
        let pos = context.pos();
        let line = context.line();
        let line = &line[..pos];

        if let Some(last_non_ws) = line.rfind(|c: char| !c.is_whitespace()) {
            let ws_count = pos - (last_non_ws + 1);
            if ws_count > 0 {
                // Move to start of whitespace, replace it with our character
                let move_back = Movement::BackwardChar(ws_count as RepeatCount);
                let insert_str = self.insert_char.to_string();

                // Return sequence: move back, replace whitespace, then move forward
                return Some(Cmd::Multiple(vec![ 
                    Cmd::Replace(move_back, Some(insert_str)),
                    Cmd::Move(Movement::ForwardChar(1)),
                ]));
            }
        }

        None
    }
}

fn bind_handler(editor: &mut Editor<()>, key: char) {
    let event = Event::Key(KeyEvent::new(key, Modifiers::NONE));
    let handler = EventHandler::Conditional(Box::new(MyEventHandler::new(key)));
    editor.bind_sequence(event, handler);
}

fn main() -> Result<()> {
    let config = Config::builder()
        .completion_type(CompletionType::List)
        .build();

    let mut rl = Editor::with_config(config)?;

    // Bind our special handlers for '.' and ','
    bind_handler(&mut rl, '.');
    bind_handler(&mut rl, ',');

    println!("SQL Editor with special whitespace handling. Try completing 'bo' then typing '.'");

    loop {
        let line = rl.readline("zql> ");
        match line {
            Ok(line) => println!("You entered: {}", line),
            Err(rustyline::error::ReadlineError::Interrupted) => {
                println!("CTRL-C");
