use clap::{Parser, Subcommand};

#[derive(Parser)]
#[command(version, about, long_about = None)]
struct Cli {
    #[command(subcommand)]
    command: Commands,
}

#[derive(Subcommand)]
enum Commands {
    /// Node operations
    Node(NodeCommand),
}

#[derive(Subcommand)]
enum NodeCommand {
    /// Create a node
    Create {
        /// Name of the node
        name: String,
    },
    /// Get a node
    Get {
        /// Name of the node
        name: String,
    },
    /// Other node operations (on an existing node)
    #[command(external_subcommand)]
    Op(Vec<String>),
}

fn main() {
    let cli = Cli::parse();

    match cli.command {
        Commands::Node(node_cmd) => {
            match node_cmd {
                NodeCommand::Create { name } => {
                    println!("Creating node: {}", name);
                }
                NodeCommand::Get { name } => {
                    println!("Getting node: {}", name);
                }
                NodeCommand::Op(args) => {
                    if args.is_empty() {
                        eprintln!("Error: Missing node name and operation");
                        std::process::exit(1);
                    }
                    let node_name = &args[0];
                    let op_args = &args[1..];
